-- Poems batch 159
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('03d60f59-7f8a-41cd-88de-fd7acfcbda82','運使兵部以某馳想林泉拙詩言志薦承屬和曲有褒嘉今復致謝','文彥博','宋','宋诗','song-poetry','','[]','爲憶伊川塢，因成洛社吟。',48,'全唐诗/poet.song.16000.json','["爲憶伊川塢，因成洛社吟。", "永言聊見志，真賞得知心。", "黼繡頻加飾，夔牙屢振音。", "傳家同祕寶，不啻滿籝金。"]'),
('f287bbd0-fbb7-4970-a8fb-e19ec69cd5a1','運使兵部見采拙詩四沐繼和唱者已竭而答者無窮內省小巫敢當大敵既難收合餘燼願爲城下之盟','文彥博','宋','宋诗','song-poetry','','[]','引玉纔三唱，投珠已四吟。',48,'全唐诗/poet.song.16000.json','["引玉纔三唱，投珠已四吟。", "一鈞皆協律，六義盡同心。", "巨浸傾無竭，洪鐘叩有音。", "鼓行君正勇，怯者原聞金。"]'),
('4e56aca3-8e3b-4f4b-8f2d-8e3256dfb93a','元師遷化其徒得舍利供於天鉢因作四十言讚嘆既而得殿省蘇承詩又增十字','文彥博','宋','宋诗','song-poetry','','[]','師今順寂去，所寂竟何如。',60,'全唐诗/poet.song.16000.json','["師今順寂去，所寂竟何如。", "倏爾歸無物，湛然同太虛。", "化成三昧火，超出四禪居。", "方悟祇園法，又勝漆園書。", "蘇君善知識，言詩更起予。"]'),
('0a9c954b-ad21-4c9e-aafa-1b0739f412d3','令弟堅官滿歸京偶成四十言代書寄判武學顧學士略資一噱','文彥博','宋','宋诗','song-poetry','','[]','多年判武學，未改舊官銜。',48,'全唐诗/poet.song.16000.json','["多年判武學，未改舊官銜。", "有意將投閣，無人爲解驂。", "師資盡韜略，况味極齏鹽。", "聞說鱸魚好，歸心風滿帆。"]'),
('f2e3f5d3-8c81-4b37-91e2-f57991de3d13','蒙惠咸陽水梨極佳快陶隱居謂梨爲快果太原鳳棲梨少許納上非報也欲校其味耳呂大忠運使惠','文彥博','宋','宋诗','song-poetry','','[]','鳳棲佳果玉漿寒，馬乳龍鬚味一般。',32,'全唐诗/poet.song.16000.json','["鳳棲佳果玉漿寒，馬乳龍鬚味一般。", "未敢便教充釘坐，更將冰蜜校量看。"]'),
('30d0c23e-6214-42c6-8215-9f9559bb2fe9','承答詩披覽歎服無已今復和呈資一噱而已','文彥博','宋','宋诗','song-poetry','','[]','藥錄雖稱性味寒，滌煩功效有多般。',32,'全唐诗/poet.song.16000.json','["藥錄雖稱性味寒，滌煩功效有多般。", "從來御宿嘉名著，豈與西沙一例看。"]'),
('90bd85a3-3e31-4f91-8b4c-fa74b69848a3','承惠梨栗前詩止及梨今并及之荒詞喧黯又增戰栗','文彥博','宋','宋诗','song-poetry','','[]','盈襜始自終南采，兼量初從御宿般。',32,'全唐诗/poet.song.16000.json','["盈襜始自終南采，兼量初從御宿般。", "寄到鄴城人未識，阿通欣躍已先看。"]'),
('4e662bf5-0b59-466a-8296-5b3279cf3a6b','承惠鱖白魚蛤蜊仍以佳章見示併深珍感輒依來韻奉和且申致謝之意  其一','文彥博','宋','宋诗','song-poetry','','[]','多魚見饋逾雙鯉，異味兼常過八珍。',32,'全唐诗/poet.song.16000.json','["多魚見饋逾雙鯉，異味兼常過八珍。", "更使伊賓垂釣手，轉思東上鱠鱸人。"]'),
('b6627337-fe98-4a54-847c-f8986175df2c','承惠鱖白魚蛤蜊仍以佳章見示併深珍感輒依來韻奉和且申致謝之意  其二','文彥博','宋','宋诗','song-poetry','','[]','望月懷珠重紫唇，隔牆聞賣已稱珍。',32,'全唐诗/poet.song.16000.json','["望月懷珠重紫唇，隔牆聞賣已稱珍。", "奩收篋貯承佳惠，深濟頹山病酒人。"]'),
('366e2264-60dd-4250-b9bd-4aa0cd396d54','偶書答岐守吳卿','文彥博','宋','宋诗','song-poetry','','[]','君說歸期未有期，西風又是鱠鱸時。',32,'全唐诗/poet.song.16000.json','["君說歸期未有期，西風又是鱠鱸時。", "何當會集香山伴，同赴松窗燭下棋。"]'),
('12da494f-a34d-4940-9aff-8299ac18ff2e','東溪奉送景仁內翰歸東都  其一','文彥博','宋','宋诗','song-poetry','','[]','君自東都至西洛，風光相賞不相違。',32,'全唐诗/poet.song.16000.json','["君自東都至西洛，風光相賞不相違。", "瑞雪承露從頭看，看到姚黄興盡歸。"]'),
('554e384b-5360-4329-8e9b-e2ffb598c267','東溪奉送景仁內翰歸東都  其二','文彥博','宋','宋诗','song-poetry','','[]','暮春脩禊洛川遊，絲管隨登李郭舟。',32,'全唐诗/poet.song.16000.json','["暮春脩禊洛川遊，絲管隨登李郭舟。", "仲損昌言俱未至，凝眸東望不回頭。"]'),
('88079e2d-cedb-441e-9b23-a7022c40b9e2','東溪奉送景仁內翰歸東都  其三','文彥博','宋','宋诗','song-poetry','','[]','送君東至伊東塢，東望青嵩與白雲。',32,'全唐诗/poet.song.16000.json','["送君東至伊東塢，東望青嵩與白雲。", "又向嵩雲更東去，花前把酒惜離羣。"]'),
('6453b33e-f626-46eb-87c4-fbe2c8f08678','頌送天鉢長老','文彥博','宋','宋诗','song-poetry','','[]','江無行化久，法眼眾推尊。',72,'全唐诗/poet.song.16000.json','["江無行化久，法眼眾推尊。", "不憚南來遠，緣從北請頻。", "潮音振祖道，朔土闢宗門。", "有授傳高弟，無遮接下根。", "慈航拯羣溺，慧日破重昏。", "老守心迷鈍，求師求一言。"]'),
('e80489e4-8bdd-475b-9ada-1729602e8bce','五老會詩','文彥博','宋','宋诗','song-poetry','','[]','四個老兒三百歲，當時此會已難倫。',64,'全唐诗/poet.song.16000.json','["四個老兒三百歲，當時此會已難倫。", "如今白髮游河叟，半是清朝解綬人。", "喜向園林同燕集，更緣樽酒長精神。", "歡言預有伊川約，好作元豐第四春。"]'),
('7c696502-89e0-451d-a9fe-6e3ac648a77f','耆老會詩','文彥博','宋','宋诗','song-poetry','','[]','九老唐賢形繪事，元豐今勝會昌春。',96,'全唐诗/poet.song.16000.json','["九老唐賢形繪事，元豐今勝會昌春。", "垂肩素髮皆時彥，揮麈清談盡席珍。", "染翰不停詩思健，飛觴無算酒行頻。", "蘭亭雅集誇脩禊，洛社英游貴序賓。", "自愧空疎陪几杖，更容款密奉簪紳。", "當筵尚齒尤多幸，十二人中第二人。"]'),
('222f8c20-cc08-4cbd-8d07-f1aa3c7b4c2c','再酬富公一絕','文彥博','宋','宋诗','song-poetry','','[]','洛下衣冠今最盛，當年尚齒禮容優。',32,'全唐诗/poet.song.16000.json','["洛下衣冠今最盛，當年尚齒禮容優。", "惟公福壽并勳德，合是人間第一流。"]'),
('d49eda1f-c7c4-4ede-9d1c-a1db94442fab','次韻秦帥經略呂通議過洛少留','文彥博','宋','宋诗','song-poetry','','[]','喜過西都暫解鞍，樽前不惜醉酡顔。',64,'全唐诗/poet.song.16000.json','["喜過西都暫解鞍，樽前不惜醉酡顔。", "推襟道舊從容久，落筆成詩頃刻間。", "塞外定知威令肅，幙中常得雅歌閑。", "相門出相歸人望，瑣闥難淹侍從班。"]'),
('2a4e07c4-2789-4460-81fd-0e7fdecea0a4','家園花開與陳大師飲茶同賞呈伯壽正叔昌言','文彥博','宋','宋诗','song-poetry','','[]','今朝自賞家園花，濃艷繁英粗可誇。',32,'全唐诗/poet.song.16000.json','["今朝自賞家園花，濃艷繁英粗可誇。", "外監上坡俱不至，紫園仙客共烹茶。"]'),
('bc476b22-b1b9-40b2-ac65-e95928371038','近以洛花寄獻齋閣蒙賜詩五絕褒借今輒成五篇以答來貺端明  其一','文彥博','宋','宋诗','song-poetry','','[]','左魏牛黄數十枝，洗粧添色又新奇。',32,'全唐诗/poet.song.16000.json','["左魏牛黄數十枝，洗粧添色又新奇。", "金刀剪送三城去，聊助山翁宴習池。"]'),
('d0d60711-7d7f-449d-8f5e-136c8b7a4708','近以洛花寄獻齋閣蒙賜詩五絕褒借今輒成五篇以答來貺端明  其二','文彥博','宋','宋诗','song-poetry','','[]','山翁爲賞洛花奇，采筆連揮五絕詩。',32,'全唐诗/poet.song.16000.json','["山翁爲賞洛花奇，采筆連揮五絕詩。", "口沫手胝頻捧讀，蘭亭醉墨尚淋漓。"]'),
('87a7c57f-4d24-44cc-8b6e-9f01a6de026c','近以洛花寄獻齋閣蒙賜詩五絕褒借今輒成五篇以答來貺端明  其三','文彥博','宋','宋诗','song-poetry','','[]','舊說河陽滿縣花，安仁當日頗矜誇。',32,'全唐诗/poet.song.16000.json','["舊說河陽滿縣花，安仁當日頗矜誇。", "洛城花品雖奇絕，多出尋常百姓家。"]'),
('0f576e08-fe2d-4d5d-a428-84cdd30b503b','近以洛花寄獻齋閣蒙賜詩五絕褒借今輒成五篇以答來貺端明  其四','文彥博','宋','宋诗','song-poetry','','[]','朱輪大旆行春樂，濟上山陽景物佳。',32,'全唐诗/poet.song.16000.json','["朱輪大旆行春樂，濟上山陽景物佳。", "莫羨洛城花品好，三城本自有朱砂。"]'),
('e5253393-69d0-41e7-9792-cb37d0686fc2','近以洛花寄獻齋閣蒙賜詩五絕褒借今輒成五篇以答來貺端明  其五','文彥博','宋','宋诗','song-poetry','','[]','後園不見栽桃李，舊尹無能可自知。',32,'全唐诗/poet.song.16000.json','["後園不見栽桃李，舊尹無能可自知。", "從使當時曾手植，經今十載亦凋衰。"]'),
('106d4549-d7d2-46aa-856b-8bb5a023bd74','近聞有真率會呈提舉端明','文彥博','宋','宋诗','song-poetry','','[]','近知雅會名真率，率意從心各任真。',64,'全唐诗/poet.song.16000.json','["近知雅會名真率，率意從心各任真。", "顔子簞瓢猶自樂，庾郎鮭韮不爲貧。", "加籩只恐勞煩主，緝御徒能困倦賓。", "務簡去華方盡適，古來彭澤是其人。"]'),
('9e37976e-88b5-48a4-9610-6eec151695e3','提舉端明寵示三月三十日雨中書懷包含廣博義味精深詞高韻險宜其寡和輒次元韻','文彥博','宋','宋诗','song-poetry','','[]','春光垂欲盡，夏景漸增添。',288,'全唐诗/poet.song.16000.json','["春光垂欲盡，夏景漸增添。", "鬰鬰松篁茂，蕭蕭風雨兼。", "花心隨絮落，屐齒被苔粘。", "巧囀鶯遷木，驚飛燕入簾。", "蝦鬚穿曲沼，虎爪度前簷。", "坐久香銷炷，吟多筆費尖。", "雲容方靄靄，日色未炎炎。", "舞鶴傾丹頂，游龜散綠髯。", "命賓常務率，出令更須嚴。", "詩詠當階藥，書尋傍架籤。", "蘭芬衣可襲，露潤草俱沾。", "貴近辭金馬，編脩賜玉蟾。", "高懽惟自適，獨樂未嘗厭。", "赤白曾諮丙，丹青每誚閻。", "沖和緣養浩，寂寞爲安恬。", "身處貧無愧，心貪道不廉。", "成文推大手，濟用鄙輕縑。", "視履循清節，祈恩陋雜占。", "聞韶欣鳳舞，在藻愛魚潜。", "鱸鱠思魚艇，貂冠望酒帘。", "聖時非吏隱，賢業繫民瞻。", "撫事惟公論，摛辭乃自謙。", "保躬誠易退，康世義難淹。", "纇句慙無取，酬言幸不嫌。"]'),
('5fe01c8a-dd8e-42b3-b0f0-4239e6e6b668','奉陪伯溫中散程伯康朝議司馬君從大夫席於所居小園作同甲會','文彥博','宋','宋诗','song-poetry','','[]','四人三百十二歲，況是同生丙午年。',64,'全唐诗/poet.song.16000.json','["四人三百十二歲，況是同生丙午年。", "招得梁園同賦客，合成商嶺採芝仙。", "清談亹亹風盈席，素髮飄飄雪滿肩。", "此會從來誠未有，洛中應作畫圖傳。"]'),
('3d15edde-b7f9-4a5c-b582-bd34073bc58d','子山朝奉倅汝陰過洛訪別求詩','文彥博','宋','宋诗','song-poetry','','[]','鄴下才名同七子，六年開幕得嘉賓。',64,'全唐诗/poet.song.16000.json','["鄴下才名同七子，六年開幕得嘉賓。", "屈從潁水投餘刃，合去甘泉作從臣。", "素以潘陽敦信睦，仍於洛孟卜仁鄰。", "士元驥足難羈絆，即見康衢勢絕塵。"]'),
('48da1fbe-bc8f-4fd3-9b1e-32a08b483960','留守相公和提舉端明作三壽公字韻詩輒繼前韻 紀留守相公','文彥博','宋','宋诗','song-poetry','','[]','三川開盛府，萬鑰主離宮。',48,'全唐诗/poet.song.16000.json','["三川開盛府，萬鑰主離宮。", "雪苑延梅叟，湖園奉晉公。", "因依念有素，出處幸多同。", "雅會歡言意，今推前輩風。"]'),
('233adfcc-e40f-4c42-9965-977fb4a0a747','留守相公和提舉端明作三壽公字韻詩輒繼前韻 自述并謝留守相公','文彥博','宋','宋诗','song-poetry','','[]','千載親逢聖，三槐位忝公。',48,'全唐诗/poet.song.16000.json','["千載親逢聖，三槐位忝公。", "周行簉鵷鷺，渭水愧羆熊。", "致主曾無術，康時豈有功。", "台文形雅詠，褒假過優隆。"]'),
('d3ebf818-f54c-4cd4-b598-d5173e3aee6a','留守相公和提舉端明作三壽公字韻詩輒繼前韻 景仁內翰','文彥博','宋','宋诗','song-poetry','','[]','春色滿伊嵩，春花拆萬紅。',48,'全唐诗/poet.song.16000.json','["春色滿伊嵩，春花拆萬紅。", "欣逢翰林主，還訪玉壺公。", "聽賞吹簫鳳，陪隨飛蓋鴻。", "罇前忍輕別，樂事轉頭空。"]'),
('120cdc59-3832-49d4-a7bd-262299083909','留守相公和提舉端明作三壽公字韻詩輒繼前韻 君實端明','文彥博','宋','宋诗','song-poetry','','[]','水軒淙夜響，花寨燁春紅。',48,'全唐诗/poet.song.16000.json','["水軒淙夜響，花寨燁春紅。", "中有羣書府，恬然獨樂公。", "清吟如唳鶴，高翥若冥鴻。", "汗簡猶多費，時聞橐屢空。"]'),
('f9692cac-7042-4aae-8a6d-b8ee876c3d1e','承伯壽大蓬惠書寄大小鉢囊花并語及敝居松下石上之飲因成二小詩  其一','文彥博','宋','宋诗','song-poetry','','[]','片石長松時下有，青山綠水覺來無。',32,'全唐诗/poet.song.16000.json','["片石長松時下有，青山綠水覺來無。", "姚黄賞盡東歸去，六六峯前會酒徒。"]'),
('7e633518-17e0-4602-8dc7-a6bd09785e5b','承伯壽大蓬惠書寄大小鉢囊花并語及敝居松下石上之飲因成二小詩  其二','文彥博','宋','宋诗','song-poetry','','[]','大小鉢囊花色好，不知得似此間無。',32,'全唐诗/poet.song.16000.json','["大小鉢囊花色好，不知得似此間無。", "玉華峯下應頻賞，綺里園中是飲徒。"]'),
('efef0e9d-0b4d-474e-ad7d-bcf514a2e037','次韻留守相公洛中金橘','文彥博','宋','宋诗','song-poetry','','[]','嘉實本從南地產，移栽洛土結成時。',32,'全唐诗/poet.song.16000.json','["嘉實本從南地產，移栽洛土結成時。", "踰淮未必全爲枳，方信中邦物物宜。"]'),
('098d3a1c-e06d-4c90-9ddb-ff882ae30bf2','北都留守相公韓以某頃守魏都粗脩齋舍特加標牓仍示雅章謹依高韻','文彥博','宋','宋诗','song-poetry','','[]','載守銅壺踰八歲，漸營凉室與溫房。',64,'全唐诗/poet.song.16000.json','["載守銅壺踰八歲，漸營凉室與溫房。", "踈簾夏捲清風閣，密幄冬褰愛日堂。", "窗靜坐聞松竹韻，徑深行襲蕙蘭香。", "已慙必葺非宏麗，更愧佳章比召棠。"]'),
('1325b915-93f2-4636-9b3f-b286acc07f8c','贈國信畢少卿北京作','文彥博','宋','宋诗','song-poetry','','[]','鄴下常推七子才，兔園賓客重鄒杖。',64,'全唐诗/poet.song.16000.json','["鄴下常推七子才，兔園賓客重鄒杖。", "三千里外出疆去，四五年前點頓來。", "將幙未歸慙老大，使旃重到喜追徘。", "朔風不度龍沙遠，只向雲中講信回。"]'),
('416188c3-a0ee-4f1e-a789-ae48acb1fccd','答龐相家園雖陋春物向榮日冀相車時枉遊覽未蒙寵降承貺佳章謹次嚴韻','文彥博','宋','宋诗','song-poetry','','[]','一廛幽趣斗城西，竹映軒窗柳拂堤。',64,'全唐诗/poet.song.16000.json','["一廛幽趣斗城西，竹映軒窗柳拂堤。", "園吏每誇風物美，主人常歎簿書迷。", "碧池荷動觀魚戲，朱檻梧傾待鳳棲。", "惟願毗耶長者至，莫憂花裏有鶯啼。"]'),
('7679b03a-25d2-4409-9de6-99a49d7766f2','題龍門奉先寺興禪師房','文彥博','宋','宋诗','song-poetry','','[]','伊叟已先至，興公猶未歸。',24,'全唐诗/poet.song.16000.json','["伊叟已先至，興公猶未歸。", "憑高東北望，一片白雲飛。"]'),
('cbd23485-541f-44be-bc69-99c1f141646f','偶書扇面','文彥博','宋','宋诗','song-poetry','','[]','人生七十古來稀，老境來侵老病隨。',32,'全唐诗/poet.song.16000.json','["人生七十古來稀，老境來侵老病隨。", "自算愚年垂九十，也須慙愧耳聾遲。"]'),
('012dde63-6cb7-4f45-becf-380b08ee3d8a','慈聖皇太后挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','仁皇當寧久，聖后配天崇。',48,'全唐诗/poet.song.16000.json','["仁皇當寧久，聖后配天崇。", "厚德符坤象，先朝定震宮。", "尊榮三代禮，擁佑兩朝功。", "徽範并慈訓，皆留信史中。"]'),
('8b0c8c60-4dc2-4e9b-bea7-171d389c543e','慈聖皇太后挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','聖孝攀慈範，神遊冀少留。',48,'全唐诗/poet.song.16000.json','["聖孝攀慈範，神遊冀少留。", "重明緣積慶，陰德在貽謀。", "制服從恩重，因山變禮優。", "白雲何處去，雪涕望嵩丘。"]'),
('9d30d778-978c-4320-8a21-dd0430e6ba5c','慈聖皇太后挽詞  其三','文彥博','宋','宋诗','song-poetry','','[]','榆輴漸出金門遠，蘭膳深悲玉座空。',64,'全唐诗/poet.song.16000.json','["榆輴漸出金門遠，蘭膳深悲玉座空。", "奕葉舜華推至孝，前朝文母繼清風。", "栢城鬰鬰依嵩北，石闕隆隆鎮洛東。", "白髮老臣何以報，日期西去掃山宮。"]'),
('4f376718-427a-4b64-b05d-14f184e7446e','英宗皇帝挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','乾德符亨會，天飛出慶寧。',48,'全唐诗/poet.song.16000.json','["乾德符亨會，天飛出慶寧。", "繼明光五葉，啟聖協千齡。", "方保瑶圖永，俄悲玉殿青。", "定知遷寶座，還集太微庭。"]'),
('9642affa-ed8a-41a1-ac34-2f181c35afcf','英宗皇帝挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','厥初丕命集，咸慶長君賢。',48,'全唐诗/poet.song.16000.json','["厥初丕命集，咸慶長君賢。", "恭儉敦堯德，憂勤損舜年。", "象耕蒼野地，龍御鼎湖天。", "帝錫宣英號，鴻休耀信編。"]'),
('690444b5-134a-41f2-97a8-7241699173ed','英宗皇帝挽詞  其三','文彥博','宋','宋诗','song-poetry','','[]','在隱推龍德，重明協帝華。',48,'全唐诗/poet.song.16000.json','["在隱推龍德，重明協帝華。", "蓼蕭均澤及，四海讋威加。", "就日心方切，騰天馭已賒。", "攀髯不可跂，淚目送雲霞。"]'),
('3450f665-bfd5-495c-9a56-13a885a3d5e6','濮安懿王夫人挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','令淑王藩表，恩榮代邸尊。',48,'全唐诗/poet.song.16000.json','["令淑王藩表，恩榮代邸尊。", "篤生爲聖嗣，善述在神孫。", "吉兆憑崧麓，真歸傃濮園。", "賓天雖日遠，國本自靈源。"]'),
('482ae9d0-6289-4d5c-b9e7-b461c8d4b835','濮安懿王夫人挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','昔重間平樂，中推輔佐功。',48,'全唐诗/poet.song.16000.json','["昔重間平樂，中推輔佐功。", "德容咸有裕，善慶果無窮。", "以義情雖奪，於親禮更崇。", "洛郊春向晚，薤挽變凄風。"]'),
('d031cf76-ed79-4b49-b5c5-7dfd20330bbe','神宗皇帝挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','千齡逢聖旦，六葉嗣昌辰。',48,'全唐诗/poet.song.16000.json','["千齡逢聖旦，六葉嗣昌辰。", "睿智天攸縱，章程日又新。", "車書通絕域，雨露洽殊鄰。", "民罄華封祝，帝思蒼野巡。"]'),
('5f375df8-5e5b-4650-9817-bdbdf7f18782','神宗皇帝挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','龍髯攀不及，鳳翼附無因。',48,'全唐诗/poet.song.16000.json','["龍髯攀不及，鳳翼附無因。", "望斷喬山路，憂深杞國人。", "含生蒙舜德，率土被堯仁。", "罔極何由報，徒能損百身。"]'),
('d39f2748-0a05-497a-9fd9-ef2a4666e8e0','神宗皇帝挽詞  其三','文彥博','宋','宋诗','song-poetry','','[]','元豐聖政洽隆平，溢牘聯篇載頌聲。',64,'全唐诗/poet.song.16000.json','["元豐聖政洽隆平，溢牘聯篇載頌聲。", "皇武惟揚昭七德，帝華克協麗重明。", "喬山去日乘龍馭，蒼野巡時見象耕。", "憶兆臣民蒙澤久，隕身思報一毫輕。"]'),
('decd4375-ae3c-4967-9bdf-4face70bf567','神宗皇帝挽詞  其四','文彥博','宋','宋诗','song-poetry','','[]','老臣逢聖運，受眷特優隆。',96,'全唐诗/poet.song.16000.json','["老臣逢聖運，受眷特優隆。", "覲禮超羣后，官儀極上公。", "皇慈矜舊物，帝念錄微功。", "一酌堯罇異，三篇說命同。", "斯心期檢玉，不意遂遺弓。", "聲暨要荒外，哀纏普率中。", "凄涼石門路，慘淡栢城風。", "血淚盈襟隕，何由報昊穹。"]'),
('94e61250-f732-4068-a8c1-613e567f47ef','宣仁聖烈皇太后挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','九年四海被清暉，瑞彩重輪照殿幃。',64,'全唐诗/poet.song.16000.json','["九年四海被清暉，瑞彩重輪照殿幃。", "間日視朝覲旰食，未明思政事宵衣。", "存心庶務勞千慮，决意真游厭萬機。", "下土顒顒望霄漢，仙輿直指厚陵歸。"]'),
('2bb24fd3-b3d0-4b5d-a7d0-51e73c01d0ba','宣仁聖烈皇太后挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','老臣八十慙尸素，掛了貂冠歸洛陽。',64,'全唐诗/poet.song.16000.json','["老臣八十慙尸素，掛了貂冠歸洛陽。", "芝詔薦臨優眷注，蒲輪促起預平章。", "重辭禁幄猶如昨，今迓靈輿益自傷。", "勉策衰羸來鞏固，臨風灑淚厚陵傍。"]'),
('d6a57c41-4801-41fe-896b-b5c594162ace','故相國元憲宋公挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','天聖收羣彥，惟公獨出羣。',48,'全唐诗/poet.song.16000.json','["天聖收羣彥，惟公獨出羣。", "兩朝推舊德，一代仰高文。", "得位才康世，逢時道佐君。", "云胡天不憗，撫几悼勳勤。"]'),
('f7cbad79-3f6d-4a52-826b-958dfc6d26c1','故相國元憲宋公挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','念昔爲寮契，周旋一紀餘。',48,'全唐诗/poet.song.16000.json','["念昔爲寮契，周旋一紀餘。", "佐時君望重，謀國我才疎。", "霧露常蒙潤，陽秋每借噓。", "忽焉傷殄瘁，隕淚滿襟裾。"]'),
('c59d33cb-a23e-4415-9772-13168bb4849d','故相國元憲宋公挽詞  其三','文彥博','宋','宋诗','song-poetry','','[]','名遂營身退，高風近古稀。',48,'全唐诗/poet.song.16000.json','["名遂營身退，高風近古稀。", "台司脫屣去，空土掛冠歸。", "仁壽宜難老，朝陽歎易晞。", "宸篇學丘禱，恩耀賁泉扉。"]'),
('d3027bd4-ebaf-435f-ab39-fb88f5d716ed','故宣徽惠穆呂公挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','奕世韋平族，經時管葛才。',48,'全唐诗/poet.song.16000.json','["奕世韋平族，經時管葛才。", "蒼生方仰望，大厦忽傾頹。", "不憗皇情悼，如仁士論哀。", "刑山赴真宅，應見國僑來。"]'),
('8d656a8c-a3f1-446f-97d5-ed0f3fc8b15b','故宣徽惠穆呂公挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','蚤預朋從談燕熟，晚陪樞筦歲時多。',64,'全唐诗/poet.song.16000.json','["蚤預朋從談燕熟，晚陪樞筦歲時多。", "心如金石堅無改，聲似塤箎久更和。", "丹鳳臨池猶未浴，白駒逢隙已先過。", "相門餘慶簪纓盛，繼述皆同穀與儺。"]'),
('7248c564-4cb3-42b9-8f5b-8214c9309df1','故尚書懿敏王公挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','盛德三槐舊，論交二紀深。',48,'全唐诗/poet.song.16000.json','["盛德三槐舊，論交二紀深。", "帝聰聞曳履，人望在爲霖。", "沒世猶赍志，康時未稱心。", "孤懷傷殄瘁，清淚滿衣襟。"]'),
('82844bfc-eca5-4946-a7bd-28ddc84eaf23','故尚書懿敏王公挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','上臺三品位非輕，秘殿論思職更清。',64,'全唐诗/poet.song.16000.json','["上臺三品位非輕，秘殿論思職更清。", "頻倚壯猷爲屏翰，合從僉議秉鈞衡。", "頹然處順君無怛，慟矣懷賢我有情。", "不獨九原埋寶玉，人琴從此絕遺聲。"]'),
('0c009b19-79ce-4a96-b655-99f1e2eceb3e','尚書令魏國忠憲韓公挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','平生投分比金蘭，莫逆論心最歲寒。',64,'全唐诗/poet.song.16000.json','["平生投分比金蘭，莫逆論心最歲寒。", "唱第楓宸陪驥尾，秉鈞槐府並貂冠。", "潘陽事契常脩睦，相魏親鄰正講歡。", "冰井臺邊星隕後，百身何贖但汍瀾。"]'),
('1b2543e2-470f-4054-ad8a-6ea067d12a68','尚書令魏國忠憲韓公挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','出入三朝共，周旋四紀同。',48,'全唐诗/poet.song.16000.json','["出入三朝共，周旋四紀同。", "論交最知我，經世獨推公。", "觀水驚川逝，升堂失棟隆。", "悲懷與聲淚，遠寄紼謳中。"]'),
('6a7eb568-b86f-4562-b036-92d700d9bf7a','尚書令魏國忠憲韓公挽詞  其三','文彥博','宋','宋诗','song-poetry','','[]','三朝光輔致昇平，九敘咸熙入頌聲。',64,'全唐诗/poet.song.16000.json','["三朝光輔致昇平，九敘咸熙入頌聲。", "獨運鴻鈞成大業，親扶英主繼重明。", "聖賢自昔推同德，忠獻于今重易名。", "清廟已聞從配饗，哀榮不獨在佳城。"]'),
('169ac376-f95f-4f9a-9458-94c9adbbaaaf','中書令魯國宣靖魯公挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','三朝輔翊秉鴻鈞，功在旂常澤在民。',64,'全唐诗/poet.song.16000.json','["三朝輔翊秉鴻鈞，功在旂常澤在民。", "黄石授來爲帝傅，赤松遊去保天真。", "達生優享高年福，出世輕遺大夢身。", "自古陘山多吉宅，國僑裴令繼芳塵。"]'),
('a0cf64e2-b375-42b8-99da-fd35543e9cd6','中書令魯國宣靖魯公挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','二府陪游垂二紀，服公哲範每思齊。',64,'全唐诗/poet.song.16000.json','["二府陪游垂二紀，服公哲範每思齊。", "留心舊典皆馴致，從事新書悉順稽。", "言發清風常穆若，心停止水更淵兮。", "先朝付囑非無謂，必爲其仁在放麑。"]'),
('d4cd0868-328f-482b-8615-44c759cd2248','中書令魯國宣靖魯公挽詞  其三','文彥博','宋','宋诗','song-poetry','','[]','龜蒙啟土世傳榮，猶倚耆英作政卿。',32,'全唐诗/poet.song.16000.json','["龜蒙啟土世傳榮，猶倚耆英作政卿。", "及見伯禽親拜後，方知遺愛在元成。"]'),
('7636746c-f995-43b0-8e03-5f186268da13','中書令魯國宣靖魯公挽詞  其四','文彥博','宋','宋诗','song-poetry','','[]','穆穆罷朝嗟不憗，衝衝停市歎如仁。',32,'全唐诗/poet.song.16000.json','["穆穆罷朝嗟不憗，衝衝停市歎如仁。", "生芻絮酒難親致，薤曲書成淚滿巾。"]'),
('fac09e4a-086b-4985-bcf0-e4d03208baf0','王太師挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','賢書蚤入英雄彀，冠歲高馳賈馬聲。',64,'全唐诗/poet.song.16000.json','["賢書蚤入英雄彀，冠歲高馳賈馬聲。", "一紀玉堂司大筆，兩朝金鼎主和羹。", "天邊遽失騎箕象，川上猶思用檝名。", "欲識聖恩優異處，密章重疊賁佳城。"]'),
('e13f7287-af38-40fb-840b-0a0f08b01c79','王太師挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','去春解組遂西征，曾辱都門出饒行。',64,'全唐诗/poet.song.16000.json','["去春解組遂西征，曾辱都門出饒行。", "席上詩成光退跡，樽中酒滿敘離情。", "經年方歎音容隔，此日俄驚柱石傾。", "羸老不能親引紼，臨風灑淚濕襟纓。"]'),
('16b8e20b-b276-458e-a811-b25d313c1ab5','司馬溫公挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','莫逆論交司馬丈，君心知我我知君。',64,'全唐诗/poet.song.16000.json','["莫逆論交司馬丈，君心知我我知君。", "同謀同道殊無間，一死一生今遂分。", "八十衰翁如槁木，一千餘日是殘曛。", "前途若有相逢處，尚以英靈解世紛。"]'),
('5d7a9aa8-1a28-434e-a335-313cdb145987','司馬溫公挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','留滯周南十五年，成書奏牘過三千。',64,'全唐诗/poet.song.16000.json','["留滯周南十五年，成書奏牘過三千。", "東山方起爲霖雨，大厦俄傾歎逝川。", "密有忠言如藥石，別加優禮賜貂蟬。", "兩宮痛悼皆臨奠，祗爲臯夔志未宣。"]'),
('fac3e7b3-e39b-4cde-8c94-eff12fdbc8fc','司馬溫公挽詞  其三','文彥博','宋','宋诗','song-poetry','','[]','昔有鄉賢陽道州，亦聞比近有松楸。',32,'全唐诗/poet.song.16000.json','["昔有鄉賢陽道州，亦聞比近有松楸。", "新阡便合開三徑，同氣相求好並游。"]'),
('815f1515-0aad-49d3-924f-c387b7e53ac6','司馬溫公挽詞  其四','文彥博','宋','宋诗','song-poetry','','[]','傅巖舊跡今猶在，兼與安平祖廟鄰。',32,'全唐诗/poet.song.16000.json','["傅巖舊跡今猶在，兼與安平祖廟鄰。", "賢相裔孫還卜宅，先疇吉土是歸真。"]'),
('8e031308-c177-4cf5-84b4-f4b0b80a4cc0','司馬贈太傅康國韓公挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','朝路相從三紀餘，更陪國論對鈞樞。',64,'全唐诗/poet.song.16000.json','["朝路相從三紀餘，更陪國論對鈞樞。", "康時遠術推賢業，造膝嘉猷協帝俞。", "盤結方資庖刃解，旱乾猶望傅霖蘇。", "寢門遽有人琴歎，老伴調零道轉孤。"]'),
('a2eaf0f0-7cf3-4032-b761-e57bbfe83376','司馬贈太傅康國韓公挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','洛城曾與公相別，已爲人生老別難。',32,'全唐诗/poet.song.16000.json','["洛城曾與公相別，已爲人生老別難。", "今作紼謳成永訣，滿襟悲淚轉汍瀾。"]'),
('49ee5dd4-8409-4798-8824-3d7ef37c05bc','司馬贈太傅康國韓公挽詞  其三','文彥博','宋','宋诗','song-poetry','','[]','西豪居在許東偏，丹旐遥遥過許田。',32,'全唐诗/poet.song.16000.json','["西豪居在許東偏，丹旐遥遥過許田。", "欲問相君真宅處，高平吉地是新阡。"]'),
('9681da8b-51ab-4389-948e-d8010602c2b8','中書侍郎傅公挽詞  其一','文彥博','宋','宋诗','song-poetry','','[]','友會朋情二紀餘，金蘭投分更無殊。',64,'全唐诗/poet.song.16000.json','["友會朋情二紀餘，金蘭投分更無殊。", "鳳池晚接經邦論，龍陛晨陪步武趨。", "起副民瞻方倚賴，用爲霖雨待昭蘇。", "如何奄忽公先逝，自歎靈光老益孤。"]'),
('7a853ac9-84fb-4c4a-adf8-1479784d1181','中書侍郎傅公挽詞  其二','文彥博','宋','宋诗','song-poetry','','[]','賢業雖長命不融，從來此恨古今同。',32,'全唐诗/poet.song.16000.json','["賢業雖長命不融，從來此恨古今同。", "爲霖作礪君家事，未盡舒張數已窮。"]'),
('4159e37e-5733-4f44-947d-be0886d0af2b','中書侍郎傅公挽詞  其三','文彥博','宋','宋诗','song-poetry','','[]','常愛龍潭龜島上，移床醉卧綠髯中。',32,'全唐诗/poet.song.16000.json','["常愛龍潭龜島上，移床醉卧綠髯中。", "茂林脩竹皆如舊，惟歎人琴遂一空。"]'),
('f1d26287-b04b-4329-93c8-400b36a4f3cc','致政仲損工部哀詞    其一','文彥博','宋','宋诗','song-poetry','','[]','自昔朋游今五紀，斷金連璧附英翹。',64,'全唐诗/poet.song.16000.json','["自昔朋游今五紀，斷金連璧附英翹。", "學通經史蒙三益，心類松筠見久要。", "白首郎潛甘寂寞，清時吏隱甚逍遥。", "年逾九九誠無慊，惟歎人亡與道消。"]'),
('e998862d-18a5-4dbe-abf2-3b367a7fa7e7','致政仲損工部哀詞    其二','文彥博','宋','宋诗','song-poetry','','[]','金蘭取友務端良，仲損於余極久長。',64,'全唐诗/poet.song.16000.json','["金蘭取友務端良，仲損於余極久長。", "蚤歲傾懷論管鮑，晚年脩好結潘陽。", "人琴忽起芝焚歎，簫鼓俄隨薤挽傷。", "不到寢門親一慟，臨風老淚獨浪浪。"]'),
('1e0034fb-d00a-4c67-99c8-c9483b13edc6','太尉韓國文忠富公哀詞  其一','文彥博','宋','宋诗','song-poetry','','[]','蚤擅才名重，天資德望崇。',48,'全唐诗/poet.song.16000.json','["蚤擅才名重，天資德望崇。", "大勳緣定策，美利在和戎。", "一代推人傑，三朝倚棟隆。", "音容雖已矣，永譽更無窮。"]'),
('4d87af5b-474c-4ae0-89cf-d6de30596fe5','太尉韓國文忠富公哀詞  其二','文彥博','宋','宋诗','song-poetry','','[]','鼂董經邦策，臯夔濟世賢。',72,'全唐诗/poet.song.16000.json','["鼂董經邦策，臯夔濟世賢。", "頻堅挂冠請，未及縱心年。", "蚤遂赤松伴，晚參黄蘗禪。", "懸車垂一紀，筑室冠三川。", "瀟灑山中相，優游地上仙。", "尊榮兼壽考，五福在公全。"]'),
('5fbdcb7e-cbbb-4942-80d3-b876e858f9c0','太尉韓國文忠富公哀詞  其三','文彥博','宋','宋诗','song-poetry','','[]','我愧才無取，公常問不能。',48,'全唐诗/poet.song.16000.json','["我愧才無取，公常問不能。", "白麻曾並命，黄閣遂同升。", "調燮彝倫敘，將明庶績凝。", "如仁今奄忽，昭代失良肱。"]'),
('dc15f79d-e7aa-4fb0-8176-e3821c264735','太尉韓國文忠富公哀詞  其四','文彥博','宋','宋诗','song-poetry','','[]','去年春作耆英會，一坐簪紳仰典刑。',32,'全唐诗/poet.song.16000.json','["去年春作耆英會，一坐簪紳仰典刑。", "今日共嗟天不憗，惟瞻英範在丹青。"]'),
('3ac8255f-4c56-46ee-9c14-29377cea3055','太尉韓國文忠富公哀詞  其五','文彥博','宋','宋诗','song-poetry','','[]','達觀定知無怛化，常情未免愴離魂。',32,'全唐诗/poet.song.16000.json','["達觀定知無怛化，常情未免愴離魂。", "邛山土厚雖埋玉，遺烈餘芬萬古存。"]'),
('bc4a1e20-3fa7-4ec1-bda8-917c4b434200','故開府太師王公挽詞太子太師  其一','文彥博','宋','宋诗','song-poetry','','[]','蚤歲馳聲猶未冠，錦標獨得冠詞林。',64,'全唐诗/poet.song.16000.json','["蚤歲馳聲猶未冠，錦標獨得冠詞林。", "四朝出處身名泰，五紀游從事契深。", "居守北郊依舊德，退休西洛負初心。", "白龍泉畔青烏兆，引紼悲謳淚滿襟。"]'),
('ac451245-ca77-4487-b0e7-4ecf02b7b00c','故開府太師王公挽詞太子太師  其二','文彥博','宋','宋诗','song-poetry','','[]','昔年壺洛赴三城，華髮青雲敘故情。',32,'全唐诗/poet.song.16000.json','["昔年壺洛赴三城，華髮青雲敘故情。", "今日人琴俱已矣，猶傳樂府沁園聲。"]'),
('b2be5058-652e-43a2-9cec-2f49d58bfe61','故開府太師王公挽詞太子太師  其三','文彥博','宋','宋诗','song-poetry','','[]','天聖年中始得朋，後陪孟洛兩交承。',32,'全唐诗/poet.song.16000.json','["天聖年中始得朋，後陪孟洛兩交承。", "追思往事渾如夢，老淚如傾自不勝。"]'),
('3e670085-e232-44b5-b929-4656bda5ebbd','故開府太師王公挽詞太子太師  其四','文彥博','宋','宋诗','song-poetry','','[]','前歲公圖歸洛中，待君同賞狀元紅。',32,'全唐诗/poet.song.16000.json','["前歲公圖歸洛中，待君同賞狀元紅。", "人間萬事難如意，須把興亡付壞空。"]'),
('7378f707-dfa8-4ef1-a350-7463abd81337','楚正議挽詞三章  其一','文彥博','宋','宋诗','song-poetry','','[]','出處交游五十春，洛城晚歲卜親鄰。',32,'全唐诗/poet.song.16000.json','["出處交游五十春，洛城晚歲卜親鄰。", "東齋錦襻清談處，今日重來淚滿襟。"]'),
('dc7f173c-ad12-4c5f-aa47-ba0c02599048','楚正議挽詞三章  其二','文彥博','宋','宋诗','song-poetry','','[]','大抵神存體不留，萬安山下宅松楸。',32,'全唐诗/poet.song.16000.json','["大抵神存體不留，萬安山下宅松楸。", "平生燕集歌懽友，伯壽應同泉下游。"]'),
('0dd5a968-97c7-4db8-afe0-afea869cb265','楚正議挽詞三章  其三','文彥博','宋','宋诗','song-poetry','','[]','每讀龜書鴻範篇，人間五福是高年。',32,'全唐诗/poet.song.16000.json','["每讀龜書鴻範篇，人間五福是高年。", "公年九九雖無慊，散盡耆英我屹然。"]'),
('8c8f0429-2641-4655-886e-e5ca9b3de761','初知榆次縣題新衙鼓上','文彥博','宋','宋诗','song-poetry','','[]','置向譙樓一任撾，撾多撾少不知他。',32,'全唐诗/poet.song.16000.json','["置向譙樓一任撾，撾多撾少不知他。", "如今幸有黄紬被，努出頭來道放衙。"]'),
('214c37b2-e220-4f1a-9bc6-b6967e54f917','贈李戡','文彥博','宋','宋诗','song-poetry','','[]','昌元建邑幾經春，百里封疆秀氣勻。',32,'全唐诗/poet.song.16000.json','["昌元建邑幾經春，百里封疆秀氣勻。", "鴨子池邊登第客，老鴉山下著棋人。"]'),
('69a1515d-4af6-472c-951a-ebeac1e1d7e5','依漾園池上即事','文彥博','宋','宋诗','song-poetry','','[]','莫問竹風來不來，竹間已自絕塵埃。',32,'全唐诗/poet.song.16000.json','["莫問竹風來不來，竹間已自絕塵埃。", "貪看池上能言鴨，小立橋邊稱意苔。"]'),
('3ca177e8-ceab-469b-aca3-a1aa307952b4','詩一首','文彥博','宋','宋诗','song-poetry','','[]','楚澤荃蘅盡化蓬，自須高謝脫池籠。',32,'全唐诗/poet.song.16000.json','["楚澤荃蘅盡化蓬，自須高謝脫池籠。", "從知鳩鳥真無賴，猶使瑶臺關有娀。"]'),
('434a0b3f-d26b-4a3e-8807-ef614000051a','汶陽館','文彥博','宋','宋诗','song-poetry','','[]','去歲營船隩，今朝館汶陽。',48,'全唐诗/poet.song.16000.json','["去歲營船隩，今朝館汶陽。", "海空沙漠漠，河廣草茫茫。", "家國哀千古，男兒慨四方。", "老槐秋雨暗，孤影照琳琅。"]'),
('d1597471-d07a-4f3e-a971-a651d22e8d90','睢陽五老圖','文彥博','宋','宋诗','song-poetry','','[]','輔政何時退省閑，清平告老謝簪冠。',64,'全唐诗/poet.song.16000.json','["輔政何時退省閑，清平告老謝簪冠。", "兩朝耆宿真英武，一代謀謨實柱桓。", "太史尚瞻星有烈，小民猶念德無寒。", "誰知我輩登樞要，嚴貌冰威祗肅看。"]'),
('5abafe22-dc3d-41aa-9eb3-1306b2489cc5','宿獨樂園詰朝將歸','文彥博','宋','宋诗','song-poetry','','[]','平曉何人汲井華，轆轤聲發散春鴉。',64,'全唐诗/poet.song.16000.json','["平曉何人汲井華，轆轤聲發散春鴉。", "開園更有四五日，映葉尚餘三兩花。", "宿病岑岑猶带酒，無眠耿耿不禁茶。", "自嫌行樂妨年少，遽索籃輿且向家。"]'),
('25b18f0f-6a36-4cec-80ad-b8c44d4369d9','雙泉','文彥博','宋','宋诗','song-poetry','','[]','長劍並彈霜氣豪，白虹半折秋雲高。',32,'全唐诗/poet.song.16000.json','["長劍並彈霜氣豪，白虹半折秋雲高。", "濯纓洗耳更何處，世人回看輕鴻毛。"]'),
('a6674d4b-9f85-43dc-a05a-52fb35431a06','溴水','文彥博','宋','宋诗','song-poetry','','[]','潺湲北山水，繚繞南城臯。',48,'全唐诗/poet.song.16000.json','["潺湲北山水，繚繞南城臯。", "晴灘錦石亂，擊觸春湍高。", "誰謂溴梁大，不能容魴魛。", "臨流自縮手，揭厲應徒勞。"]'),
('62cb507b-51f6-4f38-aa2c-76e5151237fb','草堂肖遥寺','李章','宋','宋诗','song-poetry','','[]','羅什留真嗣，重扉掩碧松。',48,'全唐诗/poet.song.16000.json','["羅什留真嗣，重扉掩碧松。", "鄰僧來紫閣，遠逕接圭峯。", "雨氣晴先潤，庭陰午後濃。", "依稀祖師意，瘦倚一枝笻。"]'),
('c4a9e1ce-7421-4dc7-808a-541152b86fc1','句','李章','宋','宋诗','song-poetry','','[]','願求裴令一篇詩。',8,'全唐诗/poet.song.16000.json','["願求裴令一篇詩。"]'),
('327aa36f-5268-4bd1-87e8-f785d6b03b13','和氣致祥詩','裴湘','宋','宋诗','song-poetry','','[]','君德奉天道，沖融協太和。',72,'全唐诗/poet.song.16000.json','["君德奉天道，沖融協太和。", "卿雲呈瑞早，膏澤應時多。", "煦集連枝木，嘉扶異穎禾。", "五星還聚井，丹鳳更巢阿。", "藪澤無遺士，邊防久息戈。", "黔黎逢至化，稽首載賡歌。"]'),
('1ddd17cd-5465-4781-b3bf-0e71edb46ecb','句','楊士彥','宋','宋诗','song-poetry','','[]','江氣南吞吳分野，海波北撼楚封陲。',16,'全唐诗/poet.song.16000.json','["江氣南吞吳分野，海波北撼楚封陲。"]'),
('440dc47f-8e44-43a4-9208-73e28d353f9d','跨鼇亭','李楫','宋','宋诗','song-poetry','','[]','紫金高處是鼇頭，獨負華堂幾百秋。',48,'全唐诗/poet.song.16000.json','["紫金高處是鼇頭，獨負華堂幾百秋。", "形勢平吞北夢澤，規摹雄峙南司州。", "三關設險知無敵，八相風流孰與儔。"]'),
('b7f3fe5d-0bbd-40ae-abad-dfa1a6674249','車蓋亭','李楫','宋','宋诗','song-poetry','','[]','白兆山光相掩映，紫金氣象轉深幽。',32,'全唐诗/poet.song.16000.json','["白兆山光相掩映，紫金氣象轉深幽。", "水西咫尺無人到，乘興何妨一葉舟。"]'),
('472781a1-4577-4983-8d7b-ace962085c14','句','李楫','宋','宋诗','song-poetry','','[]','令人却憶保寧寺，二水三山李白詩。',16,'全唐诗/poet.song.16000.json','["令人却憶保寧寺，二水三山李白詩。"]'),
('d600614d-35d3-47d9-b3f4-673d8de293dd','句','錢仙芝','宋','宋诗','song-poetry','','[]','乘秋張翰思歸國，垂老龜蒙畢著書。',16,'全唐诗/poet.song.16000.json','["乘秋張翰思歸國，垂老龜蒙畢著書。"]'),
('86e3f3f3-2f4a-4bf0-9f6c-5fe2faf9b1de','送張無夢歸天台','慎鏞','宋','宋诗','song-poetry','','[]','暫御飚輪謁冕旒，却思揮袂揖浮丘。',64,'全唐诗/poet.song.16000.json','["暫御飚輪謁冕旒，却思揮袂揖浮丘。", "日邊已奉崆峒問，塵外還隨汗漫遊。", "玉座榮頒天藻麗，石橋危過雨苔秋。", "吾皇清浄延高蹈，雲水無心本自由。"]'),
('557c233e-f123-4b49-a8b0-bf2b0522e4a9','題桐柏觀','元積中','宋','宋诗','song-poetry','','[]','九峯巍絕亂雲屯，石室瓊臺舊址存。',64,'全唐诗/poet.song.16000.json','["九峯巍絕亂雲屯，石室瓊臺舊址存。", "山險密盤之字徑，洞深高闢丙方門。", "碧桃花爛春溪暖，紫玉簫沉月榭昏。", "未覺壺中光景晚，人間歸去見來孫。"]'),
('c7b94fa1-f190-450c-b72b-a7eeef033bf7','題安國寺','元積中','宋','宋诗','song-poetry','','[]','繞縣江山翠翦裁，檥舟亭下重徘徊。',64,'全唐诗/poet.song.16000.json','["繞縣江山翠翦裁，檥舟亭下重徘徊。", "昔承官乏因曾到，今按刑章得再來。", "井邑半迷新巷陌，園林猶認舊亭臺。", "靜思三十年前事，恍若邯鄲一夢回。"]'),
('cfddcc45-24cc-4748-8fce-5648b280216e','句','元積中','宋','宋诗','song-poetry','','[]','江東一十州，宜城名善地。',12,'全唐诗/poet.song.16000.json','["江東一十州，宜城名善地。"]'),
('691ee5d1-6d7f-4e71-baa5-9e5b877db844','送鈐轄館使王公二首  其一','張靖','宋','宋诗','song-poetry','','[]','保塞昔年嘗閉壘，甘陵今歲又勞師。',32,'全唐诗/poet.song.16000.json','["保塞昔年嘗閉壘，甘陵今歲又勞師。", "將軍鎮蜀功多少，不見干戈出虎皮。"]'),
('6f7a0121-de52-49ab-8343-9867cd4ab641','送鈐轄館使王公二首  其二','張靖','宋','宋诗','song-poetry','','[]','玉勒嘶風出錦城，山光野色助離情。',32,'全唐诗/poet.song.16000.json','["玉勒嘶風出錦城，山光野色助離情。", "行行莫倦神華遠，芳草連雲伴去程。"]'),
('60689dc3-3174-44cf-846b-e4b1e0e238cc','送同年蒲叔範察判杭州監','王疇','宋','宋诗','song-poetry','','[]','釋之久未調，王粲當從軍。',288,'全唐诗/poet.song.16000.json','["釋之久未調，王粲當從軍。", "謂言塞垣事，壯氣橫風雲。", "育材幸明代，薦賢無令君。", "如無漢酤冗，沈此荆山珍。", "萍氏本譏酒，周官有彝倫。", "孝武事却攘，志清天地屯。", "連兵無時已，四海蕭然貧。", "官始操釀具，榷之飽師人。", "利源一以洩，頹波蕩無垠。", "糜穀費耒耜，良糵爭清醇。", "酒禁著律令，犯笞及其身。", "狂藥乃陷穽，傷哉堯舜民。", "炎靈屬我后，天資英且仁。", "邦力早雄富，漢制仍相循。", "歲賦二千萬，經入固已勤。", "彌年擁武節，聚邊清國氛。", "雄雄百萬師，跨邁擊燕秦。", "仰給傾武庫，賞赍圖戎勳。", "加斂猶不足，返古當何云。", "杭城東南劇，地將湖海鄰。", "榷利冠天下，旗亭壓重闉。", "彼雖斗筲職，亦擇才英臣。", "風露氣已肅，溪潭寒彌新。", "沙榜朝汍汍，吳濤暮沄沄。"]'),
('ad12d541-60b6-4f6d-8348-ee0745cbd38f','立秋日書懷','王疇','宋','宋诗','song-poetry','','[]','一歲中分氣序平，夫何猶有感秋情。',64,'全唐诗/poet.song.16000.json','["一歲中分氣序平，夫何猶有感秋情。", "已饒健鶻凌空翮，肯作寒蜩抱樹聲。", "桐葉漸愁經雨墜，桂枝還喜得風生。", "夜凉頻愜山居興，天澹銀河徹曉清。"]'),
('3956e284-0769-41fa-bd13-44800baa05f5','句','榮諲','宋','宋诗','song-poetry','','[]','城下江流金雁水，亭中人弄玉絃琴。',16,'全唐诗/poet.song.16000.json','["城下江流金雁水，亭中人弄玉絃琴。"]'),
('aa632e9e-dbc4-4977-8f50-4e629d319e8e','三高僧詩 霅之晝能清秀','釋契嵩','宋','宋诗','song-poetry','','[]','晝公文章清復秀，天與其能不可鬭。',112,'全唐诗/poet.song.16000.json','["晝公文章清復秀，天與其能不可鬭。", "僧攻文什自古有，出拔須尊晝爲首。", "造化雖移神不遷，晝公作詩心亦然。", "上跨騷雅下沈宋，俊思縱橫道自全。", "禪伯修文豈徒爾，誘引人心通佛理。", "搢紳先生魯公輩，早躡清游慕方外。", "斯人已歿斯言在，護法當應垂萬代。"]'),
('e5378097-4abe-4ec7-b92e-cacf50a36173','三高僧詩 越之徹如冰雪','釋契嵩','宋','宋诗','song-poetry','','[]','徹公之清若冰雪，高僧天資與人別。',112,'全唐诗/poet.song.16000.json','["徹公之清若冰雪，高僧天資與人別。", "三十能詩名已出，名在詩流心在律。", "不殊惠遠殊惠休，皎然未合誰與儔。", "白雲蕭散何定止，忽入關中訪包李。", "孤清難立眾所沮，到底無辜中非語。", "木秀於林風必摧，徹公懷德成禍胎。", "古人已往不復歎，爲爾爲詩遺後來。"]'),
('6698abfa-8b8d-4630-b804-71efc29b999c','三高僧詩 杭之標摩雲霄','釋契嵩','宋','宋诗','song-poetry','','[]','標師之高摩雲霄，在德豈在於泬寥。',96,'全唐诗/poet.song.16000.json','["標師之高摩雲霄，在德豈在於泬寥。", "一庵嶺底寄幽獨，抗迹蕭然不入俗。", "有時虛陟層崖眺，不聞其語聞清嘯。", "當時陸羽事幽討，曾入青雲預聞道。", "取雨救旱驅神龍，此與人間事豈同。", "冥機感異心之苗，此公所以稱道標。"]'),
('31eba6bb-e1ee-40a1-8d84-2d0dbf992206','送章表民秘書','釋契嵩','宋','宋诗','song-poetry','','[]','一日夫子來山陲，來言去別將何之。',384,'全唐诗/poet.song.16000.json','["一日夫子來山陲，來言去別將何之。", "清塵舊尉亦皆至，鮮車輕珮光陸離。", "入門顧我顔色好，林下把袂相追隨。", "笑傲恣肆意氣豪，舉首不覺白日欹。", "拂榻乃留巖宇宿，紙衾蒲席誠可嗤。", "不計豐約但適美，唯唯無語相拒違。", "是時春和二月半，永夜耿耿輕寒微。", "高談交發雅興合，如瓶注泉爭淋漓。", "須臾促席命言志，直吐胸臆撝淳詞。", "人心不同有如面，平生各自有所爲。", "表民卒然趨席端，曰吾有志人不知。", "末俗淺近烏足語，含哺未吐長嗟咨。", "少從先生學經典，不探枝葉窮根基。", "帝王之道斷可識，殷盤周誥無復疑。", "古今事業貴適用，文意述作須有規。", "豈類童稚空琢刻，畫餅不能療朝饑。", "十五孜孜事文字，磨礱筆硯精神罷。", "長篇大軸浩無數，慷慨但欲扶政治。", "前年補吏來浙右，局務冗俗不可窺。", "傾懷欲效王覇略，騏驥捕鼠非宜宜。", "錢唐大府多達官，品秩相較我最卑。", "孟軻獨負浩然氣，誰能斂袂長低眉。", "丈夫所重以道進，青雲萬里須自馳。", "咄嗟顧我胡爲者，甘以門廕爲身資。"]'),
('660464d9-22b0-49db-8fad-95fdc45b99e5','古意  其一','釋契嵩','宋','宋诗','song-poetry','','[]','風吹一點雲，散漫爲春雨。',48,'全唐诗/poet.song.16000.json','["風吹一點雲，散漫爲春雨。", "灑余松柏林，青葱枝可取。", "持此歲寒操，手中空楚楚。", "幽谷無人來，日暮意誰與。"]'),
('1f572703-c364-4967-a2db-8a15dd68e99d','古意  其二','釋契嵩','宋','宋诗','song-poetry','','[]','君莫笑支許，寂寞非愚懵。',96,'全唐诗/poet.song.16000.json','["君莫笑支許，寂寞非愚懵。", "君莫輕嵇阮，山林有清興。", "人生徒百歲，樂少憂還剩。", "萬事漫短長，無如使道勝。", "爾非傲世士，高蹈釣名稱。", "但謝區中緣，甘心棲石磴。", "澄空白日飛，世事終無應。", "不如省爾誠，自言還自贈。"]'),
('51630d1a-e9f0-4663-9b76-ac8eb371e7df','古意  其三','釋契嵩','宋','宋诗','song-poetry','','[]','雲中見雙鳥，高飛揭日月。',96,'全唐诗/poet.song.16000.json','["雲中見雙鳥，高飛揭日月。", "毛羽賁文章，翱翔異鷹鶻。", "翛然邈千里，竟不顧林樾。", "春風漫飄颺，勁翮更超忽。", "陌上遊俠子，窺爾徒倉卒。", "雖有金彈丸，睥睨不敢發。", "因知奇異資，自保長超越。", "回視黄雀羣，胡爲戀塵𡋯。"]'),
('2284ce4c-df49-4731-bc00-1e6dad2cb5ad','古意  其四','釋契嵩','宋','宋诗','song-poetry','','[]','堪笑浮雲高，凌虛翳日星。',96,'全唐诗/poet.song.16000.json','["堪笑浮雲高，凌虛翳日星。", "寧作蘭蕙幽，草中自芳馨。", "自足乃天分，未需爾虛靈。", "掩翳之所惡，胡爲久亭亭。", "古爲曠達士，浪跡多晦暝。", "山林惜長往，藏用亦藏形。", "愚谷不可及，窅然還自寧。", "嗟余亦羨此，岑寂養頹齡。"]'),
('63170a42-d36a-4ed8-aad0-8724dbde6b32','古意  其五','釋契嵩','宋','宋诗','song-poetry','','[]','窮品偶真叟，授我一卷書。',120,'全唐诗/poet.song.16000.json','["窮品偶真叟，授我一卷書。", "深林值幽人，遺我斧與鋤。", "斧鋤亦奚爲，教養材與蔬。", "荒穢必須剪，使之藹自如。", "授書欲胡爲，教爾心與軀。", "學必先正己，自治乃及餘。", "此意有嘉訓，佩之未始除。", "如何悠悠人，自謬欲是渠。", "相習成薄俗，尠德懷籧篨。", "吾裁此俚語，憑君爲傳諸。"]'),
('34da6e43-e9d6-4259-9fcb-56a96e1886a8','游龍山訪道士李仙師','釋契嵩','宋','宋诗','song-poetry','','[]','日出野曠明，肅然訪道生。',168,'全唐诗/poet.song.16000.json','["日出野曠明，肅然訪道生。", "杳渺湖外去，散誕雲邊行。", "秋高天宇浄，脫葉飛縱橫。", "乘風度林嶺，轉覺衣屨輕。", "時聞縹緲間，微飚傳鶴聲。", "知與仙家近，逸思泠然清。", "須臾轉幽谷，紫府芝田平。", "仙童走脚報，松子來門迎。", "接袂語且笑，所歡非欲情。", "丹臉人未老，道貌天已成。", "開筵羅玉粒，盤餐饈紫英。", "綢繆似交舊，灑落懷抱傾。", "薄暮忍云去，徘徊倚山楹。", "欲有重尋約，還憂變高名。"]'),
('f72ac4a3-c373-4ec7-835c-a93a74098cfc','感遇九首  其一','釋契嵩','宋','宋诗','song-poetry','','[]','海水晦夜清，秋色涵蓬壺。',48,'全唐诗/poet.song.16000.json','["海水晦夜清，秋色涵蓬壺。", "有叟雙龍公，鐵網羅珊瑚。", "風雲浩容與，悵恨何所圖。", "欲問天上人，可換明月無。"]'),
('8e124de7-ca5d-408f-b165-b7ef9c272737','感遇九首  其二','釋契嵩','宋','宋诗','song-poetry','','[]','仙人白玉京，去去何縹緲。',72,'全唐诗/poet.song.16000.json','["仙人白玉京，去去何縹緲。", "瓊樓二十層，玲瓏汍雲表。", "銀湟月爲波，萬頃即池沼。", "秋來宮殿光，逗落人間曉。", "空際時澄明，烟暇眇青鳥。", "可見不可到，所思空杳杳。"]'),
('fecd8c52-06da-4404-a9a0-9e2044f4a086','感遇九首  其三','釋契嵩','宋','宋诗','song-poetry','','[]','悠哉楊執戟，識遠才絕奇。',96,'全唐诗/poet.song.16000.json','["悠哉楊執戟，識遠才絕奇。", "初提草玄筆，頗爲人所嗤。", "卓卓孔孟道，謝爾平嶮巇。", "一鑑含幽光，千載方葳蕤。", "寄語曠懷士，未達休嗟咨。", "心期道自貴，俗態勢焉隨。", "青山保長往，白日貞可窺。", "高標謝松柏，孤芳操弗移。"]'),
('b5457f94-b583-41e8-90aa-229939fceb9c','感遇九首  其四','釋契嵩','宋','宋诗','song-poetry','','[]','天威不到處，干戈動邊鄙。',120,'全唐诗/poet.song.16000.json','["天威不到處，干戈動邊鄙。", "將軍奮威猛，英雄勢隨起。", "紛紛出榆關，肅肅秋色裏。", "白馬冒黄雲，清霜厲嚴旨。", "少壯羽林兒，務能莫多喜。", "好武匪君心，用兵不得已。", "寄言飛將軍，妙略應無比。", "志在報君恩，豈爲黄金死。", "丈夫身許國，慷慨當如此。", "寧教太史書，輕笑魯連子。"]'),
('f2e42321-eac5-4930-bc46-33fc2248166f','感遇九首  其五','釋契嵩','宋','宋诗','song-poetry','','[]','蒼茫天地間，流光一何遽。',96,'全唐诗/poet.song.16000.json','["蒼茫天地間，流光一何遽。", "曾聞太古人，未見曦輪駐。", "才沈崦嵫雲，還上浮桑樹。", "山色愁裏暝，天形夢中曙。", "安知穆天子，龍馬神爲御。", "萬里速乘風，又向瑶臺去。", "超遥侶神仙，此理當何故。", "不向堯年長，永使人間住。"]'),
('da79fc5d-1b37-41ca-a96d-430160baed23','感遇九首  其六','釋契嵩','宋','宋诗','song-poetry','','[]','冠蓋何處客，凌雲意氣驕。',144,'全唐诗/poet.song.16000.json','["冠蓋何處客，凌雲意氣驕。", "旦旦趨雙闕，衝衝過渭橋。", "金珂雲外響，畫燭月中燒。", "縹緲行天路，升騰在玉霄。", "如何區宇內，頓與人間遥。", "長拂羅裳去，明光殿下朝。", "一俯復一仰，榮多憂亦饒。", "白髮領邊長，朱顔鏡裏凋。", "豈知松檜下，幽人長寂寥。", "萬事淡無慮，恣卧時長謠。", "浩蕩天地間，孰問犧黄堯。", "臨風一清嘯，胡爲王子喬。"]'),
('57e7cd36-4922-4aaa-946d-2c4cbea1156e','感遇九首  其七','釋契嵩','宋','宋诗','song-poetry','','[]','空虛澄遠煙，霽色含秋景。',48,'全唐诗/poet.song.16000.json','["空虛澄遠煙，霽色含秋景。", "思君每盤桓，駐目千峰頂。", "明月初團圝，可照美人影。", "美人來不來，雲霞渺林嶺。"]'),
('9401b56d-3caa-40b8-afd5-d9b348a6d46b','感遇九首  其八','釋契嵩','宋','宋诗','song-poetry','','[]','松柏地之靈，草莽亦同茂。',72,'全唐诗/poet.song.16000.json','["松柏地之靈，草莽亦同茂。", "願得區域中，人心復純素。", "蒼梧會稽陰，罔復有陵墓。", "六合無知音，青山有歸路。", "人生惜朱顔，賢照長相顧。", "昨夜露華臺，誰不怨秋暮。"]'),
('daaabd54-1d7c-4dc3-8c2a-2cb167f40e27','感遇九首  其九','釋契嵩','宋','宋诗','song-poetry','','[]','悠然嚴子陵，遠大寥廓器。',120,'全唐诗/poet.song.16000.json','["悠然嚴子陵，遠大寥廓器。", "故人貴爲君，白駒要不至。", "耽閑戀淥潭，高超弄芳餌。", "青山汎白雲，萬古寄高意。", "侯覇不知道，初亦嫌傲志。", "何事卑王侯，其心越天地。", "因悲婁護輩，故爲附權勢。", "流游絳灌間，折節蹁蹮例。", "皇皇古皇道，勞生自拘繫。", "不如歸去來，乘風拂長袂。"]'),
('2aea9367-62b4-49fd-85d0-3fe5c6d08896','懷越中兼示山陰諸明士','釋契嵩','宋','宋诗','song-poetry','','[]','厭見人境喧，清游憶靈越。',96,'全唐诗/poet.song.16000.json','["厭見人境喧，清游憶靈越。", "東南千萬山，浮青滿寥泬。", "從來鑑中景，形勝人間絕。", "月湛換鵝溪，雲起藏書穴。", "客子若飄蓬，遽與故人別。", "尺素未及通，芳草已云歇。", "所悲行路難，俯仰損名節。", "鳴鴈欲東飛，寄語謝明月。"]'),
('c50e2f86-447e-4f6f-9abf-2d2ba3e0ac11','早秋吟','釋契嵩','宋','宋诗','song-poetry','','[]','山家昨夜房櫳冷，梧桐一葉飄金井。',128,'全唐诗/poet.song.16000.json','["山家昨夜房櫳冷，梧桐一葉飄金井。", "長天如水凈藏雲，明月含暉變秋景。", "桂枝花拆風飄飄，誰在高樓吹玉簫。", "人間不見槎升漢，天上將看鵲作橋。", "年少征人在何處，白露霑衣未歸去。", "海畔今無漂母家，江南誰與王孫遇。", "徘徊月下空長吟，吾徒自古難知音。", "欲上高臺問明月，明月何不照人心。"]'),
('1b190f6f-568f-48d8-84cd-341cee460fa7','群賢宿山賦得暮雲巖下宿','釋契嵩','宋','宋诗','song-poetry','','[]','微風靜林杪，紅日下巖阿。',48,'全唐诗/poet.song.16000.json','["微風靜林杪，紅日下巖阿。", "明月出已滿，白雲歸未多。", "高應伴猿鶴，深不暗松蘿。", "若弗爲霖去，其如旱歲何。"]'),
('584b5527-6a52-4eff-9fad-962f379a3194','浙江晚望','釋契嵩','宋','宋诗','song-poetry','','[]','暮色看無際，秋空水混天。',48,'全唐诗/poet.song.16000.json','["暮色看無際，秋空水混天。", "片帆飛鳥外，新月落潮邊。", "隔越山形小，吞吳地勢偏。", "幾人來往老，早晚渡頭船。"]'),
('d6208e80-14e7-4126-803d-68d79cf24409','題徑山寺','釋契嵩','宋','宋诗','song-poetry','','[]','翠拔羣山外，連天勢未休。',48,'全唐诗/poet.song.16000.json','["翠拔羣山外，連天勢未休。", "雲迷飛鳥道，雨出古龍湫。", "僧在深雲定，香和杳靄浮。", "人間游不到，臺殿自清秋。"]'),
('b828d300-c7ac-49ff-a5b0-c67137999e2a','郎侍郎致仕','釋契嵩','宋','宋诗','song-poetry','','[]','平時獨高謝，道勝欲韜光。',48,'全唐诗/poet.song.16000.json','["平時獨高謝，道勝欲韜光。", "白髮辭明主，青山戀故鄉。", "藥畦容鶴到，吟徑恐雲藏。", "更愛禪林卧，時來拂石牀。"]'),
('e93c0840-9e4b-4053-8e08-67b1a5c9664a','山中早梅','釋契嵩','宋','宋诗','song-poetry','','[]','亭亭映晚景，皎皎出林端。',48,'全唐诗/poet.song.16000.json','["亭亭映晚景，皎皎出林端。", "小圃連雲淡，孤芳冒雪寒。", "人間殊未見，物外最先看。", "但欲方瓊玉，寧將勝牡丹。"]'),
('69c49b9d-6065-44f8-b2d0-98895b6aecd1','汎若耶溪','釋契嵩','宋','宋诗','song-poetry','','[]','越水乘春泛，船窗掩又開。',48,'全唐诗/poet.song.16000.json','["越水乘春泛，船窗掩又開。", "好山沿岸去，驟雨落花來。", "岸影樵人渡，歌聲浣女回。", "滄浪無限意，日暮更悠哉。"]'),
('f4b90f5c-7e76-4c9a-b951-1b27d21b21a7','書毛有章園亭','釋契嵩','宋','宋诗','song-poetry','','[]','愛此園林好，重來花木滋。',48,'全唐诗/poet.song.16000.json','["愛此園林好，重來花木滋。", "游人醉不去，幽鳥語無時。", "烟郭連芳草，春湖泛淥池。", "松篁非俗韻，游子漫相期。"]'),
('cbba42cf-6ba5-48da-b473-26a7002204bd','山亭晚春','釋契嵩','宋','宋诗','song-poetry','','[]','山庭晚來靜，林石自巉喦。',48,'全唐诗/poet.song.16000.json','["山庭晚來靜，林石自巉喦。", "犬去吠人語，花飛恣鳥銜。", "晴烟熏茂草，煦日藹高杉。", "更喜團圓月，清光下碧巖。"]'),
('ab4dd912-6d6d-4010-a400-c278e5113bd1','自贈','釋契嵩','宋','宋诗','song-poetry','','[]','靜坐還看竹，閒行亦合樵。',48,'全唐诗/poet.song.16000.json','["靜坐還看竹，閒行亦合樵。", "道心應有在，生事合無憀。", "客去清談少，年來白髮饒。", "漫將支遁筆，閒且賦逍遥。"]'),
('c9dcd8a6-10c4-4ce0-af2a-82ee6ef0f945','夏日無雨','釋契嵩','宋','宋诗','song-poetry','','[]','山中苦無雨，日日望雲霓。',48,'全唐诗/poet.song.16000.json','["山中苦無雨，日日望雲霓。", "小暑復大暑，深溪成淺溪。", "泉枯連井底，地熱亢蔬畦。", "無以問天意，空思水鳥啼。"]'),
('17256186-66dc-4d1d-9986-f6e7f445071a','歲暮書懷','釋契嵩','宋','宋诗','song-poetry','','[]','朔風適變寒，曉日將含煦。',48,'全唐诗/poet.song.16000.json','["朔風適變寒，曉日將含煦。", "南國殊未還，東山歲云暮。", "浮生奄忽往，芳顔安得駐。", "寄謝人世間，紛華尤可悟。"]'),
('a7ce2c37-fc62-48ce-b7e8-05d5cafcf367','山中早行','釋契嵩','宋','宋诗','song-poetry','','[]','前山經夜雨，獨往步春泥。',48,'全唐诗/poet.song.16000.json','["前山經夜雨，獨往步春泥。", "天岸日將出，田家雞更啼。", "孤烟行處起，曠野望中低。", "猶喜逢樵客，相將過數溪。"]'),
('8a01b870-c5b5-49e2-8e9c-86af1d0c51bf','湖上晚歸','釋契嵩','宋','宋诗','song-poetry','','[]','人間薄游罷，歸興尋舊隱。',48,'全唐诗/poet.song.16000.json','["人間薄游罷，歸興尋舊隱。", "春岸行未窮，夕陽看欲盡。", "嵐光山際淡，天影水邊近。", "自憐幽趣真，清吟更長引。"]'),
('089c2562-1f7a-49cb-a85d-bf1d47480099','季春寄友生','釋契嵩','宋','宋诗','song-poetry','','[]','湖上無烟晝，人間寒食時。',48,'全唐诗/poet.song.16000.json','["湖上無烟晝，人間寒食時。", "陰晴春易變，花月候難齊。", "未畏青蛙亂，先愁紫蕨衰。", "雲山向漸熱，相訪勿應遲。"]'),
('e3b8bb6d-9ac8-47e6-9048-cd20d7eb2b1a','寄懷泐潭山月禪師','釋契嵩','宋','宋诗','song-poetry','','[]','聞道安禪處，深蘿杳隔溪。',48,'全唐诗/poet.song.16000.json','["聞道安禪處，深蘿杳隔溪。", "清猿定中發，幽鳥坐邊栖。", "雲影朝晡別，山峯遠近齊。", "不知誰問法，雪夜立江西。"]'),
('f828401a-c281-42dd-bcad-9b505bab615f','送客還北闕道中作','釋契嵩','宋','宋诗','song-poetry','','[]','北郭送陽子，日斜歸舊居。',48,'全唐诗/poet.song.16000.json','["北郭送陽子，日斜歸舊居。", "路泥侵曉潤，晦月逼春餘。", "桑柘雨中綠，人烟關外疎。", "依然見風俗，歸興混樵漁。"]'),
('a858f377-ba67-4e7b-ab6a-24510083d158','次韻無{巩/言}赴承天再命','釋契嵩','宋','宋诗','song-poetry','','[]','載命還高讓，知君所趣深。',48,'全唐诗/poet.song.16000.json','["載命還高讓，知君所趣深。", "青山當隱處，白髮欲栖心。", "更俟逢梅雨，何妨過虎林。", "潺湲合澗水，六月足清音。"]'),
('6093b7e1-1437-487b-8adf-c061cffbda06','山舍晚歸','釋契嵩','宋','宋诗','song-poetry','','[]','薄暮還精廬，徐行無所並。',48,'全唐诗/poet.song.16000.json','["薄暮還精廬，徐行無所並。", "日入月還清，山空水更靜。", "彷彿聞疎鐘，翛然在西嶺。", "寄語高世流，來茲謝塵境。"]'),
('8bba38e1-4b97-44fa-b477-75d5bd5eacef','讀書','釋契嵩','宋','宋诗','song-poetry','','[]','讀書老何爲，更讀聊遮眼。',48,'全唐诗/poet.song.16000.json','["讀書老何爲，更讀聊遮眼。", "此意雖等閒，高情寄無限。", "錯磨千古心，翻覆幾忘飯。", "不知白雲去，春靜山中晚。"]'),
('be2e32c8-6e6a-4638-9da5-82519241d9c0','送盧隱士歸廬山','釋契嵩','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','世事如循環，是非終莫盡。',48,'全唐诗/poet.song.16000.json','["世事如循環，是非終莫盡。", "羨爾歸深山，任他譏小隱。", "黄鵠舉已高，白雲去非近。", "天籟歸寂寞，何峰弄清軫。"]'),
('a36f26bf-93b7-4139-9941-c7a326d68924','還南屏山即事','釋契嵩','宋','宋诗','song-poetry','','[]','歲晚歸來石室寒，松蘿岑寂自盤桓。',64,'全唐诗/poet.song.16000.json','["歲晚歸來石室寒，松蘿岑寂自盤桓。", "但知林下一年過，不見人間萬事難。", "招隱有詩題石記，解嘲無說與時看。", "此心已共空生合，身似浮雲不必觀。"]'),
('34958f48-65a5-462b-9625-a255e8a02298','入石壁山','釋契嵩','宋','宋诗','song-poetry','','[]','身似浮雲年似流，人間擾攘只宜休。',64,'全唐诗/poet.song.16000.json','["身似浮雲年似流，人間擾攘只宜休。", "老來已習青蘿子，隱去應追白道猷。", "填入亂山寧計路，定看落葉始知秋。", "他時谷口人相遇，莫問裁詩謝五侯。"]'),
('40b976b9-4561-4601-be90-9cb55489461d','山中自怡謝所知','釋契嵩','宋','宋诗','song-poetry','','[]','萬事隨宜勿强攀，暫過朝市即歸山。',64,'全唐诗/poet.song.16000.json','["萬事隨宜勿强攀，暫過朝市即歸山。", "勞生未必浮名好，稱性應須到處閑。", "都似夢中休問影，只堪吟裏更怡顔。", "襄陽道者寧知爾，猿鶴蕭然石室間。"]'),
('33811a38-4c48-45f7-8a8c-158740a065b3','寄承天元老','釋契嵩','宋','宋诗','song-poetry','','[]','清散年來事益閒，不論林下與人間。',64,'全唐诗/poet.song.16000.json','["清散年來事益閒，不論林下與人間。", "禪心至了非喧靜，默客何妨更往還。", "奇石清軒增勝趣，流泉碧座照衰顔。", "支形脫略時機甚，應笑歸來別買山。"]'),
('08e13885-2757-40dd-8597-23de4e7c43d1','誡題','釋契嵩','宋','宋诗','song-poetry','','[]','高吟遠矚倚雲梯，往事經心盡可題。',64,'全唐诗/poet.song.16000.json','["高吟遠矚倚雲梯，往事經心盡可題。", "道德二篇徒自辯，是非一馬豈能齊。", "暉山真玉傷驚火，失水靈蛇畏在泥。", "寄語冥鴻上天去，凌雲羽翼莫思低。"]'),
('ef7f1cc5-1f12-4d62-b4d0-19119d98db25','元日','釋契嵩','宋','宋诗','song-poetry','','[]','暗裏春催曙色明，百雞迎曉報新聲。',64,'全唐诗/poet.song.16000.json','["暗裏春催曙色明，百雞迎曉報新聲。", "宿寒尚在龍蛇蟄，歲曆初傳日月迎。", "蓂葉四時今始發，梅花一旦占先榮。", "山家也祝堯天壽，漫學牛山報太平。"]'),
('1d8fe225-9c55-4df7-9d44-db928da36058','著書罷思南還復會客自番禺來因賦此詩','釋契嵩','宋','宋诗','song-poetry','','[]','平昔著書今粗畢，南還終欲隱羅浮。',64,'全唐诗/poet.song.16000.json','["平昔著書今粗畢，南還終欲隱羅浮。", "初春況遇故鄉子，終夜更誇滄海遊。", "但貴羊城風物好，豈辭梅嶺路歧脩。", "應須相與葛洪輩，抗迹山林送白頭。"]'),
('341f916d-ceba-4001-a629-2236b30753b9','冷泉獨賞寄沖晦上人','釋契嵩','宋','宋诗','song-poetry','','[]','南風掠波溪水滿，山中幽人來洗浣。',64,'全唐诗/poet.song.16000.json','["南風掠波溪水滿，山中幽人來洗浣。", "獨立溪傍清興欵，更愛泉流芳草短。", "平生幽討貴蕭散，世道紛紜何足算。", "人間五月夏雲煩，相約歸爲君莫緩。"]'),
('3dc00c39-1548-4aee-bfa1-a32caac5733b','遣興三絕  其一','釋契嵩','宋','宋诗','song-poetry','','[]','逸興應須傚皎然，此生瀟灑老詩禪。',32,'全唐诗/poet.song.16000.json','["逸興應須傚皎然，此生瀟灑老詩禪。", "何妨剩得驚人句，詠徧江山一萬篇。"]'),
('3d112a64-26f4-4f0f-93ca-799c69836bf7','遣興三絕  其二','釋契嵩','宋','宋诗','song-poetry','','[]','吾道陵遲事事訛，而今無計遏頹波。',32,'全唐诗/poet.song.16000.json','["吾道陵遲事事訛，而今無計遏頹波。", "徇人玩法成流俗，但泣金書奈爾何。"]'),
('d3af2b85-6ea8-45da-a7d8-ba688987fad0','遣興三絕  其三','釋契嵩','宋','宋诗','song-poetry','','[]','去年聊駐江頭寺，今寄林僧喦下扃。',32,'全唐诗/poet.song.16000.json','["去年聊駐江頭寺，今寄林僧喦下扃。", "莫謂此身無定迹，人生都類一浮萍。"]'),
('89da7892-0af8-491e-bc6b-0e90b01ba779','書南山六和寺','釋契嵩','宋','宋诗','song-poetry','','[]','青葱玉樹接溪岑，臺閣凌虛地布金。',32,'全唐诗/poet.song.16000.json','["青葱玉樹接溪岑，臺閣凌虛地布金。", "行到白雲重疊處，水聲松韻淡人心。"]'),
('f95be624-f07c-4b15-bafe-2a3451f19533','寒食日雨中','釋契嵩','宋','宋诗','song-poetry','','[]','漠漠行雲晴復陰，野花垂濕晚沉沉。',32,'全唐诗/poet.song.16000.json','["漠漠行雲晴復陰，野花垂濕晚沉沉。", "游人莫怨天多雨，況在東臯春已深。"]'),
('0240c8c7-6523-4871-a17e-b875f029c96f','早起','釋契嵩','宋','宋诗','song-poetry','','[]','天窗月過星踈渺，檐際冥分雲窈窕。',32,'全唐诗/poet.song.16000.json','["天窗月過星踈渺，檐際冥分雲窈窕。", "山家深處勿雞啼，時有寒鵶來報曉。"]'),
('d97f170a-efa3-4a7e-91b0-4f7d6b3a9f39','對喜鵲','釋契嵩','宋','宋诗','song-poetry','','[]','靜卧時驚鵲喜多，須臾果有故人過。',32,'全唐诗/poet.song.16000.json','["靜卧時驚鵲喜多，須臾果有故人過。", "山中明度還無事，問爾綿蠻更語麽。"]'),
('058629bd-c8a3-49bd-9b49-2ccc317f5054','寄晤沖晦','釋契嵩','宋','宋诗','song-poetry','','[]','年老相看眼倍青，念君詩思苦勞形。',32,'全唐诗/poet.song.16000.json','["年老相看眼倍青，念君詩思苦勞形。", "人間更有無窮感，好把禪關護性靈。"]'),
('e8b47f22-3151-46ee-8f99-60624089fed5','洗筆','釋契嵩','宋','宋诗','song-poetry','','[]','古人信文字，字字從此出。',36,'全唐诗/poet.song.16000.json','["古人信文字，字字從此出。", "天下心不欺，爾亦有陰隲。", "濯之遺孺子，念茲未應失。"]'),
('e3d77594-8449-4204-a7f9-08943d3dcc7d','遊大慈山書晝上人壁','釋契嵩','宋','宋诗','song-poetry','','[]','谷裏侵雲寺，尋幽到深處。',36,'全唐诗/poet.song.16000.json','["谷裏侵雲寺，尋幽到深處。", "春過寒花開，人來啼鳥去。", "豈期草庵客，日暮此相遇。"]'),
('2330e97d-5acd-4307-b9e5-99009df36bd2','清溪','釋契嵩','宋','宋诗','song-poetry','','[]','勿謂清溪清，長如鏡初洗。',24,'全唐诗/poet.song.16000.json','["勿謂清溪清，長如鏡初洗。", "須防苟容物，汙爾清到底。"]'),
('5bd6332d-6fae-43c8-8765-e20c2baf24d7','歲暮值雪山齋焚香獨坐命童取雪烹茗因思柳絮隨風起之句遂取謝道藴傳讀之見其神情散朗故有林下風氣益發幽興乃爲詩兼簡居士公濟彼上人沖晦','釋契嵩','宋','宋诗','song-poetry','','[]','簷外驚風幽鳥歸，窗間獨坐事還稀。',64,'全唐诗/poet.song.16000.json','["簷外驚風幽鳥歸，窗間獨坐事還稀。", "初看曆日新年近，喜見山林驟雪飛。", "但憶故人能有詠，寧懷久客此無衣。", "鮑昭湯老能乘興，城郭何如大翠微。"]'),
('89e2193b-dad3-4f98-83ba-eb54c34779f9','次韻和酬','釋契嵩','宋','宋诗','song-poetry','','[]','襄陽習子不貪官，欲友幽人擬道安。',64,'全唐诗/poet.song.16000.json','["襄陽習子不貪官，欲友幽人擬道安。", "冒雪履霜臨歲杪，攀蘿挽翠到雲端。", "初論浮世慚年老，久對清規苦夜寒。", "空感知音何以報，但誇山水富君看。"]'),
('73f0eadf-e0d6-44fa-8182-083805888673','次韻和酬','釋契嵩','宋','宋诗','song-poetry','','[]','歲晚陰沈天宇昏，宗雷訪我更携君。',64,'全唐诗/poet.song.16000.json','["歲晚陰沈天宇昏，宗雷訪我更携君。", "相期石屋宜投宿，獨憩山茨學卧雲。", "雪映窗櫺人已靜，風吟燈影夜初分。", "自憐惠永多閑散，强接清言媿不文。"]'),
('07a8e031-843b-486d-884a-206cabee5590','次韻和酬','釋契嵩','宋','宋诗','song-poetry','','[]','詩豪何遜宿喦扃，品格高卑徹曉評。',64,'全唐诗/poet.song.16000.json','["詩豪何遜宿喦扃，品格高卑徹曉評。", "未省窗前無月到，唯驚席上有風生。", "郄超年少偏高隱，莊子才雄不近名。", "明日君歸入落去，莫將平叔擬虛聲。"]'),
('09b8d45d-ff0b-4aca-ba52-3d568122ce6c','嘉公濟沖晦見訪','釋契嵩','宋','宋诗','song-poetry','','[]','數曲青溪山數重，山深日暮已鳴鐘。',64,'全唐诗/poet.song.16000.json','["數曲青溪山數重，山深日暮已鳴鐘。", "忽聞行客門前語，來覓幽人林下蹤。", "初接風流殊歷落，更張燈火倍迎逢。", "不須便去疑無待，已有黄糧在宿舂。"]'),
('e4d1cc97-e4f5-4fab-8b08-fd590152167f','次韻和酬','釋契嵩','宋','宋诗','song-poetry','','[]','暮雲將雨苦紛紛，看雨携君倚寺門。',64,'全唐诗/poet.song.16000.json','["暮雲將雨苦紛紛，看雨携君倚寺門。", "飛鳥驚雷歸後塢，落梅流水出前村。", "名山當爾何須去，勝事而今更好論。", "況有禪翁通妙理，徘徊重欵扣真源。"]'),
('213f15f0-e6ed-44a9-939b-b1e73e890b35','同公濟沖晦宿靈隱夜晴','釋契嵩','宋','宋诗','song-poetry','','[]','不睡還烹北苑茶，寒燈落盡適未花。',64,'全唐诗/poet.song.16000.json','["不睡還烹北苑茶，寒燈落盡適未花。", "夜深雨過山形出，天靜雲空月色佳。", "且喜僧窗晴似晝，莫論人世事如麻。", "況陪支許皆能賦，豈厭留詩在碧紗。"]'),
('a6a0f1b9-6845-4645-acc5-89a553533570','次韻和酬','釋契嵩','宋','宋诗','song-poetry','','[]','澗北夜依禪舍宿，峰南今訪講師堂。',64,'全唐诗/poet.song.16000.json','["澗北夜依禪舍宿，峰南今訪講師堂。", "初行松路愛清曉，及過石橋聞異香。", "日色煖烘諸壑浄，晴嵐翠潑幾峰光。", "道標尚客何高趣，更飲吾曹柏葉湯。"]'),
('7b738650-5a72-4571-a959-7711a7a9034b','南澗傍遊戲呈公濟沖晦','釋契嵩','宋','宋诗','song-poetry','','[]','相引朝來碧澗傍，山林雪盡水流長。',64,'全唐诗/poet.song.16000.json','["相引朝來碧澗傍，山林雪盡水流長。", "未應驚鳥下苔岸，先共觀魚跨石梁。", "日淡沙寒鷗自聚，歲闌春入草含芳。", "鮑昭湯老須同詠，何必人間萬事忙。"]'),
('74b3f4a6-1138-4488-a213-9bfe1eb50dc6','次韻和酬','釋契嵩','宋','宋诗','song-poetry','','[]','共訪迢遥深塢寺，仍隨野老賣樵還。',64,'全唐诗/poet.song.16000.json','["共訪迢遥深塢寺，仍隨野老賣樵還。", "鳥栖已定人方到，暮色雖濃門未關。", "今宿喦房休問法，來朝蠟屐重登山。", "平生勝友殊難會，莫厭相携寂寞間。"]'),
('2a758a75-3bc5-4873-bd85-e9652e708c45','同公濟沖晦遊天竺兼簡呈伯周禪老','釋契嵩','宋','宋诗','song-poetry','','[]','愛此蕭然松塢深，詩流邀我此相尋。',64,'全唐诗/poet.song.16000.json','["愛此蕭然松塢深，詩流邀我此相尋。", "蒼茫寒日纔開霧，靉靆濃雲又結陰。", "安石放懷還劇賞，皎然乘興合清吟。", "主人勤駐禪扉宿，況值梅香正滿林。"]'),
('715c2094-6c52-4529-a5e3-dfe393167a15','次韻奉和','釋契嵩','宋','宋诗','song-poetry','','[]','沈侯才雋冠儒林，詩語驚人金玉音。',64,'全唐诗/poet.song.16000.json','["沈侯才雋冠儒林，詩語驚人金玉音。", "學海平生慚我淺，詞源今日羨君深。", "强睎老格須張膽，喜聽清言更洗心。", "賡唱苟能容累句，漫陪梁甫續高吟。"]'),
('12cdec74-2df9-478c-a309-8c8e9f2418a8','同公濟宿天竺寺賦聞泉','釋契嵩','宋','宋诗','song-poetry','','[]','幾晏林間宿，初聞況夜晴。',48,'全唐诗/poet.song.16000.json','["幾晏林間宿，初聞況夜晴。", "漱寒醒客夢，飛響應山鳴。", "深澗松風靜，幽人石室清。", "誰人能爲我，寫此入琴聲。"]'),
('dc726256-bccc-4612-8a09-99f66bac09f7','送公濟沖晦出山兼簡駐泊李思文','釋契嵩','宋','宋诗','song-poetry','','[]','幾日山遊霰雪稀，相隨野老亦忘機。',64,'全唐诗/poet.song.16000.json','["幾日山遊霰雪稀，相隨野老亦忘機。", "始憐洞裏雲堪卧，又憶人間歲杪歸。", "夜落梅花應滿路，風含春色自吹衣。", "憑君爲語王孫道，音信終須寄鳥飛。"]'),
('bca89def-3cc1-4953-8eea-8d7d2626abc4','次韻和酬','釋契嵩','宋','宋诗','song-poetry','','[]','嚴維靈徹出山時，避雨曾聞礙木枝。',64,'全唐诗/poet.song.16000.json','["嚴維靈徹出山時，避雨曾聞礙木枝。", "幾杪霜寒何足畏，管中春色已堪吹。", "風含鐘韻凝還散，水結溪聲咽又悲。", "鬭草野遊君莫笑，初平元是牧羊兒。"]'),
('80ff3675-48f6-4e20-8fe2-38c496424bb2','次韻奉酬','釋契嵩','宋','宋诗','song-poetry','','[]','君事逍遥入亂雲，與君躡屐遍溪鄰。',64,'全唐诗/poet.song.16000.json','["君事逍遥入亂雲，與君躡屐遍溪鄰。", "林間聽鳥聞偏好，烟際觀山見匪真。", "澗水只能忙送客，岩花不解久留人。", "樂天更有龍門約，勝會應須趁早春。"]'),
('4561945a-294e-493a-9ec6-bbf4057a6e21','連得公濟出山道中見示二篇鄙思枯涸奉和不暇且乞罷唱','釋契嵩','宋','宋诗','song-poetry','','[]','詩篇留落野人窗，又得虞卿璧一雙。',64,'全唐诗/poet.song.16000.json','["詩篇留落野人窗，又得虞卿璧一雙。", "怪似蛟龍出古水，清如日月浸秋江。", "賡吟何止夸山澤，變雅終須繫國邦。", "爲報詩家驍將道，雪闌休唱已心降。"]'),
('cce8f2a4-959a-41d7-be53-7cb743477883','次韻和酬','釋契嵩','宋','宋诗','song-poetry','','[]','忽憶山中人白頭，歲闌來看雪初收。',64,'全唐诗/poet.song.16000.json','["忽憶山中人白頭，歲闌來看雪初收。", "詩篇見賞皆高興，謝客相隨匪俗流。", "漫有嵓雲供夜卧，況無土食備晨羞。", "愛君吟詠殊堪聽，金玉聲音勝楚囚。"]'),
('944c3957-3a0e-448b-8925-38ec7b8c5c25','公濟沖晦出山次日奉寄','釋契嵩','宋','宋诗','song-poetry','','[]','孫綽曾陪支遁遊，千年人謂兩風流。',64,'全唐诗/poet.song.16000.json','["孫綽曾陪支遁遊，千年人謂兩風流。", "羨君慕此乘雙屐，結侶還來共一丘。", "衣冷雪霜猶未去，興高雲月肯甘收。", "耽詩重道皆無比，應敵當時萬戶侯。"]'),
('1abc2d13-2ed7-444f-821c-517490a17292','次韻奉和','釋契嵩','宋','宋诗','song-poetry','','[]','樂天已與廣宣遊，更出風塵外俗流。',64,'全唐诗/poet.song.16000.json','["樂天已與廣宣遊，更出風塵外俗流。", "酒聖盡能非畢卓，詩仙皆欲接浮丘。", "篇章逸處江山動，筆硯閒時雲雨收。", "況有聲名俱籍甚，並飛南北動王侯。"]'),
('fa6d543f-ab9d-4208-a17d-d04d2ea9cf8c','歲暮還西塢寄公濟無{巩/言}','釋契嵩','宋','宋诗','song-poetry','','[]','乘興溪邊去，仍從林下歸。',48,'全唐诗/poet.song.16000.json','["乘興溪邊去，仍從林下歸。", "梅香带春信，日色暖人衣。", "白髮思還遠，清流遇更稀。", "野禽寧會意，相顧向柴扉。"]'),
('3c9a20a9-7b70-4282-b0a6-c28ef440e41e','次韻奉酬','釋契嵩','宋','宋诗','song-poetry','','[]','翛然林下隱，吾道異夫君。',48,'全唐诗/poet.song.16000.json','["翛然林下隱，吾道異夫君。", "習忍如幽草，觀身類片雲。", "人情無意染，鶴唳有時聞。", "謝客詩懷寄，憐君此興勤。"]'),
('3d7b0a47-ff7c-4c81-bcdb-805c967dcef0','次韻奉酬','釋契嵩','宋','宋诗','song-poetry','','[]','暝色陰森雪和雲，故人當此動吟魂。',64,'全唐诗/poet.song.16000.json','["暝色陰森雪和雲，故人當此動吟魂。", "烟凝火冷萬家靜，水色山光竟夜昏。", "興發晉賢前古遠，詩傳蕭寺邇今存。", "春歸嵓壑多芳樹，漫欲邀君同聽猿。"]'),
('335b4f47-a542-4f62-989e-faf1c157cd3e','即事  其三','楊冠卿','宋','宋诗','song-poetry','','[]','未辦因人出，時歌不我過。',48,'全唐诗/poet.song.160000.json','["未辦因人出，時歌不我過。", "墨泓雲脚亂，藥鼎雨聲多。", "三篾閲浮世，把茆營懶窠。", "肯將猶在舌，容易說干戈。"]'),
('983aa7c9-0fe2-473f-89a3-df0221934b61','讀書','楊冠卿','宋','宋诗','song-poetry','','[]','憂世終何補，忠懷悵不平。',48,'全唐诗/poet.song.160000.json','["憂世終何補，忠懷悵不平。", "收回長太息，翻作短歌行。", "是事且復置，今人誰可盟。", "湘中千樹橘，墨墨了餘生。"]'),
('c59a11af-fa08-4b65-a5d5-434ad3e25c4b','題凌波采蓮圖','楊冠卿','宋','宋诗','song-poetry','','[]','綽約風姿雲霧衣，波心新月映明輝。',32,'全唐诗/poet.song.160000.json','["綽約風姿雲霧衣，波心新月映明輝。", "更深折得清香去，煙靄不知何處歸。"]'),
('6b5fde48-8ac4-4f5d-a49d-9f32df39b627','歸塗春晚  其一','楊冠卿','宋','宋诗','song-poetry','','[]','待得春歸人亦歸，風花撩亂撲征衣。',32,'全唐诗/poet.song.160000.json','["待得春歸人亦歸，風花撩亂撲征衣。", "清香十里荼蘼路，零落珠幢對晚暉。"]'),
('80d525f7-271d-464f-9fe3-c437d4515c49','歸塗春晚  其二','楊冠卿','宋','宋诗','song-poetry','','[]','點點更籌清夜徂，昏昏鄉月瑣窗虛。',32,'全唐诗/poet.song.160000.json','["點點更籌清夜徂，昏昏鄉月瑣窗虛。", "夢回忽聽狂風雨，明日前村花更疎。"]'),
('50e5c5df-1683-4796-8e4e-7bd30eba7b4b','歸塗春晚  其三','楊冠卿','宋','宋诗','song-poetry','','[]','蹔解征驂野水湄，卷衣上馬夜何其。',32,'全唐诗/poet.song.160000.json','["蹔解征驂野水湄，卷衣上馬夜何其。", "客愁政自不堪說，殘月一聲聞子規。"]'),
('55f64d05-eac5-4121-bdb0-b4f4d912bc56','山茶','楊冠卿','宋','宋诗','song-poetry','','[]','綠葉巃嵷襯渥丹，疎林殘雪尚班班。',32,'全唐诗/poet.song.160000.json','["綠葉巃嵷襯渥丹，疎林殘雪尚班班。", "先驅特爲東君至，怕向春風桃李間。"]'),
('78700e29-44df-40b2-8465-baa255f1f7f6','道間所見','楊冠卿','宋','宋诗','song-poetry','','[]','窄窄山腰路，娟娟屋角花。',24,'全唐诗/poet.song.160000.json','["窄窄山腰路，娟娟屋角花。", "谿回蔽修竹，鷗暖戲春沙。"]'),
('1e20883a-92c6-44cc-b68e-f29f74ce0919','夾江  其一','楊冠卿','宋','宋诗','song-poetry','','[]','雨洗山容靜，江流塞水通。',48,'全唐诗/poet.song.160000.json','["雨洗山容靜，江流塞水通。", "征塗萬煙樹，行色一秋蓬。", "黯澹平郊霧，清徐邃谷風。", "直須歌緩緩，莫作去怱怱。"]'),
('79190269-d7c4-4c2d-80a9-50b4c3f7f9d6','夾江  其二','楊冠卿','宋','宋诗','song-poetry','','[]','麥浪浮濃綠，山眉暈遠青。',48,'全唐诗/poet.song.160000.json','["麥浪浮濃綠，山眉暈遠青。", "光風來婉娩，客意獨伶俜。", "回鴈鳴何許，輕鷗下遠汀。", "人家總幽隠，煙雨竹門扃。"]'),
('ed47081b-a31c-431d-84a8-15b0aae8134c','漫題','楊冠卿','宋','宋诗','song-poetry','','[]','著雨林花暗，敲風檻竹幽。',24,'全唐诗/poet.song.160000.json','["著雨林花暗，敲風檻竹幽。", "翠屏疎得夢，紅葉忽驚秋。"]'),
('293c70fb-dec5-46db-9db9-534a965c3430','適安旅次  其一','楊冠卿','宋','宋诗','song-poetry','','[]','山郭蕭條晚，秋堂窈窕深。',48,'全唐诗/poet.song.160000.json','["山郭蕭條晚，秋堂窈窕深。", "輕寒籠暮靄，橫吹度疎砧。", "叢竹深藏翠，孤雲带晚陰。", "淹留有幽趣，不礙短長吟。"]'),
('e9566b62-74f3-4633-a771-1661a23c0c4c','適安旅次  其二','楊冠卿','宋','宋诗','song-poetry','','[]','檻蒲行碧瘦，林葉得紅深。',48,'全唐诗/poet.song.160000.json','["檻蒲行碧瘦，林葉得紅深。", "客子倦長夜，居人催暮砧。", "風梢窗紙急，月轉藥欄陰。", "高枕已無睡，寒螿休苦吟。"]'),
('e4334941-9bae-49a3-8072-e249b10a7b14','曉思','楊冠卿','宋','宋诗','song-poetry','','[]','山鳥春猶咽，城烏曉亂啼。',48,'全唐诗/poet.song.160000.json','["山鳥春猶咽，城烏曉亂啼。", "危譙初罷角，落月已催雞。", "地迥來何事，家遥夢到迷。", "片懷如許惡，深覺負瓜畦。"]'),
('4ea3008b-3bfd-4b98-b704-69ed9352bddd','雪後','楊冠卿','宋','宋诗','song-poetry','','[]','野日茅茨短，荒村霰雪餘。',48,'全唐诗/poet.song.160000.json','["野日茅茨短，荒村霰雪餘。", "溪流山足裂，谷迥鳥聲虛。", "矯首懷新隠，歸窗有舊書。", "殘年甘飽飯，何必事名譽。"]'),
('95136c2b-4595-43eb-8a88-f4f8da8dd180','觀諸園接花果','楊冠卿','宋','宋诗','song-poetry','','[]','花木聊觀化，芳菲觸處同。',48,'全唐诗/poet.song.160000.json','["花木聊觀化，芳菲觸處同。", "大都知歲晚，各自占春風。", "巧著移根力，陰爭造物功。", "化鈞均播埴，此理杳冥中。"]'),
('580320af-b49c-4378-b741-ce53e4e8e895','寒食雨中  其一','楊冠卿','宋','宋诗','song-poetry','','[]','無家可耐異鄉何，怪底愁邊萬感多。',32,'全唐诗/poet.song.160000.json','["無家可耐異鄉何，怪底愁邊萬感多。", "今夜雨昏山月暗，泪痕元不減金波。"]'),
('29c6fd40-3aa8-4ff6-bad4-dec1dfca16bb','寒食雨中  其二','楊冠卿','宋','宋诗','song-poetry','','[]','晚風一再花狼籍，春去怱怱不可尋。',32,'全唐诗/poet.song.160000.json','["晚風一再花狼籍，春去怱怱不可尋。", "蜂蝶亦如人意薄，便無消息到牆陰。"]'),
('9b1f89d0-5ebd-4ac7-8df2-ad0f43350375','渡口','楊冠卿','宋','宋诗','song-poetry','','[]','欲繫孤舟日已斜，秋霜一岸著蒹葭。',32,'全唐诗/poet.song.160000.json','["欲繫孤舟日已斜，秋霜一岸著蒹葭。", "若爲喚得愁魂醒，柱杖穿沙尋酒家。"]'),
('fa550882-4b4b-4edc-9285-b5429dac3aa3','絕句  其一','楊冠卿','宋','宋诗','song-poetry','','[]','東閣官梅已退粧，遠村沙柳發新黄。',32,'全唐诗/poet.song.160000.json','["東閣官梅已退粧，遠村沙柳發新黄。", "遥知歸去西江路，定有飛花觸地香。"]'),
('b3d55e38-7091-418f-bec5-28fbfcb9bf7b','絕句  其二','楊冠卿','宋','宋诗','song-poetry','','[]','忽憶前時小院歸，杏花牆角兩三枝。',32,'全唐诗/poet.song.160000.json','["忽憶前時小院歸，杏花牆角兩三枝。", "夜香燒斷黄昏月，縹緲隣家玉笛吹。"]'),
('fa681055-a0e1-4ae9-9da3-ba3733e31749','始覺','楊冠卿','宋','宋诗','song-poetry','','[]','始覺躬耕晚，從誰話此情。',48,'全唐诗/poet.song.160000.json','["始覺躬耕晚，從誰話此情。", "但能安食息，敢復計聲名。", "留滯煩書信，驅馳愧友生。", "有懷愁不盡，歸鳥暮雲橫。"]'),
('0e3db053-1e2b-4a35-9ce5-0fc35fe1afe4','自檇李至毗陵道中  其一','楊冠卿','宋','宋诗','song-poetry','','[]','風捲雲歸雨忽晴，月輪安穩上青冥。',32,'全唐诗/poet.song.160000.json','["風捲雲歸雨忽晴，月輪安穩上青冥。", "怪來枕底流泉急，去去短桅初不停。"]'),
('cb33b7aa-d9e0-4442-85bb-290267fdfb33','自檇李至毗陵道中  其二','楊冠卿','宋','宋诗','song-poetry','','[]','朱槿碧蘆相間栽，蓬棚車水過塍來。',32,'全唐诗/poet.song.160000.json','["朱槿碧蘆相間栽，蓬棚車水過塍來。", "茸茸秋色濃如染，已有陂塘似鏡開。"]'),
('03127451-069d-44ff-9b6b-266a397747b4','自檇李至毗陵道中  其三','楊冠卿','宋','宋诗','song-poetry','','[]','極目雲天意已舒，迎人草樹綠扶疎。',32,'全唐诗/poet.song.160000.json','["極目雲天意已舒，迎人草樹綠扶疎。", "望中孤塔松江近，便有小船來賣魚。"]'),
('cb1d8a77-f6cc-4c0c-8ee9-ec2608861711','自檇李至毗陵道中  其四','楊冠卿','宋','宋诗','song-poetry','','[]','滿目江山無限情，夫差城郭暮雲平。',32,'全唐诗/poet.song.160000.json','["滿目江山無限情，夫差城郭暮雲平。", "當時不競黄池長，一再何由致越兵。"]'),
('90c53e43-77bb-4dc7-99aa-e602c66675a3','自檇李至毗陵道中  其五','楊冠卿','宋','宋诗','song-poetry','','[]','晉陵城東窣堵坡，兩尖高並下臨河。',32,'全唐诗/poet.song.160000.json','["晉陵城東窣堵坡，兩尖高並下臨河。", "昔年曾醉隣牆酒，卧聽扁舟唱踏歌。"]'),
('36e96934-0547-4c8b-ad33-8b2fbdf201c9','癸卯春雜用古語繼吳監簿水月即事','楊冠卿','宋','宋诗','song-poetry','','[]','霜日炫晴晝，意行春色隨。',48,'全唐诗/poet.song.160000.json','["霜日炫晴晝，意行春色隨。", "平林花淡淡，荒墅草離離。", "竹徑通幽處，山雲薄暮時。", "壺觴情未極，飛鞚返青絲。"]'),
('b70cb1ad-3887-4e45-a74e-4b111c7bb93e','爲谷隠和虞參議韻','楊冠卿','宋','宋诗','song-poetry','','[]','誅茅祗合老僧龕，一笑欣陪麈尾談。',64,'全唐诗/poet.song.160000.json','["誅茅祗合老僧龕，一笑欣陪麈尾談。", "天末冥鴻方避弋，遼東白豕忍懷慚。", "折腰我已宦情薄，嚼蠟誰言世味甘。", "萬事轉頭俱夢幻，試將此語靜中參。"]'),
('86dc9b07-4f03-45e2-87c7-4cb43bf9fc3e','谷隠之東芍藥酴醾涉夏尚有存者籜龍頭角且森列於前次前韻呈九江趙使君','楊冠卿','宋','宋诗','song-poetry','','[]','衣鉢相傳書一龕，晴窗時許聽名談。',64,'全唐诗/poet.song.160000.json','["衣鉢相傳書一龕，晴窗時許聽名談。", "詩成與客探囊取，句好令人下筆慚。", "別墅經春花未老，芳畦過雨薺尤甘。", "明朝更欲從公去，玉版堂頭作小參。"]'),
('7ac062f6-225a-4b0d-81b2-cb17013b136f','歸自淮右讀楚辭有感','楊冠卿','宋','宋诗','song-poetry','','[]','憶昔淮山戰骨高，行人持節過臨洮。',64,'全唐诗/poet.song.160000.json','["憶昔淮山戰骨高，行人持節過臨洮。", "匣中劍氣徒干斗，袖裏綸鈎莫釣鼇。", "世事從來兩蝸角，男兒不遇一鴻毛。", "功名槐國吾深省，痛飲何妨讀楚騷。"]'),
('42ad9a13-b656-4f7a-8760-7d97815721a5','頃歲如番禺與慶傳十六兄遇上饒後五年胥會於霅時太學增置生試竟不遂志將別去理朱方棹因詠昔人風雨對床之語慨然有感作是詩','楊冠卿','宋','宋诗','song-poetry','','[]','囊空未辦買山錢，壯志隨人祗自憐。',64,'全唐诗/poet.song.160000.json','["囊空未辦買山錢，壯志隨人祗自憐。", "千里鄉關愁夢裏，幾年蹤跡瘴江邊。", "回谿重困南摶翼，異縣還尋東去船。", "何日蒼崖結茅屋，與君風雨對床眠。"]'),
('beb6de54-3b0f-450e-8c8e-8c019c3667a3','繼詩社諸友韻','楊冠卿','宋','宋诗','song-poetry','','[]','休將龜筴問窮通，往事邯鄲午枕中。',64,'全唐诗/poet.song.160000.json','["休將龜筴問窮通，往事邯鄲午枕中。", "南郭吹竽羞濫食，北山運畚笑愚公。", "酒邊頼有賡酬在，客裏還欣臭味同。", "得句不妨頻寄我，從今莫效馬牛風。"]'),
('b42dfd2d-b41b-4b64-9c6d-7629c685561c','復用前韻且約携琴尋花下之盟','楊冠卿','宋','宋诗','song-poetry','','[]','吟牋寫就訊難通，人在千巖紫翠中。',64,'全唐诗/poet.song.160000.json','["吟牋寫就訊難通，人在千巖紫翠中。", "談笑尊罍有餘樂，交遊氣槩壓羣公。", "忘年許締金蘭好，佳處何妨杖履同。", "我欲携琴坐花底，乞君妙曲奏松風。"]'),
('bd191614-98d6-4a71-894e-a62aa28b2643','淮楚春晚病中','楊冠卿','宋','宋诗','song-poetry','','[]','絕塞驅馳有底忙，病餘歸思遶江鄉。',64,'全唐诗/poet.song.160000.json','["絕塞驅馳有底忙，病餘歸思遶江鄉。", "鴈飛不到楚天遠，蝶夢可堪春晝長。", "滿地香紅初過雨，一簾風絮正斜陽。", "愁邊頼有新詩在，强劈吟牋付錦囊。"]'),
('c86ef046-83a4-428b-bb9b-b023f13828bc','遊交廣用帳幹趙德縱韻','楊冠卿','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','家聲久矣愧長楊，浪說男兒志四方。',64,'全唐诗/poet.song.160000.json','["家聲久矣愧長楊，浪說男兒志四方。", "鼎鼎百年半流落，悠悠萬里益凄凉。", "羈懷嶺表芙蓉幕，歸夢江南雲水鄉。", "欲訪匡廬近消息，試憑征雁到潯陽。"]'),
('62e31be2-a99e-405d-85cd-df54d555ae50','琴久不作客問其故戲爲說偈','楊冠卿','宋','宋诗','song-poetry','','[]','昭琴不鼓任虧成，澤畔行吟且獨醒。',64,'全唐诗/poet.song.160000.json','["昭琴不鼓任虧成，澤畔行吟且獨醒。", "自信榮枯本同轍，誰云得喪有殊形。", "古今幾見桑田變，日月常循晝夜經。", "去去來來祇如此，風前別調不須聽。"]'),
('7c80485c-04b1-47bb-bc8e-dc07de805ab2','代秦幹上刑部張尚書  其一','楊冠卿','宋','宋诗','song-poetry','','[]','疇昔持衡冰鑑清，議刑今去刻爲明。',64,'全唐诗/poet.song.160000.json','["疇昔持衡冰鑑清，議刑今去刻爲明。", "坐令几閣文書靜，馴致齋居獄訟平。", "疏闊漢朝新禁網，風流廷尉舊家聲。", "哀窮悼屈心如砥，應笑張湯有重輕。"]'),
('6e46debf-5968-452a-9cff-545d4079b037','代秦幹上刑部張尚書  其二','楊冠卿','宋','宋诗','song-poetry','','[]','平生報國劍鋩寒，萬里漂流困一簞。',64,'全唐诗/poet.song.160000.json','["平生報國劍鋩寒，萬里漂流困一簞。", "貧劇方思毛義檄，歸來却戴楚囚冠。", "解驂舊事無人繼，慟哭窮塗祗自嘆。", "倚伏循環知有待，春回寒谷在毫端。"]'),
('c59f4599-64ae-4669-b4c0-a06fcb8c9b41','繼朱叔謙所寄韻','楊冠卿','宋','宋诗','song-poetry','','[]','湖海三十載，窮觀未見書。',48,'全唐诗/poet.song.160000.json','["湖海三十載，窮觀未見書。", "文章恥沿襲，體製薄浮虛。", "老去情懷惡，生平習氣除。", "交親應笑我，術業廢三餘。"]'),
('cf866eb3-6d7c-4b08-8909-674b974385a6','王鷗盟別去久之有詩繼韻','楊冠卿','宋','宋诗','song-poetry','','[]','急槳衝煙去，奚奴喚不譍。',48,'全唐诗/poet.song.160000.json','["急槳衝煙去，奚奴喚不譍。", "清吟繼囊錦，妙句琢壺冰。", "天遠暮雲碧，江寒秋練澄。", "懷人心欲折，愁坐對青燈。"]'),
('e9319edc-bc2e-40cf-b6e2-24e81e615ac0','秋日懷松竹舊友  其一','楊冠卿','宋','宋诗','song-poetry','','[]','松竹隠君子，別來安穩不。',48,'全唐诗/poet.song.160000.json','["松竹隠君子，別來安穩不。", "音書遲寄雁，風雨又驚秋。", "金井葉黄落，青燈人白頭。", "客懷難著語，誰共賦牢愁。"]'),
('657be381-038d-4352-ada0-95a4a1020cc9','秋日懷松竹舊友  其二','楊冠卿','宋','宋诗','song-poetry','','[]','烏免不停軌，蒹葭鬢已蒼。',48,'全唐诗/poet.song.160000.json','["烏免不停軌，蒹葭鬢已蒼。", "囊空携古錦，賦未奏長楊。", "林下松風曲，爐邊栢子香。", "朝昏作禪供，榮辱已俱忘。"]'),
('4b9b97c0-d783-4ff9-a96b-5fa9d9b45d45','倦遊','楊冠卿','宋','宋诗','song-poetry','','[]','歸去陶彭澤，重來丁令威。',48,'全唐诗/poet.song.160000.json','["歸去陶彭澤，重來丁令威。", "逢場真戲劇，閲世識危機。", "蠻雨沾烏帽，京塵黯素衣。", "回頭今自笑，三十六年非。"]'),
('b556f4b3-e92c-4bf5-8e27-1c9ade88c063','水亭晚坐','楊冠卿','宋','宋诗','song-poetry','','[]','煙波渺渺白鷗雙，遠樹微紅襯夕陽。',32,'全唐诗/poet.song.160000.json','["煙波渺渺白鷗雙，遠樹微紅襯夕陽。", "坐久江風起蘋末，馮夷借我一襟凉。"]'),
('cd915f8a-b30f-4402-a89b-25c5477db023','詩僧常不輕以梅花句得名于時雪後踏月相過論詩終夕退得二絕以謝  其一','楊冠卿','宋','宋诗','song-poetry','','[]','十年袖裏梅花句，夢遶江南煙雨村。',32,'全唐诗/poet.song.160000.json','["十年袖裏梅花句，夢遶江南煙雨村。", "今日相看更愁絕，天低雲淡月黄昏。"]'),
('6e4c9102-2287-47b3-ab96-5c03f5274622','詩僧常不輕以梅花句得名于時雪後踏月相過論詩終夕退得二絕以謝  其二','楊冠卿','宋','宋诗','song-poetry','','[]','荒江落日孤鴻影，遠趁幽人踏月來。',32,'全唐诗/poet.song.160000.json','["荒江落日孤鴻影，遠趁幽人踏月來。", "雪屋雲林淡相對，月邊依約有寒梅。"]'),
('c2bb396f-e3a7-45e8-8de1-e8abccd7b65d','題張安國舍人平沙落雁圖','楊冠卿','宋','宋诗','song-poetry','','[]','渚雲低壓雲山暮，煙素橫空落日斜。',32,'全唐诗/poet.song.160000.json','["渚雲低壓雲山暮，煙素橫空落日斜。", "秋老江鄉稻粱熟，一行征雁下平沙。"]'),
('87714ceb-4a77-4509-ba80-040100b90080','九江春半雨中寒甚忽見梨花','楊冠卿','宋','宋诗','song-poetry','','[]','江城一雨春强半，寒色著人芳信遲。',32,'全唐诗/poet.song.160000.json','["江城一雨春强半，寒色著人芳信遲。", "頼有梨花遮病眼，一枝带雨出疎籬。"]'),
('29d624f6-07b9-4dd9-8e8f-6a2eab25a5bb','乙未秋賦不遂志歸寓水村','楊冠卿','宋','宋诗','song-poetry','','[]','歸來不負白鷗盟，要聽雲山韶濩聲。',32,'全唐诗/poet.song.160000.json','["歸來不負白鷗盟，要聽雲山韶濩聲。", "鐘鼎軒裳非我事，從教水到自渠成。"]'),
('c4aadffd-273e-4ea1-a198-a084ce35965d','自仙潭治歸舟呈王鷗盟  其一','楊冠卿','宋','宋诗','song-poetry','','[]','江頭重整舊漁衣，觸起眠沙鷗鷺機。',32,'全唐诗/poet.song.160000.json','["江頭重整舊漁衣，觸起眠沙鷗鷺機。", "煙渚蘆花留不住，葉舟還趁夕陽歸。"]'),
('dc29ab3b-2306-4190-8ccd-764874e316d0','自仙潭治歸舟呈王鷗盟  其二','楊冠卿','宋','宋诗','song-poetry','','[]','絕嶂雲煙乍有無，蒼崖茅屋近何如。',32,'全唐诗/poet.song.160000.json','["絕嶂雲煙乍有無，蒼崖茅屋近何如。", "西風拍手喚征雁，恐有平安錦字書。"]'),
('7f2e42c1-71b5-4a1a-8da5-875326eac4f8','自仙潭治歸舟呈王鷗盟  其三','楊冠卿','宋','宋诗','song-poetry','','[]','扁舟夜泊蓼花叢，曉掛風帆苕水東。',32,'全唐诗/poet.song.160000.json','["扁舟夜泊蓼花叢，曉掛風帆苕水東。", "擬辦蓋頭茅一把，十年湖海浪飄蓬。"]'),
('5d9c464f-286a-4f8d-8332-1a5b392c3c9e','自仙潭治歸舟呈王鷗盟  其四','楊冠卿','宋','宋诗','song-poetry','','[]','江村煙雨暗霏微，正是鷗盟得句時。',32,'全唐诗/poet.song.160000.json','["江村煙雨暗霏微，正是鷗盟得句時。", "雨後屏山展新綠，更煩摹寫送新詩。"]'),
('a3d29735-8597-4965-a494-b89d2b77f0a8','次韻王鷗盟秋日郊居即事  其一','楊冠卿','宋','宋诗','song-poetry','','[]','老去柴桑晝掩關，悠然得意在南山。',32,'全唐诗/poet.song.160000.json','["老去柴桑晝掩關，悠然得意在南山。", "忘言妙處無人解，目送孤鴻天際還。"]'),
('9db25701-37b8-4679-a41d-4e72dc6f5261','次韻王鷗盟秋日郊居即事  其二','楊冠卿','宋','宋诗','song-poetry','','[]','不貪薏苡與明珠，曳屣狂歌信杖扶。',32,'全唐诗/poet.song.160000.json','["不貪薏苡與明珠，曳屣狂歌信杖扶。", "誰道先生貧徹骨，先生清處若冰壺。"]'),
('bc6180a8-d615-4a75-b728-fbf4ac4451f5','次韻王鷗盟秋日郊居即事  其三','楊冠卿','宋','宋诗','song-poetry','','[]','松菊依然遶舊廬，西風歸興動鱸魚。',32,'全唐诗/poet.song.160000.json','["松菊依然遶舊廬，西風歸興動鱸魚。", "歸來有酒輒成醉，旋摘秋園雨後蔬。"]'),
('c0291284-1a16-400c-a056-f487281b5bc5','次李提舉桂花韻  其一','楊冠卿','宋','宋诗','song-poetry','','[]','綠帷深護黄金粟，嫵媚似嫌紅粉粧。',32,'全唐诗/poet.song.160000.json','["綠帷深護黄金粟，嫵媚似嫌紅粉粧。", "年來不作廣寒夢，喜對孤標時踞床。"]'),
('444e0c9d-446f-49ff-b4b8-27c186e421d2','次李提舉桂花韻  其二','楊冠卿','宋','宋诗','song-poetry','','[]','人間初未識奇木，子落蟾宮秋政芳。',32,'全唐诗/poet.song.160000.json','["人間初未識奇木，子落蟾宮秋政芳。", "託根底事在幽谷，要伴清都山水郎。"]'),
('62d9b2a9-c3cd-4db6-8fcd-a7d82cd314a5','春雨未霽有載歌姬遊道場山者','楊冠卿','宋','宋诗','song-poetry','','[]','濛濛煙雨暗空山，驕馬行春翠袖寒。',32,'全唐诗/poet.song.160000.json','["濛濛煙雨暗空山，驕馬行春翠袖寒。", "待得春風捲雲幕，却愁春色又闌珊。"]'),
('ea2846c6-f762-4553-b423-94b2cb1828eb','塞上與鄭將夜飲  其一','楊冠卿','宋','宋诗','song-poetry','','[]','白髮將軍夜枕戈，樓蘭未斬奈愁何。',32,'全唐诗/poet.song.160000.json','["白髮將軍夜枕戈，樓蘭未斬奈愁何。", "挑燈看劍怳如洗，那聽蕭蕭易水歌。"]'),
('f0a9b7fa-9539-48a6-a14d-133212dbe6cb','塞上與鄭將夜飲  其二','楊冠卿','宋','宋诗','song-poetry','','[]','幾年京洛暗胡塵，老上龍庭恨未焚。',32,'全唐诗/poet.song.160000.json','["幾年京洛暗胡塵，老上龍庭恨未焚。", "安得君王倚天劍，提携直上决浮雲。"]'),
('d7e5c2b4-5acc-4361-9e7d-081765a2d05d','次韻李提舉秋日雜詠','楊冠卿','宋','宋诗','song-poetry','','[]','羊坂路岐險，燕巢生計疎。',48,'全唐诗/poet.song.160000.json','["羊坂路岐險，燕巢生計疎。", "萍蓬三尺劍，衣鉢一床書。", "葉露泣金井，簷牙掛玉鈎。", "魂清了無寐，詩思不禁秋。"]'),
('01a84009-1716-45e9-a4e0-9e0c7ececf07','次歸耕堂稀字韻  其一','楊冠卿','宋','宋诗','song-poetry','','[]','精忠貫日古來稀，帷幄從容扈六飛。',32,'全唐诗/poet.song.160000.json','["精忠貫日古來稀，帷幄從容扈六飛。", "風虎雲龍方際會，故鄉未許我公歸。"]'),
('56e9d5b6-5f7d-48e1-9553-b6022dac55fb','次歸耕堂稀字韻  其二','楊冠卿','宋','宋诗','song-poetry','','[]','神京千里雁書稀，關塞傳聞驛騎飛。',32,'全唐诗/poet.song.160000.json','["神京千里雁書稀，關塞傳聞驛騎飛。", "報道天驕遁沙漠，衮衣行從翠華歸。"]'),
('07148d91-bb5a-44fd-a1a0-138f5e24c823','次歸耕堂稀字韻  其三','楊冠卿','宋','宋诗','song-poetry','','[]','功業汾陽千載稀，龍庭單騎去如飛。',32,'全唐诗/poet.song.160000.json','["功業汾陽千載稀，龍庭單騎去如飛。", "笑談整頓乾坤了，黄鉞金鉦奏凱歸。"]'),
('ec856f8e-1e81-47de-bb88-581b52686fa9','次歸耕堂稀字韻  其四','楊冠卿','宋','宋诗','song-poetry','','[]','湖山春老杏花稀，柳絮漫空作雪飛。',32,'全唐诗/poet.song.160000.json','["湖山春老杏花稀，柳絮漫空作雪飛。", "橫槊賦詩有餘暇，不妨倒載送春歸。"]'),
('ef681658-9f88-4529-a19e-8f66f81059f5','又用韻  其一','楊冠卿','宋','宋诗','song-poetry','','[]','弱水蓬山到者稀，凌空須仗羽輪飛。',32,'全唐诗/poet.song.160000.json','["弱水蓬山到者稀，凌空須仗羽輪飛。", "羣仙拍手山頭笑，笑我漂零胡不歸。"]'),
('b333148e-fc46-4a59-9850-531cf06044d1','又用韻  其二','楊冠卿','宋','宋诗','song-poetry','','[]','窮巷無人車轍稀，尋巢燕子故飛飛。',32,'全唐诗/poet.song.160000.json','["窮巷無人車轍稀，尋巢燕子故飛飛。", "似嫌茅屋太低小，廣厦千間欣有歸。"]'),
('cee3947f-2746-43f1-92bb-b44c771d62af','又用韻  其三','楊冠卿','宋','宋诗','song-poetry','','[]','杏壇鏗爾瑟聲稀，劍佩三千羽蓋飛。',32,'全唐诗/poet.song.160000.json','["杏壇鏗爾瑟聲稀，劍佩三千羽蓋飛。", "獨對春風吟詠處，從今願學舞雩歸。"]'),
('5f4ea1a1-2aa1-40b0-9dda-b1f18a55dc1a','乙巳春次中隠先生韻  其一','楊冠卿','宋','宋诗','song-poetry','','[]','密勿籌帷今幾春，故山猿鶴尚關情。',32,'全唐诗/poet.song.160000.json','["密勿籌帷今幾春，故山猿鶴尚關情。", "中書歷徧令公考，樂道要從莘野耕。"]'),
('ac6d8a40-adff-421b-8929-9803645b2a02','乙巳春次中隠先生韻  其二','楊冠卿','宋','宋诗','song-poetry','','[]','種滿人間桃李春，門闌舊物詎忘情。',32,'全唐诗/poet.song.160000.json','["種滿人間桃李春，門闌舊物詎忘情。", "江湖若也有閑地，著我一犁春雨耕。"]'),
('1aa14728-0967-42e8-ab16-09a4cf80dc5a','挽葉南仲','楊冠卿','宋','宋诗','song-poetry','','[]','疇昔丈人行，典型詩禮家。',48,'全唐诗/poet.song.160000.json','["疇昔丈人行，典型詩禮家。", "剛方排武叔，詞賦敵張華。", "造膝陳經濟，凝旒屢嘆嘉。", "他年想遺烈，拊髀諒興嗟。"]'),
('54ab167e-2999-4b07-af76-6693240d493b','次韻王宣幹秋懷','楊冠卿','宋','宋诗','song-poetry','','[]','囊錐脫穎久崢嶸，劍氣干霄恨莫平。',64,'全唐诗/poet.song.160000.json','["囊錐脫穎久崢嶸，劍氣干霄恨莫平。", "江左方思見王導，兒曹誰敢吏淵明。", "悲秋欲賦情難極，憂國忘言酒細傾。", "高卧東山歲將晚，何如一起爲蒼生。"]'),
('fa2b22d4-b15c-4d11-a9ed-717bb424a60c','送堵修遠歸湖城  其一','楊冠卿','宋','宋诗','song-poetry','','[]','十載讀書松竹林，壺觴歌詠有知音。',32,'全唐诗/poet.song.160000.json','["十載讀書松竹林，壺觴歌詠有知音。", "君今別我市朝去，誰伴寒窗擁鼻吟。"]'),
('f1db6740-4172-4d64-8785-44a196f47338','送堵修遠歸湖城  其二','楊冠卿','宋','宋诗','song-poetry','','[]','雲卧江村煙樹林，懸知出岫本無心。',32,'全唐诗/poet.song.160000.json','["雲卧江村煙樹林，懸知出岫本無心。", "亭臯若也有歸雁，得句不妨頻寄音。"]'),
('2f6ce655-3acb-4497-8b29-712248e7e245','西樓','楊冠卿','宋','宋诗','song-poetry','','[]','平頭四十悞儒冠，獨立西樓憂萬端。',32,'全唐诗/poet.song.160000.json','["平頭四十悞儒冠，獨立西樓憂萬端。", "兩鬢飄蕭半華髮，羞將勳業鏡頻看。"]'),
('d293e323-9676-44f1-a97d-5da85e2a01ea','次韻葉無咎梔子花','楊冠卿','宋','宋诗','song-poetry','','[]','樓石山前薝蔔花，品題從昔屬詩家。',32,'全唐诗/poet.song.160000.json','["樓石山前薝蔔花，品題從昔屬詩家。", "君看五字齊梁句，句好當令屈宋衙。"]'),
('324a6b49-3b77-4094-8acc-6dd10a3b898f','從郭中隠覓酒併呈張君量','楊冠卿','宋','宋诗','song-poetry','','[]','百斛龍文鼎可扛，揮毫曾寄碧油幢。',32,'全唐诗/poet.song.160000.json','["百斛龍文鼎可扛，揮毫曾寄碧油幢。", "酒兵若有三千騎，肯向詩壇築受降。"]'),
('e0c0fcf6-93f3-4ad3-beb1-8b09fbd62811','又示同志','楊冠卿','宋','宋诗','song-poetry','','[]','寂寂寥寥揚子居，雲山相對一床書。',32,'全唐诗/poet.song.160000.json','["寂寂寥寥揚子居，雲山相對一床書。", "無人載酒問奇字，自把殘編時卷舒。"]'),
('af4cdc82-fdb8-4590-893e-a8d1391e0535','歸途用李泉野韻','楊冠卿','宋','宋诗','song-poetry','','[]','乾坤萬古幾昏曉，兔走烏飛不暫停。',32,'全唐诗/poet.song.160000.json','["乾坤萬古幾昏曉，兔走烏飛不暫停。", "去日荻花秋索索，歸時芳草又青青。"]'),
('12bd6e3a-779d-4ca3-a975-4674908fa3d5','癸丑生朝舟行有感','楊冠卿','宋','宋诗','song-poetry','','[]','懸弧初度日，鞠育念劬勞。',48,'全唐诗/poet.song.160000.json','["懸弧初度日，鞠育念劬勞。", "未了詩書債，見輕兒女曹。", "爭知兩蝸角，等是一鴻毛。", "所貴盡忠孝，結交英與豪。"]'),
('e36043b4-e12e-45a3-a5f1-fff6b0c9007c','題畫扇','楊冠卿','宋','宋诗','song-poetry','','[]','斷橋流水小舟橫，卧看林梢素月明。',32,'全唐诗/poet.song.160000.json','["斷橋流水小舟橫，卧看林梢素月明。", "雙鶴不知何事舞，風前時送九臯聲。"]'),
('1b89aaae-d276-4be7-aab6-09eeeaa1be0e','與金陵傅漕余預鄉薦時傅兄持文衡  其一','楊冠卿','宋','宋诗','song-poetry','','[]','著作承明近玉堂，云何持節尚爲郎。',64,'全唐诗/poet.song.160000.json','["著作承明近玉堂，云何持節尚爲郎。", "運儲巧思蜀諸葛，攬轡澄清漢范滂。", "自昔謀猷資啟沃，於今軍國欠平章。", "商巖事業公須繼，好趁春風朝未央。"]'),
('c4d34b26-a6af-40ae-8917-8727ef1e2550','與金陵傅漕余預鄉薦時傅兄持文衡  其二','楊冠卿','宋','宋诗','song-poetry','','[]','鄉書憶昔獻賢能，姓字曾叨天府登。',64,'全唐诗/poet.song.160000.json','["鄉書憶昔獻賢能，姓字曾叨天府登。", "闕里摳衣欣附鳳，雲程歛翼愧飛鵬。", "流年自信一彈指，末路誰憐三折肱。", "若見金昆問消息，爲言霜鬢已鬅鬙。"]'),
('02ca8c24-7327-4ad0-9736-4a09aa893cb9','繼韓尚書春日舟行韻  其一','楊冠卿','宋','宋诗','song-poetry','','[]','河水拍堤清且漣，堤聯南陌與東阡。',32,'全唐诗/poet.song.160000.json','["河水拍堤清且漣，堤聯南陌與東阡。", "浮家泛宅苕溪路，老却春光又一年。"]'),
('500b9f07-a151-4416-8481-75daa24f1cf5','繼韓尚書春日舟行韻  其二','楊冠卿','宋','宋诗','song-poetry','','[]','蜀魄思歸晝夜啼，漆園蝴蝶夢魂飛。',32,'全唐诗/poet.song.160000.json','["蜀魄思歸晝夜啼，漆園蝴蝶夢魂飛。", "簞瓢陋巷心如水，惟有顔淵殆庶幾。"]'),
('cb1cd57f-6d8e-493d-ac2f-89a458aa1ac0','與鄂州都統張提刑  其一','楊冠卿','宋','宋诗','song-poetry','','[]','五雲樓閣武昌宮，曾挫曹瞞百萬雄。',64,'全唐诗/poet.song.160000.json','["五雲樓閣武昌宮，曾挫曹瞞百萬雄。", "今古興亡付流水，江山彈壓頼元戎。", "折衝尊俎笑談裏，極目關河指顧中。", "準擬明年會京洛，爲君沽酒醉春風。"]'),
('85202155-238f-4525-bf3a-02194f12a411','與鄂州都統張提刑  其二','楊冠卿','宋','宋诗','song-poetry','','[]','貔虎雲屯細柳營，旌旗號令轉精明。',64,'全唐诗/poet.song.160000.json','["貔虎雲屯細柳營，旌旗號令轉精明。", "人言郤縠詩書帥，自有孫卿仁義兵。", "關塞金湯今奠枕，江淮草木舊知名。", "家聲凜凜漢人傑，看取籌帷功業成。"]'),
('389e74b4-4c22-4013-9908-e01c47256cfe','與鄂州都統張提刑  其三','楊冠卿','宋','宋诗','song-poetry','','[]','江湖疇昔受恩深，歲晚漂流傷客心。',64,'全唐诗/poet.song.160000.json','["江湖疇昔受恩深，歲晚漂流傷客心。", "雨檝風帆倦行役，雪車冰柱少知音。", "價高肯羨連城璧，才謭難希諛墓金。", "但得扁舟從此去，成虧寧復問昭琴。"]'),
('1dd906a9-12c4-4440-a465-dbf69f8b712e','和京尚書上元日同禁從遊鳳山韻','楊冠卿','宋','宋诗','song-poetry','','[]','苔封石磴遶層欄，欄外行厨薦玉盤。',64,'全唐诗/poet.song.160000.json','["苔封石磴遶層欄，欄外行厨薦玉盤。", "座揖湖山詩興遠，氣吞雲海酒杯寬。", "籃輿竟日有餘樂，蓮市只今無此歡。", "我愧么微難接武，飛牋亦欲寄青翰。"]'),
('9e594358-7ece-4ef0-9bfe-ea29ff69bd33','洪溪口','楊冠卿','宋','宋诗','song-poetry','','[]','短短桃華宿雨餘，風輕春水縠紋鋪。',32,'全唐诗/poet.song.160000.json','["短短桃華宿雨餘，風輕春水縠紋鋪。", "柁師苦要貪行色，不肯繫船尋酒酤。"]'),
('4575597f-cbd5-4767-8e51-7ae4b1c6eff6','蠟梅四絕  其一','楊冠卿','宋','宋诗','song-poetry','','[]','遊蜂辛苦事芳菲，嚼蕊偷香釀蜜脾。',32,'全唐诗/poet.song.160000.json','["遊蜂辛苦事芳菲，嚼蕊偷香釀蜜脾。", "還被東風巧收拾，又隨春色上南枝。"]'),
('1596a1ef-ffd3-4b34-9fda-bc52bb002a3a','蠟梅四絕  其二','楊冠卿','宋','宋诗','song-poetry','','["\u897f\u6e56"]','枝上編鍾萬顆垂，凌寒傲視雪霜姿。',32,'全唐诗/poet.song.160000.json','["枝上編鍾萬顆垂，凌寒傲視雪霜姿。", "從今疎影暗香句，不數西湖處士詩。"]'),
('afb46dde-e343-477a-8edb-29ce29ca884b','蠟梅四絕  其三','楊冠卿','宋','宋诗','song-poetry','','[]','塗黄不學漢宮粧，一點檀心萬斛香。',32,'全唐诗/poet.song.160000.json','["塗黄不學漢宮粧，一點檀心萬斛香。", "嚼蠟我今忘世味，羞將花譜細平章。"]'),
('ac8eb043-df01-4d26-9ecb-ac6a42716059','蠟梅四絕  其四','楊冠卿','宋','宋诗','song-poetry','','[]','阿嬌厭貯黄金屋，洗盡鉛華兒女粧。',32,'全唐诗/poet.song.160000.json','["阿嬌厭貯黄金屋，洗盡鉛華兒女粧。", "香魂寒夜伴幽獨，青燈相對吟胡床。"]'),
('4b95f974-a954-4782-aaf2-b423525db358','同韓吳二寺丞飲西湖梅花下酒酣繼韓韻','楊冠卿','宋','宋诗','song-poetry','','["\u897f\u6e56"]','冉冉山雲薄暮時，壺觴歌詠欲忘歸。',32,'全唐诗/poet.song.160000.json','["冉冉山雲薄暮時，壺觴歌詠欲忘歸。", "一盃且爲梅花醉，莫待梅花作雪飛。"]'),
('d645c5b6-3ee3-4505-8245-c131e302d849','港口','楊冠卿','宋','宋诗','song-poetry','','[]','野寺雲山迥，人家煙火稀。',48,'全唐诗/poet.song.160000.json','["野寺雲山迥，人家煙火稀。", "水腥漁市近，帆落晚風微。", "拂樹昏鴉去，迎船白鳥飛。", "吾生樂江海，猶恐與心違。"]'),
('c3341960-98e4-41a8-900f-3c8886bb00b0','古梅','楊冠卿','宋','宋诗','song-poetry','','[]','幽棲地僻經過少，花徑不曾緣客掃。',64,'全唐诗/poet.song.160000.json','["幽棲地僻經過少，花徑不曾緣客掃。", "積雪飛霜此夜寒，不知明月爲誰好。", "公來肯訪浣花老，但話宿昔傷懷抱。", "忽憶兩京梅發時，巡簷索共梅花笑。"]'),
('17575b43-3474-4eca-8caf-340684b83104','美人隔秋水','楊冠卿','宋','宋诗','song-poetry','','[]','美人娟娟隔秋水，寂寞江天雲霧裏。',64,'全唐诗/poet.song.160000.json','["美人娟娟隔秋水，寂寞江天雲霧裏。", "中間消息兩茫然，咫尺應須論萬里。", "多病馬卿無日起，青眼高歌望吾子。", "安得送我置汝傍，攬環結佩相終始。"]'),
('553f346c-6be6-4d22-93c8-bc1157cde462','麻姑之東涉千堆壠至射亭宿黄氏新館','楊冠卿','宋','宋诗','song-poetry','','[]','宴宇新成苦未嘉，忽膺朝委易軍牙。',64,'全唐诗/poet.song.160000.json','["宴宇新成苦未嘉，忽膺朝委易軍牙。", "張侯暫喜留歡客，開檻憑誰種好花。", "北沼不難平釣岸，西峰猶欠入窗紗。", "後賢政敏多餘暇，高會何妨月影斜。"]'),
('04b03616-688b-407b-ae8a-1fd952a7c039','同張帥出郊客有欲別去者作詩留之','楊冠卿','宋','宋诗','song-poetry','','[]','元戎小隊出郊坰，落絮遊絲亦有情。',32,'全唐诗/poet.song.160000.json','["元戎小隊出郊坰，落絮遊絲亦有情。", "縱酒欲謀良夜醉，繫帆何惜片時程。"]'),
('c3b51b63-97cd-4005-bf77-db3c9e956d93','春江極目','楊冠卿','宋','宋诗','song-poetry','','[]','荆揚春冬異風土，江北江南春冬花。',32,'全唐诗/poet.song.160000.json','["荆揚春冬異風土，江北江南春冬花。", "跨馬出郊時極目，應須美酒送生涯。"]'),
('c91e8058-2b9c-494f-8687-f4e9ca7140ec','次楊夢錫雪後古梅正芳韵兼呈李史君','常不輕','宋','宋诗','song-poetry','','[]','郭相謀深古來少，詞翰升堂爲君掃。',64,'全唐诗/poet.song.160000.json','["郭相謀深古來少，詞翰升堂爲君掃。", "憶君誦詩神凜然，相逢苦覺人情好。", "歌詞自作風格老，百壺且試開懷抱。", "皂蓋能忘折野梅，浣花溪裏花饒笑。"]'),
('a6ac40b6-0e9c-47bf-9695-19d780c2223e','句','胡泳','宋','宋诗','song-poetry','','[]','閣下大書三姓字，海南惟見兩翁還。',16,'全唐诗/poet.song.160000.json','["閣下大書三姓字，海南惟見兩翁還。"]'),
('f9d27c60-04c4-4d24-bcb6-ca112ae749f4','長淮晚望','王卿月','宋','宋诗','song-poetry','','[]','目斷長淮渺莽中，孤城突兀倚層空。',64,'全唐诗/poet.song.160000.json','["目斷長淮渺莽中，孤城突兀倚層空。", "寒砧幾許遞秋信，漁笛一聲橫晚風。", "龍吐晴雲嵐氣白，鴉翻落日水天紅。", "扁舟今夜宿何許，赤壁斷磯蘆葦叢。"]'),
('8de7913a-2418-47e0-a5f0-e8048ffc020a','挽呂東萊  其一','趙燁','宋','宋诗','song-poetry','','[]','道統誰傳授，源流易失真。',48,'全唐诗/poet.song.160000.json','["道統誰傳授，源流易失真。", "滔滔皆四海，亹亹獨斯人。", "業履羣經粹，詞華一世新。", "可嗟天不憗，難贖百年身。"]'),
('6571264f-1463-4744-a159-f09ace24be0b','挽呂東萊  其二','趙燁','宋','宋诗','song-poetry','','[]','近接南軒訃，公今事亦休。',48,'全唐诗/poet.song.160000.json','["近接南軒訃，公今事亦休。", "彫零數耆舊，牢落一山丘。", "吾道將窮矣，蒼天可問不。", "雙溪樓下水，應共哭聲流。"]'),
('c8d2a871-b2f3-4ab3-80b9-17d0f973a151','句','劉玶','宋','宋诗','song-poetry','','[]','攀條嚼蕊繞千回，日暮碧雲驚四合。',16,'全唐诗/poet.song.160000.json','["攀條嚼蕊繞千回，日暮碧雲驚四合。"]'),
('f50e5f78-3112-43fb-a2cf-28c1a3179c78','今日','馬登','宋','宋诗','song-poetry','','[]','載記編爲令，今朝是暮春。',48,'全唐诗/poet.song.160000.json','["載記編爲令，今朝是暮春。", "燕飛高雁塞，魚躍過龍門。", "雨大添泥濘，風清減浪痕。", "鳥啼花濕濕，江日未騰輪。"]'),
('96ecf7c1-fdcb-46e4-bd7c-a23246363461','留金館作','京鏜','宋','宋诗','song-poetry','','[]','鼎湖龍馭去無蹤，三遣行人意則同。',64,'全唐诗/poet.song.160000.json','["鼎湖龍馭去無蹤，三遣行人意則同。", "凶禮强更爲吉禮，夷風終未變華風。", "設令耳與笙鏞末，只願身糜鼎鑊中。", "已辦淹留期得請，不辭築館汴江東。"]'),
('d01dfdaf-acd5-4873-86aa-ed86f0ba3e1f','漳河疑塚','京鏜','宋','宋诗','song-poetry','','[]','疑塚多留七十餘，謀身自謂永無虞。',32,'全唐诗/poet.song.160000.json','["疑塚多留七十餘，謀身自謂永無虞。", "不知三馬同槽夢，曾爲兒童遠慮無。"]'),
('5a302b83-615e-45f8-95c7-b511b96c1cd4','句  其一','京鏜','宋','宋诗','song-poetry','','[]','八千里隔東西境，十二時分晝夜泉。',16,'全唐诗/poet.song.160000.json','["八千里隔東西境，十二時分晝夜泉。"]'),
('b5f961e0-02ef-437d-ae1b-d84c614d5dec','句  其二','京鏜','宋','宋诗','song-poetry','','[]','湖邊春色十分深。',8,'全唐诗/poet.song.160000.json','["湖邊春色十分深。"]'),
('2a9db492-b8f2-4f85-a4bd-51a9c1baa331','爲李端愿居士說偈','釋達觀','宋','宋诗','song-poetry','','[]','三十八歲，懵然無知。',40,'全唐诗/poet.song.160000.json','["三十八歲，懵然無知。", "及其有知，何異無知。", "滔滔汴水，隠隠隋堤。", "師其歸矣，箭浪東馳。"]'),
('c60c2bbf-38a1-44ee-a866-c10702744103','頌古五首  其一','釋達觀','宋','宋诗','song-poetry','','[]','長安深夜雪漫漫，欲覓心安轉不安。',32,'全唐诗/poet.song.160000.json','["長安深夜雪漫漫，欲覓心安轉不安。", "縱使言前開活眼，那知已被老胡謾。"]'),
('6243e630-d01a-43a9-b27f-56ab60676a3f','頌古五首  其二','釋達觀','宋','宋诗','song-poetry','','[]','慣弄瑶琴與琵琶，清音歷歷徧天涯。',32,'全唐诗/poet.song.160000.json','["慣弄瑶琴與琵琶，清音歷歷徧天涯。", "堪嗟不入聾人耳，空使西山月又斜。"]'),
('77c447da-da9d-4ff6-8259-24c4f7b258b6','頌古五首  其三','釋達觀','宋','宋诗','song-poetry','','[]','鶴立松梢月，魚行水底天。',24,'全唐诗/poet.song.160000.json','["鶴立松梢月，魚行水底天。", "風光都占斷，不費一文錢。"]'),
('e0777d73-413f-4617-82f2-8988121b1e94','頌古五首  其四','釋達觀','宋','宋诗','song-poetry','','[]','良玉不雕，美言不文。',22,'全唐诗/poet.song.160000.json','["良玉不雕，美言不文。", "烟村三月裏，別是一家春。"]'),
('b2b9a785-5122-4048-a51e-b0fa1fb01e03','頌古五首  其五','釋達觀','宋','宋诗','song-poetry','','[]','村飲夜歸來，健倒三四五。',24,'全唐诗/poet.song.160000.json','["村飲夜歸來，健倒三四五。", "摩挲青莓苔，莫瞋驚著汝。"]'),
('5f96627e-e42e-4e1d-8761-99047d0bd0e6','梅嶺岡','黄度','宋','宋诗','song-poetry','','[]','梅岡丘壟已難尋，堪恨吳兒太忍心。',32,'全唐诗/poet.song.160000.json','["梅岡丘壟已難尋，堪恨吳兒太忍心。", "聞道土山標擘處，原頭叢薄不成陰。"]'),
('40189c8f-5046-4242-a809-4079f8f1396b','玄武湖  其一','黄度','宋','宋诗','song-poetry','','[]','玄武湖中春草生，依稀想見竹籬城。',32,'全唐诗/poet.song.160000.json','["玄武湖中春草生，依稀想見竹籬城。", "後來萬堞如雲起，方恨圖王事不成。"]'),
('67df9799-dead-4231-8c7a-d64a8ee9f5b8','玄武湖  其二','黄度','宋','宋诗','song-poetry','','[]','萬騎連山噪虎熊，千艘激浪泣魚龍。',32,'全唐诗/poet.song.160000.json','["萬騎連山噪虎熊，千艘激浪泣魚龍。", "變遷陵谷有如此，應笑銅駝無定蹤。"]'),
('9c289fce-50f7-4238-8dad-264ace24033c','冶城樓  其一','黄度','宋','宋诗','song-poetry','','[]','果然當國擅功名，著屐閑來上冶城。',32,'全唐诗/poet.song.160000.json','["果然當國擅功名，著屐閑來上冶城。", "久欲乘風還海道，江山佳處尚關情。"]'),
('1475c6ef-061a-4329-bb9b-b6ed331c671d','冶城樓  其二','黄度','宋','宋诗','song-poetry','','[]','春秋將絕書劉子，漢史雖終述武侯。',32,'全唐诗/poet.song.160000.json','["春秋將絕書劉子，漢史雖終述武侯。", "舊國不知遺烈在，我來偶作冶城樓。"]'),
('cfef2394-c1fd-4a0e-9dae-2beb88dba5a1','青溪閣','黄度','宋','宋诗','song-poetry','','[]','江家舊宅枕溪頭，誰向溪灣著小樓。',32,'全唐诗/poet.song.160000.json','["江家舊宅枕溪頭，誰向溪灣著小樓。", "無奈當年亡國恨，潮生潮落幾時休。"]'),
('c654c406-f85d-4014-98c7-d7827aeb6491','白鷺亭','黄度','宋','宋诗','song-poetry','','[]','白鷺亭前白鷺飛，定知公子未忘機。',32,'全唐诗/poet.song.160000.json','["白鷺亭前白鷺飛，定知公子未忘機。", "我來猶識難馴意，江際翩翩趁落暉。"]'),
('c7cb8a4d-6b4a-48eb-ad6e-4757bb880093','鳳凰臺','黄度','宋','宋诗','song-poetry','','[]','江淮表裏拱神州，底事干戈不肯休。',32,'全唐诗/poet.song.160000.json','["江淮表裏拱神州，底事干戈不肯休。", "試上鳳凰臺上望，定山盡處是瓜洲。"]'),
('d3a053f8-1aec-4930-a73a-b59d1394c85e','隆蔭堂','黄度','宋','宋诗','song-poetry','','[]','意得壺觴外，心清杖屨間。',24,'全唐诗/poet.song.160000.json','["意得壺觴外，心清杖屨間。", "簿書休吏早，花鳥向人閑。"]'),
('00f65e15-6e46-439e-ad9f-ef19b1aad1c2','醴泉','章天與','宋','宋诗','song-poetry','','[]','和平德化醴泉通，千古濠梁武舊蹤。',64,'全唐诗/poet.song.160000.json','["和平德化醴泉通，千古濠梁武舊蹤。", "光閃雪花微動月，影浮璚夜凈涵空。", "迢迢脈路流無盡，混混源泉出不窮。", "滿引一瓢更清徹，萬年仁壽祝重瞳。"]'),
('36063563-b49c-4dd7-92b4-f038a9e537c7','句','鄧遠舉','宋','宋诗','song-poetry','','[]','翠雲卧石千巖冷，黄葉呼風萬里秋。',16,'全唐诗/poet.song.160000.json','["翠雲卧石千巖冷，黄葉呼風萬里秋。"]'),
('0d0b8351-f56b-4a04-bab2-20fd392f6a77','山居漫興','吳端','宋','宋诗','song-poetry','','[]','莫笑山莊小，偏於隠者宜。',48,'全唐诗/poet.song.160000.json','["莫笑山莊小，偏於隠者宜。", "門當八字路，園葺五經籬。", "地暖花開早，天寒酒熟遲。", "不須雞報曉，已得數聯詩。"]'),
('65041157-e7d7-40c8-be06-ca8de52f06f9','草堂','吳端','宋','宋诗','song-poetry','','[]','草堂長寂寂，無事且徘徊。',48,'全唐诗/poet.song.160000.json','["草堂長寂寂，無事且徘徊。", "幽鳥啼清嶂，閒雲覆綠苔。", "古琴邀月聽，新酒對花開。", "俗駕何爲者，移文招不來。"]'),
('58e2e4a8-ed4e-4dfc-885b-7a7784d7e604','春懷','吳端','宋','宋诗','song-poetry','','[]','柳陰滿地水平池，門掩青春刻漏遲。',64,'全唐诗/poet.song.160000.json','["柳陰滿地水平池，門掩青春刻漏遲。", "蝶夢任渠分爾汝，蛙聲誰復計公私。", "劉伶混世酒一石，梁叔逃名歌五噫。", "午睡覺來風動竹，自收隔夜著殘棋。"]'),
('2761dd86-874a-4eac-8318-309a6f9085d9','春日山行','吳端','宋','宋诗','song-poetry','','[]','雲峰疊疊路斜斜，隔洞炊烟三兩家。',32,'全唐诗/poet.song.160000.json','["雲峰疊疊路斜斜，隔洞炊烟三兩家。", "何處有香來不斷，嫩風微雨落松花。"]'),
('95d5c51e-93dc-4164-9a2a-12a8cbf8ff21','偈頌五首  其一','釋了悟','宋','宋诗','song-poetry','','[]','今朝七月半，叢林解制忙。',40,'全唐诗/poet.song.160000.json','["今朝七月半，叢林解制忙。", "當頭老水牯，筋骨不堪當。", "大家團欒禮三拜，栴檀薝蔔一般香。"]'),
('b1bb2513-24d5-4266-9d1f-c392c949f050','偈頌五首  其二','釋了悟','宋','宋诗','song-poetry','','[]','今朝開爐向火，諸方說禪浩浩。',28,'全唐诗/poet.song.160000.json','["今朝開爐向火，諸方說禪浩浩。", "靈山一字也無，普請大家證據。"]'),
('495ca9d3-69cd-4178-9517-0683fcc8d649','偈頌五首  其三','釋了悟','宋','宋诗','song-poetry','','[]','一即三，三即一，碧眼胡僧數不出。',43,'全唐诗/poet.song.160000.json','["一即三，三即一，碧眼胡僧數不出。", "少林面壁九年，大似抱贓叫屈。", "屈屈，黄檗樹頭，討甚木蜜。"]'),
('012179d6-e340-483f-b48c-152ba05f88ad','偈頌五首  其四','釋了悟','宋','宋诗','song-poetry','','[]','倒嶽傾湫與麽來，小根魔子謾疑猜。',32,'全唐诗/poet.song.160000.json','["倒嶽傾湫與麽來，小根魔子謾疑猜。", "神駒一躍三千界，空說門前下馬臺。"]'),
('0d0fe6d7-c7ca-44fa-b3e4-7ad558db6285','偈頌五首  其五','釋了悟','宋','宋诗','song-poetry','','[]','昨日栽茄子，今日種冬瓜。',24,'全唐诗/poet.song.160000.json','["昨日栽茄子，今日種冬瓜。", "一聲河滿子，和月落誰家。"]'),
('f812d5a6-9fcc-4597-9df3-08e284b07501','讀政黄牛','釋了悟','宋','宋诗','song-poetry','','[]','清曠情懷世莫羈，放心異類樂斯時。',32,'全唐诗/poet.song.160000.json','["清曠情懷世莫羈，放心異類樂斯時。", "千山萬水無窮意，只許灘頭白鷺知。"]'),
('f13efdea-8751-4e3d-a6ca-36ba906a4a5a','頌古','釋了悟','宋','宋诗','song-poetry','','[]','試問鐘聲披七條，輕輕擊著無明發。',32,'全唐诗/poet.song.160000.json','["試問鐘聲披七條，輕輕擊著無明發。", "買來餬餠是饅頭，苦哉觀世音菩薩。"]'),
('d1dbecf3-0339-4fb8-897e-ff9eae811de9','偈頌二十二首  其一','釋道生','宋','宋诗','song-poetry','','[]','佛法二字，人人知有。',36,'全唐诗/poet.song.160000.json','["佛法二字，人人知有。", "狼毒砒霜，那容下口。", "直饒透出威音前，也是癡狂外邊走。"]'),
('efaee763-0d84-4bfb-b614-af9ca7df20ed','偈頌二十二首  其二','釋道生','宋','宋诗','song-poetry','','["\u897f\u6e56"]','今朝八月十五，天色半陰半雨。',54,'全唐诗/poet.song.160000.json','["今朝八月十五，天色半陰半雨。", "幾多門外遊人，不覩月圓當戶。", "也好笑，又堪嗟。", "爭似西湖寺裏一隊古佛，參退歸堂喫茶。"]'),
('07dc0774-1380-4c6e-a0b4-77c75b897c1c','偈頌二十二首  其三','釋道生','宋','宋诗','song-poetry','','[]','飛金烏，走玉兔，閏月十日又過去。',32,'全唐诗/poet.song.160000.json','["飛金烏，走玉兔，閏月十日又過去。", "無位真人不可尋，一夜霜風打門戶。"]'),
('f9a0cdf3-6b56-4e60-800a-7bf1dbf79b9b','偈頌二十二首  其四','釋道生','宋','宋诗','song-poetry','','[]','一九與二九，相逢不出手。',24,'全唐诗/poet.song.160000.json','["一九與二九，相逢不出手。", "巍巍不動尊，脚不離地走。"]'),
('59658b9b-24bf-40b4-8e57-87cd646dca17','偈頌二十二首  其五','釋道生','宋','宋诗','song-poetry','','[]','披毛带角入廛來，跳出馿胎墮馬胎。',32,'全唐诗/poet.song.160000.json','["披毛带角入廛來，跳出馿胎墮馬胎。", "佛手明明遮不得，從教平地起風雷。"]'),
('8de11e1a-e6e3-4427-aa05-21dea78d6441','偈頌二十二首  其六','釋道生','宋','宋诗','song-poetry','','[]','古帆高挂入曹源，雷動風行海嶽昏。',32,'全唐诗/poet.song.160000.json','["古帆高挂入曹源，雷動風行海嶽昏。", "三十二峰親坐斷，一毛頭上定乾坤。"]'),
('f6768d52-5c0d-4306-8362-7caa11ac10cd','偈頌二十二首  其七','釋道生','宋','宋诗','song-poetry','','[]','始見臘月初，立春又四日。',36,'全唐诗/poet.song.160000.json','["始見臘月初，立春又四日。", "白日走波波，肚裏黑似漆。", "擂鼓上堂來，一字說不出。"]'),
('70d92520-10c5-4bcd-9abf-82496eab71ed','偈頌二十二首  其八','釋道生','宋','宋诗','song-poetry','','[]','三月既望，惠風和暢。',38,'全唐诗/poet.song.160000.json','["三月既望，惠風和暢。", "龜峰擂鼓陞堂，雲集五湖龍象。", "人人鼻孔遼天，好箇西來榜樣。"]'),
('d8b0be9e-c274-49ef-a8ce-8adf8f4fd6b6','偈頌二十二首  其九','釋道生','宋','宋诗','song-poetry','','[]','時節循環四月一，大道何曾有得失。',46,'全唐诗/poet.song.160000.json','["時節循環四月一，大道何曾有得失。", "夜來針眼魚兒，吞却新昌石佛。", "阿呵呵，識不識，明眼衲僧跳不出。"]'),
('6356ecf1-4712-4d92-9905-3690dc347292','偈頌二十二首  其一○','釋道生','宋','宋诗','song-poetry','','[]','阿剌剌，快雨快晴天漸熱，看取而今甚時節。',36,'全唐诗/poet.song.160000.json','["阿剌剌，快雨快晴天漸熱，看取而今甚時節。", "了即萬法本來空，未了吾今爲君決。"]'),
('30e0926c-eaf5-4c68-ab61-1a7503eca242','偈頌二十二首  其一一','釋道生','宋','宋诗','song-poetry','','[]','聽著則聾，覷著則瞎。',26,'全唐诗/poet.song.160000.json','["聽著則聾，覷著則瞎。", "靠倒達磨老臊胡，打殺臨濟白拈賊。"]'),
('a96fc6df-08d2-45c6-a7b1-225c78ccf027','偈頌二十二首  其一二','釋道生','宋','宋诗','song-poetry','','[]','衲僧門下，三月一結。',44,'全唐诗/poet.song.160000.json','["衲僧門下，三月一結。", "把斷要津，聖凡路絕。", "一夜簷頭雨滴聲，剛把真機俱漏泄，切忌守著繫馿橛。"]'),
('851f224e-6565-4be3-9b0e-078650ed15c0','偈頌二十二首  其一三','釋道生','宋','宋诗','song-poetry','','[]','龜峰一訣，千聖罔測。',30,'全唐诗/poet.song.160000.json','["龜峰一訣，千聖罔測。", "硬似泥團，爛如生鐵。", "是何之訣，有口無舌。"]'),
('1cf96799-ce12-4e68-8873-1d2b50010c54','偈頌二十二首  其一四','釋道生','宋','宋诗','song-poetry','','[]','南邊是黑雲，今日應有雨。',48,'全唐诗/poet.song.160000.json','["南邊是黑雲，今日應有雨。", "宜麻宜豆，宜禾宜黍。", "雖然歲稔年豐，粒粒幾多辛苦。", "爲報參玄人，要須知落處。"]'),
('91cb324a-acc4-44cc-b56d-2612bf0f4038','偈頌二十二首  其一五','釋道生','宋','宋诗','song-poetry','','[]','浮雲散盡月當空，兔子懷胎産大蟲。',32,'全唐诗/poet.song.160000.json','["浮雲散盡月當空，兔子懷胎産大蟲。", "跳出風前弄牙爪，至今撼動廣寒宮。"]'),
('9cbdf3cc-b95e-4167-9545-6d9523175d82','偈頌二十二首  其一六','釋道生','宋','宋诗','song-poetry','','[]','兩曜劈箭急，一年彈指間。',42,'全唐诗/poet.song.160000.json','["兩曜劈箭急，一年彈指間。", "始見大暑小暑，又是小寒大寒。", "通身寒暑無回互，笑倒當年老洞山。"]'),
('6fc1dbba-174b-4478-b1ae-87ec2752755b','偈頌二十二首  其一七','釋道生','宋','宋诗','song-poetry','','[]','雨雪落紛紛，簷頭水滴滴。',40,'全唐诗/poet.song.160000.json','["雨雪落紛紛，簷頭水滴滴。", "良哉觀世音，草裏跳不出。", "跳不出，也大屈，水裏烏龜鑽鐵壁。"]'),
('24b61c93-ea6e-4d85-b1be-6dc1f44f29bc','偈頌二十二首  其一八','釋道生','宋','宋诗','song-poetry','','[]','月生一，拶倒銀山并鐵壁。',50,'全唐诗/poet.song.160000.json','["月生一，拶倒銀山并鐵壁。", "月生二，土宿騎牛穿閙市。", "月生三，屋頭幽鳥語喃喃。", "不是葛藤露布，亦非入理深談。"]'),
('d9073dbe-c3fa-4f77-ad57-349918358d97','偈頌二十二首  其一九','釋道生','宋','宋诗','song-poetry','','[]','平旦清晨三月朝，南山蒼翠插雲霄。',32,'全唐诗/poet.song.160000.json','["平旦清晨三月朝，南山蒼翠插雲霄。", "不須更覓西來意，窗外數聲婆餠焦。"]'),
('a3077450-6d7e-47ad-9249-c41485644f98','偈頌二十二首  其二○','釋道生','宋','宋诗','song-poetry','','[]','我佛生辰四月八，地涌金蓮隨步發。',208,'全唐诗/poet.song.160000.json','["我佛生辰四月八，地涌金蓮隨步發。", "天上天下獨稱尊，微妙真機俱漏泄。", "雪山成道度衆生，四十九年無剩說。", "滔滔苦海架舟航，杳杳昏衢懸日月。", "文仲宣義濟陽公，曾向靈山蒙起莂。", "示現人間長者身，日用機輪活鱍鱍。", "一壽二富三康寧，總是前生修種得。", "今生福上更增修，果報來生愈超越。", "六門晝夜放毫光，萬罪紅爐飛片雪。", "安然端坐白牛車，金鎖玄關盡透脫。", "殊勝功德利無邊，宜爾子孫皆顯達。", "自知作佛更無疑，何必當來問彌勒。", "龜峰末後爲全提，鐵卵生兒樹上飛。"]'),
('d6e47da8-223c-4051-a59e-0dd2e2bc96cf','偈頌二十二首  其二一','釋道生','宋','宋诗','song-poetry','','[]','明星覷著眼睛枯，絕後何曾得再蘇。',32,'全唐诗/poet.song.160000.json','["明星覷著眼睛枯，絕後何曾得再蘇。", "堪笑堪悲緣底事，一年一度被茶糊。"]'),
('597ee269-a66d-4fc9-b609-9fe956d51c54','偈頌二十二首  其二二','釋道生','宋','宋诗','song-poetry','','[]','弋陽溪上諸檀越，勇猛精進難比況。',192,'全唐诗/poet.song.160000.json','["弋陽溪上諸檀越，勇猛精進難比況。", "年年歲歲入山來，總是如來親眷屬。", "如來法身等虛空，隨彼願心而顯發。", "譬如月輪出霄漢，照耀一切衆生前。", "衆生性水無有邊，我此一月能普現。", "水靜而清現全體，月非取水而遽來。", "水動而濁無定光，月非捨水而遽去。", "水有清濁有動靜，月無取捨無去來。", "於無取捨去來中，不見清濁動靜相。", "既無清濁動靜相，一一含攝無有餘。", "我心佛心衆生心，心佛衆生本平等。", "佛子當作如是觀，即獲世間諸利益。"]'),
('11d3c1a7-f061-4fc0-b2cf-89eefe375546','偈頌二十二首  其二三','釋道生','宋','宋诗','song-poetry','','[]','年盡不燒錢，鼠穴被蛇穿。',24,'全唐诗/poet.song.160000.json','["年盡不燒錢，鼠穴被蛇穿。", "直饒玄會得，對面隔西天。"]'),
('e4f3b879-9c67-4df0-8d4a-fc443edd8d0b','讚密庵禪師','釋道生','宋','宋诗','song-poetry','','[]','狼毒肝腸，生鐵面具。',46,'全唐诗/poet.song.160000.json','["狼毒肝腸，生鐵面具。", "滿口鄉談，唱喏破句。", "滅臨濟正宗，起東山門戶。", "恁麽出世爲人，未免秤鎚蘸醋。"]'),
('ff8a2591-83d3-4fd9-8769-72bdf23fb543','題廬山楞伽院','釋道生','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','蘇內翰木三五筆，李夫人竹一二竿。',32,'全唐诗/poet.song.160000.json','["蘇內翰木三五筆，李夫人竹一二竿。", "會得楞伽印心法，不應來作畫圖看。"]'),
('4e540022-5158-4128-b7cb-125ec48bfd56','題廬山圓通','釋道生','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','水聲山色裏，猿嘯月明天。',24,'全唐诗/poet.song.160000.json','["水聲山色裏，猿嘯月明天。", "喚作圓通境，更參三十年。"]'),
('2a49fe96-892a-4cc8-8eab-601a90d20085','題烈山','釋道生','宋','宋诗','song-poetry','','[]','舟船來往此登臨，酹酒燒錢慮轉深。',32,'全唐诗/poet.song.160000.json','["舟船來往此登臨，酹酒燒錢慮轉深。", "大抵人心自巇嶮，心空山嶽自平沈。"]'),
('40630a30-e5b4-4e89-9819-dc61cbb929a7','題長干塔','釋道生','宋','宋诗','song-poetry','','[]','舍利無端應念來，浮圖平地擁崔嵬。',32,'全唐诗/poet.song.160000.json','["舍利無端應念來，浮圖平地擁崔嵬。", "當年不假金鎚力，爭得光明耀九垓。"]'),
('e6fac5c9-0883-4749-8e3d-4d08ef6231ca','送雪峰化主','釋道生','宋','宋诗','song-poetry','','[]','三毬輥動錯流傳，大用何曾得現前。',32,'全唐诗/poet.song.160000.json','["三毬輥動錯流傳，大用何曾得現前。", "千五百僧無頓放，累人走得脚皮穿。"]'),
('e4fd6171-413c-4bc8-99bc-ffea9ce02503','送聞兄持鉢','釋道生','宋','宋诗','song-poetry','','[]','聞聲悟道鳥投籠，祇麽無聞道未充。',64,'全唐诗/poet.song.160000.json','["聞聲悟道鳥投籠，祇麽無聞道未充。", "和劍拂開慳悋穴，全身輥入是非叢。", "脚頭脚尾無虛弁，山北山南有路通。", "一笑歸來能事畢，真金百鍊見全功。"]'),
('3c8277c6-b3b1-4718-a067-a3ea9999f7b8','送觀禪客','釋道生','宋','宋诗','song-poetry','','[]','西淛江邊話別時，斷頭船子疾如飛。',32,'全唐诗/poet.song.160000.json','["西淛江邊話別時，斷頭船子疾如飛。", "白拈手裏分贓去，臨濟休誇小廝兒。"]'),
('739b4e30-0936-41b2-bc84-8ba30e887e98','送道者幹瀾溪橋','釋道生','宋','宋诗','song-poetry','','[]','萬古瀾溪上，無風浪拍空。',24,'全唐诗/poet.song.160000.json','["萬古瀾溪上，無風浪拍空。", "路窮橋斷處，看子展神通。"]'),
('f7d68103-b0dc-453f-8290-9eb947af09f4','贈不欺信公監總餘杭建接待','釋道生','宋','宋诗','song-poetry','','[]','衲僧自有通人愛，笑捏空拳開接待。',64,'全唐诗/poet.song.160000.json','["衲僧自有通人愛，笑捏空拳開接待。", "十字縱橫古路頭，做成活計潑天大。", "阿呵呵，也奇怪，是聖是凡俱捉敗。", "接取一箇半箇來，要與叢林作殃害。"]'),
('03fcbe9d-5e06-4d2f-9a6c-f9a4ce2ec81b','偈七首  其一','釋允韶','宋','宋诗','song-poetry','','[]','一五二五，機輪無阻。',68,'全唐诗/poet.song.160000.json','["一五二五，機輪無阻。", "南山起雲，北山下雨。", "有人却道錦上添花，有人又道泥中洗土。", "有人又道離此二途，便見丹霄獨步。", "若總如斯論量，山僧未敢相許。"]'),
('423216ac-5f6c-4723-b993-165831112614','偈七首  其二','釋允韶','宋','宋诗','song-poetry','','[]','老漢當年臘月八，三更夜半顛狂發。',32,'全唐诗/poet.song.160000.json','["老漢當年臘月八，三更夜半顛狂發。", "剛把長釘釘眼睛，直至而今未能拔。"]'),
('1622eb0f-36aa-48fb-b557-d114899239f2','偈七首  其三','釋允韶','宋','宋诗','song-poetry','','[]','月月初一十五，處處槌鍾打鼓。',72,'全唐诗/poet.song.160000.json','["月月初一十五，處處槌鍾打鼓。", "若不毀謗禪道，便是呵駡佛祖。", "盡道慈悲接人，畢竟無過於此。", "承天鼻孔笑伊，直是未敢相許。", "坐人舌頭即不無，爭教無舌人解語。"]'),
('72f35ca9-cd75-4352-853d-02c676abc7c2','偈七首  其四','釋允韶','宋','宋诗','song-poetry','','[]','秋光清淺時，白鷺和烟島。',24,'全唐诗/poet.song.160000.json','["秋光清淺時，白鷺和烟島。", "良哉觀世音，全身入荒草。"]'),
('46c7a5c6-d016-4557-aaab-27a4c8db3e7d','偈七首  其五','釋允韶','宋','宋诗','song-poetry','','[]','寶劍未出匣，神光射斗牛。',24,'全唐诗/poet.song.160000.json','["寶劍未出匣，神光射斗牛。", "千兵雖易得，一將實難求。"]'),
('d46fd455-1064-41c7-946c-2ab90c9f14fc','偈七首  其六','釋允韶','宋','宋诗','song-poetry','','[]','八月秋，何處熱。',56,'全唐诗/poet.song.160000.json','["八月秋，何處熱。", "風入松，聲瑟瑟。", "落霞孤鶩齊飛，秋水長天一色。", "不是對景對機，不是應時應節。", "下座巡堂去，喫茶珍重歇。"]'),
('cfe8e6fd-2da3-4c45-a165-525a5315491b','偈七首  其七','釋允韶','宋','宋诗','song-poetry','','[]','籬畔黄花含曉露，庭前丹桂噴秋香。',32,'全唐诗/poet.song.160000.json','["籬畔黄花含曉露，庭前丹桂噴秋香。", "明明此物非他物，脫體承當不廝當。"]'),
('d5e1fcdf-783c-4489-b24e-f89f63b37fec','南山留題','呂元錫','宋','宋诗','song-poetry','','[]','龍穴潛幽通海潮，璇宮突兀插雲霄。',64,'全唐诗/poet.song.160000.json','["龍穴潛幽通海潮，璇宮突兀插雲霄。", "三千世界諸天近，百二山河故國遥。", "寥落偏城連谷口，荒涼古寺倚山腰。", "溪南可款門脩竹，何况丁寧已見招。"]'),
('e7fc61c4-d4ef-4503-bbe7-82b56d3ce3fe','和邦承所贈中隠古風','趙善括','宋','宋诗','song-poetry','','[]','少年麋鹿姿，待價非結綠。',276,'全唐诗/poet.song.160000.json','["少年麋鹿姿，待價非結綠。", "東湖嗜紅芰，西山茹黄獨。", "雖無負郭田，僅有環堵屋。", "稍知親簡編，豈意分符竹。", "不作梁甫吟，徒歌采薇曲。", "軒冕本無心，泉石慕幽躅。", "疏才偶計偕，微名玷宦牘。", "擾客書掣肘，蹈險車脫軸。", "爲米一折腰，獻玉三刖足。", "人情冰復炭，世路岸爲谷。", "奔走三十年，塵埃幾千斛。", "歸訪舊園林，要識真面目。", "敝廬他人居，故友半鬼錄。", "誅茅傾客囊，千日笑神速。", "堂成屢留醉，夜闌更秉燭。", "冬霜孤松秀，春霖萬花霂。", "薰風自生凉，秋雲不待族。", "魚鳥樂欣欣，柴荆紛樕樕。", "曳杖時往還，拊缶誰拘束。", "敲門聞剝啄，開緘佩謙牧。", "初讀少陵詩，再對淵明菊。", "試聽句擲金，坐想人如玉。", "搜腸嗣高吟，深愧窘邊幅。"]'),
('6d645e0b-2f99-45d3-8e42-adfe8ac55f09','和羅倅竹園唱和之什','趙善括','宋','宋诗','song-poetry','','[]','平生抱迂疏，舉世無兩箇。',216,'全唐诗/poet.song.160000.json','["平生抱迂疏，舉世無兩箇。", "每爲饑所驅，奔走不可奈。", "嘗聞伯夷風，粗爾立頑懦。", "初試巖邑宰，再作侯藩佐。", "一麾來江湖，不容暖席坐。", "流行遇坎止，留落寓江左。", "軻毀遭臧倉，孔厄類陽貨。", "從來宦情薄，况已心力惰。", "二兒可應門，肯堂復肯播。", "東湖五畝宅，喜賦歸來些。", "林亭足遐觀，竹齋宜醉卧。", "自謂景物幽，絕唱無人和。", "朅來憩水濱，光淥靜無涴。", "一見羅夫子，道眼俱看破。", "始知蠛蠓飛，未識天壤大。", "萬竿旌旗林，五車牛馬馱。", "羨君如籍咸，媿我非白賀。", "續貂慙斐然，君恕毋督過。"]'),
('899f9952-151b-4470-b483-b614d27a6540','清明後一日泛湖遊園聯句','趙善括','宋','宋诗','song-poetry','','[]','清明過一日，甲子喜新霽。',288,'全唐诗/poet.song.160000.json','["清明過一日，甲子喜新霽。", "理櫂汎平湖，吹風掃微曀。", "巧剪翠縠紋，忽展畫屏勢。", "千里入寸眸，萬物猶一贅。", "寄傲天地闊，放意江山麗。", "指點村市井，蕩漾漁家計。", "小泊楊柳堤，徐行蘭蕙砌。", "滿月射堵牆，乘風嚲雲髻。", "彩舟簫鼓喧，花亭翠紅蔽。", "石龍潄寒玉，竹鳳摇清篲。", "閙花如有言，閑草遠無際。", "梅豆點微酸，櫻珠綴纖脆。", "荇带牽風長，鷗雪點波細。", "怪山疊青巒，仙巖排綠桂。", "親友宴樽俎，泉石爽襟袂。", "曲徑濃香浮，深院幽人憩。", "日暖蜂蝶喧，沙軟鴛鴦儷。", "春秀猶未晚，懽遊端可繼。", "歸舠泝洄洑，嘉圃芘林翳。", "景勝詩愈豪，酒闌情未替。", "解帆竚別墅，尋芳適佳第。", "畫樓月初挂，朱欄春可繫。", "燒燭照紅粧，墮簪空綠鬄。", "笑歌誠有餘，金貂尚能貰。"]'),
('db76e28e-91c9-4ccc-b226-38bc89a3f938','和浙憲同諸公遊梅園  其一','趙善括','宋','宋诗','song-poetry','','[]','梓里德星聚，寶馬如雲屯。',144,'全唐诗/poet.song.160000.json','["梓里德星聚，寶馬如雲屯。", "揚鞭東城去，趁此梅正繁。", "林烟引輕素，晻曖連遥村。", "須臾日色高，客情舒宴溫。", "露晞潤玉瀣，雪粲融朝暾。", "千林秀松竹，萬點鋪蘭蓀。", "開落犯春早，塵埃迷晝昏。", "埋沒顔色好，孤負眉宇軒。", "疏野空自適，何人共清尊。", "諸公盡豪雋，逸飲如鯨吞。", "對花相慰藉，悲歡俱勿論。", "吹噓頼椽筆，欲謝終忘言。"]'),
('3a5ad891-46e7-4fe9-bc4f-b21bb3a4bcad','和浙憲同諸公遊梅園  其二','趙善括','宋','宋诗','song-poetry','','[]','庭除大槐安，人世甚蟻屯。',144,'全唐诗/poet.song.160000.json','["庭除大槐安，人世甚蟻屯。", "俯仰穹壤間，樂少憂且繁。", "何如置悲歡，訪梅東城村。", "羣賢負瑰奇，即之和氣溫。", "峭寒著春衣，輕烟翳晨暾。", "簪花愧華髮，席地依香蓀。", "誰許嫁東風，留香坐曉昏。", "密塢橫清溪，我欲創幽軒。", "所願花長開，日日同一尊。", "靜對影亦好，清味蕊可吞。", "此心無厭時，何物堪比論。", "哦詩愧續貂，勿以人廢言。"]'),
('63ac9755-a9a7-4cd7-b2fe-992596f0efeb','和伍解元喜祈雨有感','趙善括','宋','宋诗','song-poetry','','[]','癡龍偃蹇玩歲月，深居白雲抱幽石。',192,'全唐诗/poet.song.160000.json','["癡龍偃蹇玩歲月，深居白雲抱幽石。", "有時江海肆貪殘，坐視天焦地皮拆。", "分疆守職各有方，止沸詎可揚其湯。", "曰暘而暘雨而雨，何待酹酒焚爐香。", "不謂神心有城府，必需精禱方降雨。", "刑鵝割牲厭口腹，緇衣黄冠誦章句。", "上天有意生斯人，假爾羣祀江之濱。", "弄權推怨吝所施，帝怒碎戮猶微塵。", "吁嗟癡龍今已矣，異日憂深目前喜。", "勿將風雨希民求，歲歲豐穰盡天賜。", "我家亦有二頃田，膏澤霈然長有年。", "神心儻不悖天意，與民共賦噫嘻篇。"]'),
('4aad58cf-a446-4605-9ec4-66d65439f960','過金陵有感和韻','趙善括','宋','宋诗','song-poetry','','[]','五馬渡江思典午，祖龍謾鑿秦淮浦。',64,'全唐诗/poet.song.160000.json','["五馬渡江思典午，祖龍謾鑿秦淮浦。", "未登三代盛明時，曾是六朝文物祖。", "中興事業由憂勤，風流千載還芬薰。", "謝安王導亦可罪，至今遂使南北分。"]'),
('4e0e042f-bd31-46ec-9f4d-0f316e51973c','紀遊','趙善括','宋','宋诗','song-poetry','','[]','幾重濃雲潑黑墨，數點疏雨飛的皪。',224,'全唐诗/poet.song.160000.json','["幾重濃雲潑黑墨，數點疏雨飛的皪。", "桃花李花紅更白，不覺東風掃蹤跡。", "深山綠暗新樹密，懸崖倒掛春空碧。", "泉聲瀉出萬霹靂，長虹飛過三百尺。", "蹇馿倒騎回語客，目端春事俱可識。", "茅舍敲門傾琥珀，古寺擊鼓非玉食。", "我今已飽天工力，風吹浮雲露白日。", "崎嶮不復厭登陟，高處更窮低處逼。", "下瞰羣峰五頑石，回首一笑天地窄。", "興來策杖遶山側，竇深巖遠不可側。", "相思澗邊酌寒滴，一抹暝煙壯山色。", "尋真不見空回憶，使我傷今復傷昔。", "道人山房遍幽歷，醉裏疑從仙籍謫。", "鈞天廣樂夢中得，更問騰空好消息。"]'),
('29fd2830-19d8-49eb-9069-9def782d0048','樂塘鋪和周師禹韻','趙善括','宋','宋诗','song-poetry','','[]','遲日醉花春影長，村醪引入無何鄉。',64,'全唐诗/poet.song.160000.json','["遲日醉花春影長，村醪引入無何鄉。", "碧林啼鳥驚夢斷，行客紅塵吹去忙。", "憂心悄悄誰知道，且是不關春事了。", "雨暘今歲定豐年，慇懃更問農家老。"]'),
('c4b7ad5b-a1f5-4b1e-ae48-ce463d256db3','奉和章冠之長蘆壁間韻','趙善括','宋','宋诗','song-poetry','','[]','征帆來去方旁午，觸我扁舟維荻浦。',64,'全唐诗/poet.song.160000.json','["征帆來去方旁午，觸我扁舟維荻浦。", "疏林隠約響鐘魚，一葦可航參佛祖。", "西風留客意如勤，永日閑消一炷薰。", "詰朝霜重風力軟，千里翠縠并刀分。"]'),
('b696afa5-f32d-4ce5-806b-4f095214d36c','追和外舅郭倅定香院題詩','趙善括','宋','宋诗','song-poetry','','[]','我家冰清酒星魄，倏忽筆下驅雷風。',64,'全唐诗/poet.song.160000.json','["我家冰清酒星魄，倏忽筆下驅雷風。", "萬里去家煙瘴裏，一行作吏簿書中。", "高才不許在廊廟，仙跡且復歸瀛蓬。", "聲容杳杳水天闊，目斷波底斜陽紅。"]'),
('23fd74cd-32e4-4888-a24a-57751651793f','和張尉食字韻','趙善括','宋','宋诗','song-poetry','','[]','玉杯春酌金盤食，曾憶雪香同醉色。',64,'全唐诗/poet.song.160000.json','["玉杯春酌金盤食，曾憶雪香同醉色。", "歸來信宿未能忘，欲洗羈懷亂愁織。", "青山相對雲歸堂，一觴聊爾非瓊漿。", "羨君佳篇效伯良，要知使我搜枯腸。"]'),
('fd27be0c-d92b-42fb-a324-5385e2cce649','謝葛守詩軸','趙善括','宋','宋诗','song-poetry','','[]','君不見靈椿一株傳義方，僖儀接武躋金堂。',198,'全唐诗/poet.song.160000.json','["君不見靈椿一株傳義方，僖儀接武躋金堂。", "又不見老蘇獨步爲文主，軾轍聯芳入瓊府。", "始知盛德天所親，于門棨戟高拂雲。", "又知碩才世所貴，鯉庭詩禮超凡羣。", "司成藴蓄何如厚，萬頃淵源海波秀。", "劉郎少俊首辱和，揚善推賢宜有後。", "司成問學何如深，六經表裏金玉音。", "王氏拘攣了無取，雄文傑句由諸心。", "廬陵昔歲曾分教，甲子一周夢驚覺。", "賢郎賜得銅虎符，今日重遊想前效。", "黌堂咳唾遺明珠，翠琰刊成惠陋儒。", "請爲野史進青瑣，要繼皇朝竇與蘇。"]'),
('dd729dc0-b989-43e0-9069-4abac6c1e437','送外舅杜侍御使陝西','趙善括','宋','宋诗','song-poetry','','[]','建隆以來論人物，得士與古相低昂。',304,'全唐诗/poet.song.160000.json','["建隆以來論人物，得士與古相低昂。", "人才歷數仁祖世，後生嵬瑣無復望。", "老成寂寞典刑在，杜公玉立映班行。", "少時學問聖賢說，松柏歲寒觀老節。", "得官烏府不須臾，正色空聞動帷闥。", "鑠金衆口未必然，天與石城慰蕭屑。", "王師頃縛山西酋，朝廷却懷西顧憂。", "凉州旄鉞何足恃，岐隴須公勤傳郵。", "平生經國有雅意，乘流得坎惟所植。", "作官施設要近民，金馬嚴徐等兒戲。", "詔書寬大人樂生，吏民安業政令行。", "金城那可無粟守，堯舜與民寧並耕。", "茶鹽資國何必古，俗儒狥民不知務。", "精神折衝在本疆，要以雍容待倉遽。", "知無不爲公自期，豈弟君子神所私。", "秦山渭水照車馬，屬城列縣觀威儀。", "此行屬任良不惡，金魚新佩明光墀。", "誰言直諫居同少，淮南盜鑄煩撫綏。", "時平王度式金玉，歲晚汲公還見思。"]'),
('fc4c6f2f-f981-4c1a-8968-bff21a87f5a8','真妃祠','趙善括','宋','宋诗','song-poetry','','[]','碧潭無底潛蛟龍，神居下宅琉璃宮。',336,'全唐诗/poet.song.160000.json','["碧潭無底潛蛟龍，神居下宅琉璃宮。", "一水鏡奠撓不濁，兩山角抵常爭雄。", "鴉啼古廟樹色黑，魚躍急湍波影紅。", "鬢霧鬟烟森拱竦，棟雲簾雨飛冥濛。", "蕙肴時展朝暮奠，蒲席快分南北風。", "假威老巫腹恣飽，乞靈行客心潛通。", "無求小舸疾飛鳥，不恨孤蹤成斷蓬。", "去秋浙右盡淹沒，今夏江西尤藴隆。", "尾銜萬斛去不返，鱗次千倉皆屢空。", "農背赤裂魚釜滿，田毛焦枯龜兆同。", "炎官張皇掉旗旆，海若羞澀藏沖融。", "一方雖藉訶護力，四海正思霖雨功。", "片帆短棹利極細，釃酒割牲酬易窮。", "好乘雲車命箕伯，去擊雷鼓驅豐隆。", "晶熒燭物掣長電，剨勒掃空消霽虹。", "不須犀角照百怪，何待牛蹄翻巨䜫。", "挽起天河盡傾瀉，坐令人物還熙豐。", "笑談可活萬民命，頃刻已回元氣工。", "上帝報功賜褒敕，真妃錫號榮清躬。", "元圭華衮依約裏，介族水類驅馳中。", "山高水深千萬祀，南面血食無時終。"]'),
('8d086318-d792-469b-bbac-15b3afc89dcd','上王右司三十韻','趙善括','宋','宋诗','song-poetry','','[]','丱角從親後，摳衣拱座隅。',288,'全唐诗/poet.song.160000.json','["丱角從親後，摳衣拱座隅。", "辭章窺雅制，翰墨景良模。", "零露哀先德，青雲激壯圖。", "暌違十五載，流落二三孤。", "蹇澀憑鄉薦，崎嶇達上都。", "芝眉重晤對，桂籍偶叨踰。", "勞苦溫言重，開明鄙性迂。", "一雷初綰綬，千里遇分符。", "琴浦催科拙，澄江德政殊。", "美瓜滋灌水，良醖寄兵厨。", "社雁驚飛楚，邊鴻不到吳。", "色辭思益遠，憂患痛多虞。", "風樹親難待，林泉誓與俱。", "啼號真有累，韁鎖復相拘。", "華節來臨鎮，荒城獲走趨。", "二天蒙芘覆，半載幸馳驅。", "郡政慚轓蓋，民歌愧袴襦。", "深期展四體，寧復顧微軀。", "厚意平生在，高風振古無。", "親依方款密，聚散忽須臾。", "鷁首浮仙路，烏臺接禁塗。", "苕溪雖近甸，宣室頼嘉謨。", "德盛應難外，民思覬少蘇。", "甘泉躋法從，膏澤下寰區。"]'),
('812bfce9-5a15-4770-81f2-1f8f60aaf340','題古圳鋪','趙善括','宋','宋诗','song-poetry','','[]','去郭十五里，依山三兩家。',48,'全唐诗/poet.song.160000.json','["去郭十五里，依山三兩家。", "剪茅成棟宇，沽酒是生涯。", "雨過鳩休婦，日斜蜂趁衙。", "親闈今咫尺，停夢看燈花。"]'),
('9f3bf717-e103-4a71-bf5e-5cb050ec8c94','結茅守冢偶携子弟散策郊遊有感借用壁間韻  其一','趙善括','宋','宋诗','song-poetry','','[]','天地一蟻磨，人生何日閑。',48,'全唐诗/poet.song.160000.json','["天地一蟻磨，人生何日閑。", "此身真土木，到處即溪山。", "血點居苫淚，衣餘戲綵斑。", "春遊板輿在，無復奉慈顔。"]'),
('a8bc7462-87ac-4fa0-b07d-7a4b8e2ec9b6','結茅守冢偶携子弟散策郊遊有感借用壁間韻  其二','趙善括','宋','宋诗','song-poetry','','[]','蠖屈地容壯，鳥還天宇閑。',48,'全唐诗/poet.song.160000.json','["蠖屈地容壯，鳥還天宇閑。", "漁樵苕水市，薇蕨首陽山。", "甕下金貂友，林中玉笋班。", "誰能齊萬物，爲我辨彭顔。"]'),
('6a5c782e-408e-4f99-b7d2-c63a53decb70','題定光壁','趙善括','宋','宋诗','song-poetry','','[]','護雨雲初斷，登山眼便明。',48,'全唐诗/poet.song.160000.json','["護雨雲初斷，登山眼便明。", "楓彫丹舞葉，松古綠摇聲。", "覺宿無窮老，禪關有底清。", "小春天不冷，歸路尚餘情。"]'),
('aeda5a5d-80f3-4b92-80be-a6271a33418b','和龔同叔春日即事五首  其一','趙善括','宋','宋诗','song-poetry','','[]','苦雨不肯霽，花愁都落紅。',48,'全唐诗/poet.song.160000.json','["苦雨不肯霽，花愁都落紅。", "老農欣歲兆，游子恨途窮。", "寒尚衣難褪，春侵酒易中。", "城頭喧角弄，輕度一簾風。"]'),
('3396f2e3-5c18-4499-ad86-74d2a78c6f4d','和龔同叔春日即事五首  其二','趙善括','宋','宋诗','song-poetry','','[]','柳綿飛撲撲，荷葉散田田。',48,'全唐诗/poet.song.160000.json','["柳綿飛撲撲，荷葉散田田。", "物幻無窮意，春歸何處天。", "事隨鸞鏡改，人逐燕巢遷。", "一笑千金價，吾羞魯仲連。"]'),
('d4de190b-864f-4018-9420-982ef2aea0a3','和龔同叔春日即事五首  其三','趙善括','宋','宋诗','song-poetry','','[]','鶑簧方報暖，鳩喚未容晴。',48,'全唐诗/poet.song.160000.json','["鶑簧方報暖，鳩喚未容晴。", "新漲長還減，癡雲暗復明。", "我生隨分樂，春事有餘情。", "聞道東湖好，相邀散策行。"]'),
('1a6c1829-d4af-4e81-bfda-da7aa51e411f','和龔同叔春日即事五首  其四','趙善括','宋','宋诗','song-poetry','','[]','春已堂堂去，那聞杜宇啼。',48,'全唐诗/poet.song.160000.json','["春已堂堂去，那聞杜宇啼。", "江山驚異土，桃李謾成蹊。", "我自無心了，誰能與物齊。", "功名儻相貸，深卷碧雲溪。"]'),
('badb9227-b2cc-44c7-a5ed-b30887b304ea','和龔同叔春日即事五首  其五','趙善括','宋','宋诗','song-poetry','','[]','邂逅相逢好，初心各壯圖。',48,'全唐诗/poet.song.160000.json','["邂逅相逢好，初心各壯圖。", "金蘭期永好，銀艾願同紆。", "恨逐芳樽遣，情煩綵筆鋪。", "風雲偶然會，携手上天衢。"]'),
('86268ace-c912-4ade-b73b-37070623baa0','世事二首  其一','趙善括','宋','宋诗','song-poetry','','[]','世事今如此，惟堪一笑譁。',48,'全唐诗/poet.song.160000.json','["世事今如此，惟堪一笑譁。", "空持衝斗劍，安得上天槎。", "遠信憑飛翼，流年付落花。", "平戎須大度，何必顧纖瑕。"]'),
('73233031-545e-403a-bf4e-23195e884bd7','世事二首  其二','趙善括','宋','宋诗','song-poetry','','[]','我貧非道病，生計恝然疏。',48,'全唐诗/poet.song.160000.json','["我貧非道病，生計恝然疏。", "數畝田常旱，一溪雲有餘。", "幸無貧外樂，贏得靜中虛。", "已斷聲華念，臨深肯羨魚。"]'),
('e1b0acf3-8b24-4576-b571-a705f551a78c','再用前韻  其一','趙善括','宋','宋诗','song-poetry','','[]','枕席方相好，兒童且勿譁。',48,'全唐诗/poet.song.160000.json','["枕席方相好，兒童且勿譁。", "窗蕉鸞曳尾，簷樹鵲鳴槎。", "有客談飛屑，無才筆吐花。", "倦餘題短句，誰爲指瑜瑕。"]'),
('1d912f64-8d02-4156-a0c4-5bc10d147dc3','再用前韻  其二','趙善括','宋','宋诗','song-poetry','','[]','我是忘機士，初非學二疏。',48,'全唐诗/poet.song.160000.json','["我是忘機士，初非學二疏。", "甕醅常得醉，瓶粟任無餘。", "天下衆生病，山中四壁虛。", "昔年芻豢口，今日伴鐘魚。"]'),
('93403d51-4b73-41e8-8e46-52c8cbdced36','遊香社寺','趙善括','宋','宋诗','song-poetry','','[]','山水興方逸，塵埃縛暫寬。',48,'全唐诗/poet.song.160000.json','["山水興方逸，塵埃縛暫寬。", "菜腸甘久素，酒頰助微丹。", "江闊煙光薄，霜滋葉暈殘。", "不妨走幽寺，或可叩禪端。"]'),
('9a163ea0-b1f2-4f71-8fef-2910199a188b','清明偶題','趙善括','宋','宋诗','song-poetry','','[]','曲沼一泓碧，亂花雙徑紅。',48,'全唐诗/poet.song.160000.json','["曲沼一泓碧，亂花雙徑紅。", "欹梅驚北客，舞柳認東風。", "欲買春無價，常令酒不空。", "我生隨分樂，初不問窮通。"]'),
('b70b1f67-6fd9-4683-8467-5f622645b0a8','同王秘校和同年五使君韻餞送嚴文守江陰  其一','趙善括','宋','宋诗','song-poetry','','[]','江左詞章伯，朝端俊偉人。',48,'全唐诗/poet.song.160000.json','["江左詞章伯，朝端俊偉人。", "燕居文會友，得志澤加民。", "自是無心鏡，俱傳有脚春。", "成風運斤斧，何處不參神。"]'),
('2544b341-57fd-4d94-9c62-584aa75a5d5b','同王秘校和同年五使君韻餞送嚴文守江陰  其二','趙善括','宋','宋诗','song-poetry','','[]','欲說澄江好，丹青百雉樓。',48,'全唐诗/poet.song.160000.json','["欲說澄江好，丹青百雉樓。", "山明新雨澤，潮涌亂雲流。", "賢守聲先至，疲民疾已瘳。", "中興待良佐，千里未分憂。"]'),
('9fdb1f68-a514-465f-a133-1d530d80e89f','題儀真天寧寺','趙善括','宋','宋诗','song-poetry','','[]','短棹客千里，炷香人小留。',48,'全唐诗/poet.song.160000.json','["短棹客千里，炷香人小留。", "禪房深寂寂，世事易悠悠。", "去此兩槐夏，驚予雙鬢秋。", "鐘魚發新響，作意爲重遊。"]'),
('e99c358f-721e-499d-8e5a-1eb36bd4658a','挽王漕稚川  其一','趙善括','宋','宋诗','song-poetry','','[]','紫荷餘愛在，皂蓋填名城。',48,'全唐诗/poet.song.160000.json','["紫荷餘愛在，皂蓋填名城。", "膏澤流千里，嘉謀肅五兵。", "林泉多雅趣，桑梓有深情。", "道大雖難用，詳觀月旦評。"]'),
('368e35fc-f9cb-423d-8dfa-24e8ad23c58a','挽王漕稚川  其二','趙善括','宋','宋诗','song-poetry','','[]','昆玉皆龍鳳，唯公最白眉。',48,'全唐诗/poet.song.160000.json','["昆玉皆龍鳳，唯公最白眉。", "鄉邦好人物，翰墨妙詞詩。", "南浦言猶在，西山夢可疑。", "我歸公已逝，霰淚不勝悲。"]'),
('1d1e6f1a-547d-4d9d-acfa-49357775090d','挽朱倅周卿  其一','趙善括','宋','宋诗','song-poetry','','[]','戚畹芝蘭秀，儒宗金玉相。',48,'全唐诗/poet.song.160000.json','["戚畹芝蘭秀，儒宗金玉相。", "解牛無肯綮，馳驥阻康莊。", "政術今猶誦，家風久益彰。", "藴藏初未試，盛德付諸郎。"]'),
('17facbe6-5e2b-4d2a-b326-5fa8f278bd8b','挽朱倅周卿  其二','趙善括','宋','宋诗','song-poetry','','[]','自灑膏粱習，人推道義尊。',48,'全唐诗/poet.song.160000.json','["自灑膏粱習，人推道義尊。", "蟾宮看桂子，鳳穴見蘭孫。", "遺戒垂家法，新詩斷客魂。", "從今渭陽念，極目灌城村。"]'),
('2373418e-c3e7-41af-8d28-50e877692ced','挽陳提舉  其一','趙善括','宋','宋诗','song-poetry','','[]','藺璧雖期復，蘇書竟不還。',48,'全唐诗/poet.song.160000.json','["藺璧雖期復，蘇書竟不還。", "慶餘鍾令緒，才大壓塵寰。", "勁正三朝老，從容半世閑。", "會心真是老，一笑別人間。"]'),
('64842b18-29f4-4611-9ac1-9643356d5146','挽陳提舉  其二','趙善括','宋','宋诗','song-poetry','','[]','志學屢辭爵，傳家蔚有聲。',48,'全唐诗/poet.song.160000.json','["志學屢辭爵，傳家蔚有聲。", "小官能抗疏，文吏乃知兵。", "守法摧强禦，輸忠沃聖明。", "平生無所負，讒口任蠅營。"]'),
('aa249592-e5ed-477f-b521-b94b53db6487','挽陳提舉  其三','趙善括','宋','宋诗','song-poetry','','[]','持斧威全振，分符盜易殲。',48,'全唐诗/poet.song.160000.json','["持斧威全振，分符盜易殲。", "真祠方賜逸，榮養遽難淹。", "許國心如在，繩家法正嚴。", "莫悲才不盡，祥覽卧寒苫。"]'),
('b71d7d47-891b-4fd1-bada-9d40b2c3398e','王提舉閤政錢夫人挽詩  其一','趙善括','宋','宋诗','song-poetry','','[]','閥閲由忠孝，閨門仰靜專。',48,'全唐诗/poet.song.160000.json','["閥閲由忠孝，閨門仰靜專。", "儉勤天所賦，容德古難全。", "雲誥疏華國，霓旌返洞天。", "風霜孤鶴恨，銜羽唳寒煙。"]'),
('2ccbea8d-d189-4b36-9a0d-9562549d7492','王提舉閤政錢夫人挽詩  其二','趙善括','宋','宋诗','song-poetry','','[]','山敞神仙宅，人辭富貴家。',48,'全唐诗/poet.song.160000.json','["山敞神仙宅，人辭富貴家。", "靚容深莫識，清節瑩無瑕。", "蚌脫珠方璨，椿靈桂始華。", "他年容萬馬，今日送千車。"]'),
('e3f9843e-a173-4095-b97f-15037dfc2e5a','中秋下澣次計幕諸公佳什之韻  其一','趙善括','宋','宋诗','song-poetry','','[]','駒隙匆匆不暫留，誰能宴坐學裴休。',64,'全唐诗/poet.song.160000.json','["駒隙匆匆不暫留，誰能宴坐學裴休。", "君携嘉客江亭醉，我泛扁舟楚澤秋。", "水浸斜陽紅影濕，煙橫疊巘翠光浮。", "何時再卜秋屏約，共踏西風爛熳遊。"]'),
('d7b38335-9003-4e24-bb50-1baf3a9558ec','中秋下澣次計幕諸公佳什之韻  其二','趙善括','宋','宋诗','song-poetry','','[]','短櫂夷猶任去留，塵勞今日暫休休。',64,'全唐诗/poet.song.160000.json','["短櫂夷猶任去留，塵勞今日暫休休。", "飛觴莫問重城晚，攬鏡須驚兩鬢秋。", "千里歸艎何日到，一眉晴綠與雲浮。", "殷勤更問黄花信，準擬重陽一再遊。"]'),
('a5b46c38-4e24-434d-bccd-e5b6964da210','次龔丈同叔高韻','趙善括','宋','宋诗','song-poetry','','[]','備嘗險阻與艱難，久別松楸水一灣。',64,'全唐诗/poet.song.160000.json','["備嘗險阻與艱難，久別松楸水一灣。", "孤憤未申思北闕，雙眉初展見西山。", "化工已定休言命，巧匠于今亦汗顔。", "它日中興籌廟略，爲君一露管中斑。"]'),
('36719b63-1f33-4b76-bb1f-7d7664853652','再用同叔韻','趙善括','宋','宋诗','song-poetry','','[]','風定舟行力不難，一鈎新月照溪灣。',64,'全唐诗/poet.song.160000.json','["風定舟行力不難，一鈎新月照溪灣。", "斷烟橫抹岸頭樹，落日斜欹江上山。", "魚鳥久知思舊侶，桑榆歸去亦慙顔。", "兒童見我應相怪，兩鬢如何雪樣斑。"]'),
('b8734c84-9fec-4a20-ab80-20fa495ffc67','題馬氏避暑宮開福寺蓮湖','趙善括','宋','宋诗','song-poetry','','[]','金仙樓觀鬰嵯峨，昔日曾容萬綺羅。',64,'全唐诗/poet.song.160000.json','["金仙樓觀鬰嵯峨，昔日曾容萬綺羅。", "不見園林蒙錦繡，空教鐘鼓喚笙歌。", "印花寶甃封蒼蘚，倚檻晴山擁翠螺。", "凉夜尚疑旌蓋在，三千宮女襪凌波。"]'),
('53049982-c154-4042-8ee4-e65793eaaf6b','和莫謙父韻','趙善括','宋','宋诗','song-poetry','','[]','扁舟昨夜過黄州，準擬籃輿作勝遊。',64,'全唐诗/poet.song.160000.json','["扁舟昨夜過黄州，準擬籃輿作勝遊。", "卷地駭風迴岸脚，撲天驚浪打船頭。", "一尊欲訪東坡隠，兩鬢難禁宋玉秋。", "江上亂山雲色重，却疑眉黛鎖閑愁。"]'),
('60afe6d2-eabb-4377-b417-276f5914c889','和葉宰','趙善括','宋','宋诗','song-poetry','','[]','暫時行李已堪憂，况是經年成漫遊。',64,'全唐诗/poet.song.160000.json','["暫時行李已堪憂，况是經年成漫遊。", "三月曉風紅掃地，一犁春雨綠盈疇。", "從教征袖塵埃滿，頼有新詩篋笥收。", "桃李主人能好事，未歸誰復嘆淹流。"]'),
('96407c52-388c-4895-bc39-a4f27fe41a9a','過清江懷莫謙父','趙善括','宋','宋诗','song-poetry','','[]','春來乘興泛孤篷，櫂影頻移鑑影中。',64,'全唐诗/poet.song.160000.json','["春來乘興泛孤篷，櫂影頻移鑑影中。", "昨夜忽添三寸雨，今朝尤喜一帆風。", "桃紅李白年年好，水綠青山處處同。", "屈指歸時花未老，一樽携手過湖東。"]'),
('16248b8f-e3e8-4832-93eb-05665ad2d02d','過前岡見毀松有感  其一','趙善括','宋','宋诗','song-poetry','','[]','夾道松陰若剪齊，前人種得幾多時。',64,'全唐诗/poet.song.160000.json','["夾道松陰若剪齊，前人種得幾多時。", "曾經行客頻相戀，試問鄉翁總不知。", "暗引風聲號綠野，密留雲影掛蒼枝。", "今人惠物能如否，祇有摧殘樵牧兒。"]'),
('919b5cca-c721-4a48-a2cd-e018e8a82919','過前岡見毀松有感  其二','趙善括','宋','宋诗','song-poetry','','[]','當年種植到于今，用力雖勞用意深。',64,'全唐诗/poet.song.160000.json','["當年種植到于今，用力雖勞用意深。", "巨蔭已容車馬過，盤根寧畏雪霜侵。", "兩行冠劍大夫職，十萬旌旗勇士林。", "烈日流金路無盡，此時方識古人心。"]'),
('6b1c5706-dfed-4266-8b76-ae857e812a0c','送運幹陳聖嘉解組還朝','趙善括','宋','宋诗','song-poetry','','[]','月明千里正嬋娟，且莫匆匆便放船。',64,'全唐诗/poet.song.160000.json','["月明千里正嬋娟，且莫匆匆便放船。", "三載泛蓮依綠水，一朝薦鶚上青天。", "西樓未作經笥夢，北闕先分御鼎煙。", "且向蓬山讎校了，却持荷橐從甘泉。"]'),
('af3d4f5a-4696-44d8-a557-3df3f2d65fab','登梅仙壇觀中作','趙善括','宋','宋诗','song-poetry','','[]','梅尉棲真昔已仙，祇餘巖谷正巍然。',64,'全唐诗/poet.song.160000.json','["梅尉棲真昔已仙，祇餘巖谷正巍然。", "老松作勢龍千尺，怪石拏空虎一拳。", "樓與雲齊曾觀日，壇因斗建欲捫天。", "如今勝景能長在，塵世應無海變田。"]'),
('f76c3e89-99a5-4ad5-af6d-aadbb05f28e6','醮成作','趙善括','宋','宋诗','song-poetry','','[]','心格崇霄禁路通，纖埃收盡見天容。',64,'全唐诗/poet.song.160000.json','["心格崇霄禁路通，纖埃收盡見天容。", "三千絳闕雲開鎖，十萬霓旌月印蹤。", "香裊鬰葱翔鼎鳳，松摇寥廓狀雲龍。", "虛皇夜宴長生殿，九奏瓊璈動曉鐘。"]'),
('c84ab897-f159-4838-88e0-53730a3774b4','醮畢作','趙善括','宋','宋诗','song-poetry','','[]','醮闌星斗挂脩甍，綵蹕丹輿上玉清。',64,'全唐诗/poet.song.160000.json','["醮闌星斗挂脩甍，綵蹕丹輿上玉清。", "百尺壇空雲弄影，一鈎簾捲月輸明。", "靈香匝地寒無力，寶奏鈞天靜有聲。", "萬里好風吹目斷，松篁猶學珮環鳴。"]'),
('cd8fc186-2570-478e-9001-60dfccf5b6af','登壇作','趙善括','宋','宋诗','song-poetry','','[]','一壇橫壓紺天低，好向雲端覲紫微。',64,'全唐诗/poet.song.160000.json','["一壇橫壓紺天低，好向雲端覲紫微。", "林鶴慣聞金磬舞，烟鸞疑認玉臺飛。", "步虛聲徹空猶響，寶篆香銷露未晞。", "星斗繡天長不夜，疑乘風馭扣瑶扉。"]'),
('19f4ba90-0bf8-4e40-9c24-2153bca2b528','登裴公亭借用杜牧之登齊山詩韻二首  其一','趙善括','宋','宋诗','song-poetry','','[]','春晚風花片片飛，登臨共惜景熹微。',64,'全唐诗/poet.song.160000.json','["春晚風花片片飛，登臨共惜景熹微。", "人生待足誰如意，官况苦無胡不歸。", "且向園林窮勝事，更憑山水發清暉。", "酒酣起舞君休笑，直欲淋漓身上衣。"]'),
('3659a85e-f6bd-4694-9ce7-b166666c1835','登裴公亭借用杜牧之登齊山詩韻二首  其二','趙善括','宋','宋诗','song-poetry','','[]','風簾斜捲燕于飛，天氣清和酒力微。',64,'全唐诗/poet.song.160000.json','["風簾斜捲燕于飛，天氣清和酒力微。", "極目烟波無盡藏，關心春夢有時歸。", "香飄十里喧朝市，翠積千山斷晚暉。", "杖屨不妨頻一到，塵埃那解點征衣。"]'),
('b818a110-da8e-4092-9d14-90acb7163229','同葉宰餞春浄衆寺','趙善括','宋','宋诗','song-poetry','','[]','千尺飛虹跨碧溪，綠陰沉水暗連堤。',64,'全唐诗/poet.song.160000.json','["千尺飛虹跨碧溪，綠陰沉水暗連堤。", "馬蹄一踏沙頭滑，雲脚半垂山頂齊。", "招隠疏鐘曾破夢，洗春微雨不成泥。", "晚來放目郊園外，萬點翻鴉散麥畦。"]'),
('b180a3ee-fa52-4d5c-8d0f-d32d403e8844','游梅仙壇口占','趙善括','宋','宋诗','song-poetry','','[]','籃輿破曉雨初收，天氣正和麥正秋。',64,'全唐诗/poet.song.160000.json','["籃輿破曉雨初收，天氣正和麥正秋。", "四合平林空翠滴，一川芳草亂青浮。", "梅仙道館松全古，馬祖禪關山更幽。", "擾擾紅塵竟何事，此身宜老白雲秋。"]'),
('302d1198-ae46-49d7-8621-727562fa0064','挽趙龍圖大卿','趙善括','宋','宋诗','song-poetry','','[]','膠庠昔日共虀鹽，窮達分携四十年。',64,'全唐诗/poet.song.160000.json','["膠庠昔日共虀鹽，窮達分携四十年。", "南北阮門殊少長，東西施子異媸妍。", "判花雋嗣躋三品，司稼名卿正九遷。", "世事只須聊復爾，秋堂明月豈長圓。"]'),
('1252b948-1a69-4e8c-9e1d-5208850b430e','臨江玉虛觀有牡丹思後圃亦正開恨不與集','趙善括','宋','宋诗','song-poetry','','[]','絳苞翠幄壓朱欄，秀色生香觀裏看。',64,'全唐诗/poet.song.160000.json','["絳苞翠幄壓朱欄，秀色生香觀裏看。", "小圃想須春爛熳，大家應是醉團欒。", "名韁久縱心無累，利徑雖馳興易闌。", "但願對花常酩酊，莫思身外有悲懽。"]'),
('44155165-79eb-4626-af89-2b33b2504081','贈趙舍人','趙善括','宋','宋诗','song-poetry','','[]','季父英名上玉津，瞿曇抱送石麒麟。',64,'全唐诗/poet.song.160000.json','["季父英名上玉津，瞿曇抱送石麒麟。", "龍文寶冊傳青瑣，鳳閣鸞坡近紫宸。", "親老侍行知有子，才高見忌豈無人。", "洪崖百仞泉飛玉，一洗人間萬斛塵。"]'),
('ae23a91e-9ab4-4601-97e5-52b63420a31d','挽韓漕直閣  其一','趙善括','宋','宋诗','song-poetry','','[]','忠憲勳名冠本朝，傳芳五葉盡金貂。',64,'全唐诗/poet.song.160000.json','["忠憲勳名冠本朝，傳芳五葉盡金貂。", "芝蘭生子競秀發，松柏如公合後凋。", "淮縣劇繁迎刃解，蜀邊姦慝望風銷。", "才高見忌何須病，公道于今久寂寥。"]'),
('739e5f1e-da67-4c2d-83ed-8471c8b96207','挽韓漕直閣  其二','趙善括','宋','宋诗','song-poetry','','[]','孳孳善政被民編，謇謇嘉謨黼扆前。',64,'全唐诗/poet.song.160000.json','["孳孳善政被民編，謇謇嘉謨黼扆前。", "萬卷詩書門戶壯，一生功業子孫賢。", "夢回芳圃猶樽俎，淚落虛堂絕管絃。", "我始卜鄰君已逝，茂林修竹亦凄然。"]'),
('59e2008d-9e34-432e-ae29-5e80db13a5dd','平山堂','趙善括','宋','宋诗','song-poetry','','[]','平山堂對妙高峰，極目郊原萬里同。',64,'全唐诗/poet.song.160000.json','["平山堂對妙高峰，極目郊原萬里同。", "杳靄四垂天不盡，縈紆一带水無窮。", "城闉遥隔芙蓉浦，欄檻幾經楊柳風。", "想見風流賢太守，一尊時復酹歐翁。"]'),
('19872520-0b65-4b0f-b1a9-6c6c914c58f6','躍馬西湖','趙善括','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曉來何事到湖西，風急飛紅襯馬蹄。',64,'全唐诗/poet.song.160000.json','["曉來何事到湖西，風急飛紅襯馬蹄。", "望信只愁秋雁斷，愛春還恨早鶑啼。", "山連樓閣雲容重，水浸欄干月影低。", "歸棹採菱重惜晚，一聲歌過綠楊堤。"]'),
('d1acd579-76f4-4063-8a19-b65eb1db2b47','過清渚','趙善括','宋','宋诗','song-poetry','','[]','橫岡櫛比路彎環，茅店無人晝亦關。',64,'全唐诗/poet.song.160000.json','["橫岡櫛比路彎環，茅店無人晝亦關。", "桑圃霜枯乾葉舞，麥畦雨潤翠苗斑。", "山風力壯嘯空谷，溪水流清露瘦灘。", "斜崦乍明天地闊，只疑身在碧壺間。"]'),
('e685b4ce-7901-4467-a342-291bd9d8f04f','清明日醉普光閣上','趙善括','宋','宋诗','song-poetry','','[]','東郊綠暗已紅稀，指準酴醾待我歸。',64,'全唐诗/poet.song.160000.json','["東郊綠暗已紅稀，指準酴醾待我歸。", "細葉急隨流水去，片心常望白雲飛。", "半規殘日穿林薄，一带遥山抹黛微。", "起舞高歌共春酌，憑欄無語欲忘機。"]'),
('8ca11129-73ef-4d3e-ae3a-507d41416aee','發舟至至德觀','趙善括','宋','宋诗','song-poetry','','[]','風細檣高去路遲，曉烟秋色正霏微。',64,'全唐诗/poet.song.160000.json','["風細檣高去路遲，曉烟秋色正霏微。", "彎環沙觜村市井，突兀江心古釣磯。", "湧月小軒無盡藏，參天老檜不勝圍。", "山川好處都輸與，不是緇袍即羽衣。"]'),
('fde01fa1-e457-47cc-a55d-986638207142','題本覺寺','趙善括','宋','宋诗','song-poetry','','[]','春禽嚼徵更含宮，喚我精藍路易窮。',64,'全唐诗/poet.song.160000.json','["春禽嚼徵更含宮，喚我精藍路易窮。", "雨雪不垂成暮靄，花開都盡怨東風。", "一川芳草低隨水，滿眼青山半插空。", "躍馬歸來尤寂寞，此懷欲與故人同。"]'),
('0648ba91-b8f9-4a42-91fc-ad65f814e550','題長沙倅廳磬沼','趙善括','宋','宋诗','song-poetry','','[]','嘉名雅合泗濱浮，玉振金聲第一流。',64,'全唐诗/poet.song.160000.json','["嘉名雅合泗濱浮，玉振金聲第一流。", "曲尺映橋橫錦带，灣環沉月並瑶鈎。", "清如有韻應儀鳳，擊若無心可狎鷗。", "好向新亭按宮徵，凌波聲動一簾秋。"]'),
('8d3bd628-165f-40d3-8d78-55dbab59fc77','用子存韻寄乃兄雪香','趙善括','宋','宋诗','song-poetry','','[]','要識居塵不染塵，小窗容膝近東鄰。',64,'全唐诗/poet.song.160000.json','["要識居塵不染塵，小窗容膝近東鄰。", "香梢不老偏宜曉，瘦節常寒別是春。", "侑坐圖書情頗厚，對床風雨夢還新。", "擬將梅竹方兄弟，若說清高更逼真。"]'),
('0380c524-f7f6-43d0-b30d-ed91ed4bc890','和帥座勸農三首  其一','趙善括','宋','宋诗','song-poetry','','[]','光風駘蕩滿春亭，嶽麓雲開九疊屏。',32,'全唐诗/poet.song.160000.json','["光風駘蕩滿春亭，嶽麓雲開九疊屏。", "珍重元戎奉明詔，一犁膏雨曉痕青。"]'),
('0af1e042-9a77-4cac-a980-03d05a386171','和帥座勸農三首  其二','趙善括','宋','宋诗','song-poetry','','[]','指日追鋒數驛亭，論恩便合對丹屏。',32,'全唐诗/poet.song.160000.json','["指日追鋒數驛亭，論恩便合對丹屏。", "行看功業掀天地，陳跡俱堪入汗青。"]'),
('0f0b2612-e170-469e-986b-88c9c5b9d243','和帥座勸農三首  其三','趙善括','宋','宋诗','song-poetry','','[]','投老歸歟一草亭，蓽門蕙帳對蘭屏。',32,'全唐诗/poet.song.160000.json','["投老歸歟一草亭，蓽門蕙帳對蘭屏。", "自從濫吹紅蓮幕，孤負東風柳眼青。"]'),
('a130bb27-2db3-463a-a6dc-f2f29bdd9eb8','隔凡石','趙善括','宋','宋诗','song-poetry','','[]','見說仙凡事不同，道旁先問石屏風。',32,'全唐诗/poet.song.160000.json','["見說仙凡事不同，道旁先問石屏風。", "十洲三島不須去，絳闕瑶臺在此中。"]'),
('aa9116ca-d0f5-4473-a572-b9e5d527141a','和陽運幹見招集句','趙善括','宋','宋诗','song-poetry','','[]','漠漠窮陰斷送秋，杖藜徐步向芳洲。',32,'全唐诗/poet.song.160000.json','["漠漠窮陰斷送秋，杖藜徐步向芳洲。", "但將酩酊酬佳節，一笑相從萬事休。"]'),
('4f26624e-94db-43b3-abd7-cc6b2daa3135','題壁','趙善括','宋','宋诗','song-poetry','','[]','平蕪行盡又青山，水遶寒堤綠一灣。',32,'全唐诗/poet.song.160000.json','["平蕪行盡又青山，水遶寒堤綠一灣。", "征客紅塵自來去，碧林鳴鳥獨幽閑。"]'),
('8f281dfb-18f2-4ce9-81b8-49c85322a70a','天寶洞天','趙善括','宋','宋诗','song-poetry','','[]','扳緣石磴入青冥，霧廓雲開萬象清。',64,'全唐诗/poet.song.160000.json','["扳緣石磴入青冥，霧廓雲開萬象清。", "夭嬌老杉龍欲舞，縱橫卧石虎方獰。", "二仙昔被桃源誤，四皓今餘橘隠情。", "擬入清都真洞府，一簾寒溜隔飛瓊。"]'),
('b6dfeb09-5003-4b4b-a7df-bbe1c84b3f30','乙酉端午聯句','趙善括','宋','宋诗','song-poetry','','[]','離騷讀罷意沉沉，痛飲狂歌作楚吟。',32,'全唐诗/poet.song.160000.json','["離騷讀罷意沉沉，痛飲狂歌作楚吟。", "魚腹有靈應瞑目，後來猶自有孫心。"]'),
('70a934a4-be90-42b3-82fe-dcda5c95949e','鳴水洞辭','王炎','宋','宋诗','song-poetry','','[]','艾之西兮汨之原，山石劃斷兮穹巔而嶄巖。',215,'全唐诗/poet.song.160000.json','["艾之西兮汨之原，山石劃斷兮穹巔而嶄巖。", "瀑流下注兮，其上絕而爲亹。", "有蛟有龍兮，伏而不怒。", "雷鳴崖下兮，窮年風雨。", "誰斧鑿此雲根兮，遺予以罍洗。", "松有樛枝兮，屋之深深。", "苔蘚斑斕兮，織繢以爲茵。", "觴酒于上兮聽潺湲。", "西峰銜日半規兮，徘徊猶未忍旋。", "予欲縆朱絲兮，節清音而度曲。", "招玄鶴使舞兮，醉予醽醁。", "有玉韞櫝兮幽人之軸，秋蘭之珮兮芙蓉之服。", "瘦石寒泉兮矢其弗告，四墉無隙兮巘崿青青。", "白雲漠漠兮截洞口以爲扃，輪鞅莫來兮無傷我清。", "不執券而兼并兮莫予與爭。"]'),
('2c4e6a80-aece-4e0e-b9cf-18401021f883','懷忠堂辭','王炎','宋','宋诗','song-poetry','','[]','跂逸駕兮前修，佩武符兮典州。',216,'全唐诗/poet.song.160000.json','["跂逸駕兮前修，佩武符兮典州。", "迹已陳兮德新，可敬而慕兮幾春復秋。", "意其存兮閟千萬年之原，謂其逝兮乃在浮羅之顛。", "奮忠精兮取義，貫羲娥兮爛然。", "隘塵寰兮上征，揮八極兮爲仙。", "黄鵠脫驂兮素虯停駟，幾弭節兮念遺民而來顧。", "高弁蒼蒼兮清苕瀰瀰，公來遊兮湖山增美。", "遊觀罷兮來歸。", "有蒲與荷兮清泠之池，魚鳥懷生兮欣欣焉。", "其有依銀鈎蠆尾兮，燦翠珉而陸離。", "絃琴兮擊鼓，羞羔豚兮酌醑。", "跪起以薦兮願公燕喜。", "公燕喜兮吾民樂康。", "却災沴兮蠲除不祥。", "雲來兮萬祀，烝嘗兮不忘。"]'),
('eeedde34-dc22-4dab-afa7-337566853462','太廟瑞芝頌','王炎','宋','宋诗','song-poetry','','[]','宋紹天命，列聖重光。',240,'全唐诗/poet.song.160000.json','["宋紹天命，列聖重光。", "丕緒舄奕，施于無疆。", "少海日升，慶元五祀。", "淵默面南，格于天地。", "於穆清廟，玉芝呈瑞。", "蔓蔓其華，麗于丹楹。", "匪根斯殖，匪葩斯榮。", "和氣融液，不春而生。", "其瑞維何，祖宗咸喜。", "神孫致孝，孺慕無已。", "有開必先，産祥隤祉。", "其孝維何，神明可通。", "問安寢門，四輔翼從。", "洗爵爲壽，雍雍在宮。", "莫大之慶，朝野攸同。", "賚爾高年，曰予錫類。", "頒爵輔臣，曰汝予助。", "三宮豈樂，萬姓歌舞。", "維我高廟，中興集勳。", "神器所傳，藝祖之孫。", "重華之斷，壽康之仁。", "凝神沖漠，不俟倦勤。", "羣黎屬望，天啟元子。", "四聖揖遜，千古顓美。"]'),
('e5634cae-8e9b-4106-bf96-db3bf414d2f2','明妃曲','王炎','宋','宋诗','song-poetry','','[]','掖庭國色世所稀，不意君王初未知。',160,'全唐诗/poet.song.160000.json','["掖庭國色世所稀，不意君王初未知。", "欲行未行始驚惋，畫史乃以妍爲媸。", "約言已定不可悔，氈車萬里隨單于。", "天生胡漢族類異，古無漢女爲胡姬。", "高皇兵敗白登下，歸遣帝子稱閼氏。", "欲平兩國恃一女，烏乎此計何其疎。", "至今和親踵故事，延壽欺君何罪爲。", "此生失意甘遠去，此心戀舊終懷歸。", "胡天慘淡氣候別，風沙四面吹穹廬。", "琵琶曲盡望漢月，塞鴈年年南向飛。"]'),
('a9240083-0d1d-4532-bfa8-d1a5e86dd13f','公無渡河','王炎','宋','宋诗','song-poetry','','[]','黄河浩浩不可航，腰壺欲渡何其狂。',88,'全唐诗/poet.song.160000.json','["黄河浩浩不可航，腰壺欲渡何其狂。", "嫗挽翁衣願無渡，忠愛深言反逢怒。", "河流滔滔翁溺死，老嫗搏膺淚如雨。", "行人勸嫗莫痛傷，痛傷之極能斷腸。", "古來愎諫多不祥，鴟夷浮江吳國滅，老臣疽背霸王歇。"]'),
('53022f49-8c50-4d21-8024-96687a694e08','雉朝飛','王炎','宋','宋诗','song-poetry','','[]','飛飛野雉雄挾雌，相與孳尾爲之妃。',96,'全唐诗/poet.song.160000.json','["飛飛野雉雄挾雌，相與孳尾爲之妃。", "人生誰不有配偶，我生垂老爲鰥夫。", "永巷蛾眉幾千指，一妻一妾庶人禮。", "壯年受室不及時，老去自憐身獨處。", "短布單衣誰爲縫，東臯種黍誰共舂。", "蒼天高高不可問，願照衡茅有孤悶。"]'),
('0bbf73d3-b6b2-4063-98df-6df8c9734919','關山月','王炎','宋','宋诗','song-poetry','','[]','陰山蕭蕭木葉黄，胡兒馬健弓力强。',96,'全唐诗/poet.song.160000.json','["陰山蕭蕭木葉黄，胡兒馬健弓力强。", "鐵衣萬騎向北去，仰看鴻鴈皆南翔。", "身在邊頭家萬里，嗚咽悲笳壯心死。", "功成歸取漢爵侯，戰敗沒爲邊地鬼。", "團團霜月懸中天，閨中少婦私自憐。", "捐軀許國丈夫事，莫恨不如霜月圓。"]'),
('68b362e6-bfd9-4d8f-a2d2-b296cbfd9599','白頭吟','王炎','宋','宋诗','song-poetry','','[]','青絲織作雙鴛鴦，紫絲繡成雙鳳凰。',160,'全唐诗/poet.song.160000.json','["青絲織作雙鴛鴦，紫絲繡成雙鳳凰。", "在家不敢窺屏著，心願出門逐夫壻。", "琴中解道人心事，不辭半夜將身去。", "君親滌器妾當壚，豈料賦成天上知。", "臨邛舊事不記省，千金多買青蛾眉。", "嫁時衣裳今尚在，妾貌未衰君意改。", "當時去家恨太遲，今日思家翻自悔。", "玉環既斷不復連，青銅既破不復圓。", "古來佳人多薄命，不見鸞膠能續絃。", "但願新人同燕婉，桃花長春月長滿。"]'),
('e45bec42-5c67-4370-9c91-b61ed3a523b1','飲馬長城窟','王炎','宋','宋诗','song-poetry','','[]','春風塞草青，胡兒區脫靜。',96,'全唐诗/poet.song.160000.json','["春風塞草青，胡兒區脫靜。", "秋風塞草黄，胡騎角弓勁。", "秦人驅丁夫，築城備强胡。", "城成有虧日，胡來無已時。", "哀笳中夜起，戰馬豎雙耳。", "蒼茫沙上月，幽咽隴頭水。", "征人悲故鄉，閨人守空房。", "安得霍嫖姚，飲馬瀚海旁。"]'),
('ac4a994c-1536-4439-a717-353ad8ca58d4','門有車馬客','王炎','宋','宋诗','song-poetry','','[]','烏鵲遶屋鳴，有客停騑。',119,'全唐诗/poet.song.160000.json','["烏鵲遶屋鳴，有客停騑。", "問客何自來，君家寄家書。", "攝衣起迎客，開書多苦辭。", "蕣花不長好，玉顔亦易衰。", "水行有却流，人行無反期。", "置書拜謝客，豈不心懷歸。", "事君有明義，不得顧所私。", "作書附客返，路遠幸勿遺。", "上言重自愛，下言長相思。", "相思勿相怨，自古多別離。"]'),
('739eb58e-27b6-4333-9544-7503f634e8f6','出塞曲','王炎','宋','宋诗','song-poetry','','[]','羽檄走邊遽，虎符出精兵。',96,'全唐诗/poet.song.160000.json','["羽檄走邊遽，虎符出精兵。", "壯士卷甲起，骨肉送之行。", "擊筑歌易悲，挈榼酒更傾。", "關山殺氣纏，寒日無晶明。", "箭落紫塞鵰，馬裂黄河冰。", "豈畏虜騎多，只憂將權輕。", "閫外不中制，一賢當長城。", "鼓行渡沙磧，願勒燕然銘。"]'),
('b6e34859-47c2-4f04-be54-ae33a474962d','遠別離','王炎','宋','宋诗','song-poetry','','[]','靜女不下堂，游子志四方。',124,'全唐诗/poet.song.160000.json','["靜女不下堂，游子志四方。", "五花驕馬金絡腦，出門僕從生輝光。", "草青沙軟濕春霧，玉蹄聯翩踏花去。", "樓頭明月闕又圓，西風一夕生庭樹。", "明璫綴以木難珠，錦衣繫以貂襜褕。", "青眉玉頰爲誰好，天闊飛鴻無素書。", "今年花落容華在，明年花發容華改。", "離鸞別鵠不自憐，人生難得長少年。"]'),
('d6035834-8c5c-4cd2-a05a-bad9c69874ba','擬古閨怨三首  其一','王炎','宋','宋诗','song-poetry','','[]','爲郎縫春衣，春盡郎未歸。',24,'全唐诗/poet.song.160000.json','["爲郎縫春衣，春盡郎未歸。", "羞見庭下花，一雙胡蝶飛。"]'),
('481ae5c4-c7b8-4cd8-8b4d-d862476f41a6','擬古閨怨三首  其二','王炎','宋','宋诗','song-poetry','','[]','良人久在外，想像裁香羅。',24,'全唐诗/poet.song.160000.json','["良人久在外，想像裁香羅。", "放下金粟尺，無言顰翠蛾。"]'),
('2f77f579-8760-42e4-b0c2-9623033d9ff5','擬古閨怨三首  其三','王炎','宋','宋诗','song-poetry','','[]','花開復花謝，墮在藩溷邊。',24,'全唐诗/poet.song.160000.json','["花開復花謝，墮在藩溷邊。", "不惜花落盡，惜無長少年。"]'),
('a8ecbbb4-f6f1-4a9b-a2ec-81bc610e41c9','粧樓怨','王炎','宋','宋诗','song-poetry','','[]','長安甲第凝丹碧，門外如雲珠履客。',128,'全唐诗/poet.song.160000.json','["長安甲第凝丹碧，門外如雲珠履客。", "主人對客懶將迎，別有洞天雙國色。", "簾幃不動春風香，乃翁但醉流霞觴。", "綠絲垂地細君惜，從今可老溫柔鄉。", "歡樂短，憂恨長，鳳飛何在遺其凰。", "不言不笑念恩怨，明月無情窺象牀。", "春暖花枝啼曉露，此身今是花無主。", "可憐高塚卧麒麟，不許畫樓棲燕子。"]'),
('946b3664-b2a9-490f-a0f8-0a288e5e1b80','薄薄酒','王炎','宋','宋诗','song-poetry','','[]','薄酒可成禮，何必飲上尊。',294,'全唐诗/poet.song.160000.json','["薄酒可成禮，何必飲上尊。", "醜婦可成室，何必求麗人。", "人生有欲皆求得，誰能有得終無失。", "多藏未免誨穿窬，厚味亦能生疢疾。", "青鞋緩步可當車，不用駟馬黄金覊。", "茅簷之下庇風雨，不用丹碧文榱題。", "縕袍布衾亦自暖，不用狐裘蒙錦衣。", "菜羹脫粟亦自飽，不用五鼎羞鮮肥。", "月盈不償闕，物盛必有衰。", "逐客可相亦可夷，餓隸爲王又爲菹。", "欲從意滿神所忌，吉凶反覆相乘除。", "吾聞猩猩駡人非不智，以醉就禽猶惜屨。", "黿鼉窟穴深更深，卒爲人得由貪餌。", "古來達識照其幾，外物視之雙弊屣。", "於陵辭聘寧灌畦，禦寇辭粟寧忍饑。", "逃榮無辱二疏去，今是昨非陶令歸。", "請君莫嫌薄酒薄，瓦甕匏尊任斟酌。", "請君莫嫌醜婦醜，荆釵布襦與偕老。", "天寬地大得自由，如此足矣何多求。"]'),
('6a5f1859-1fd0-4f9c-9c44-d91982587cc3','夏日雨過','王炎','宋','宋诗','song-poetry','','[]','雲潤日杲杲，渠澀泉泠泠。',132,'全唐诗/poet.song.160000.json','["雲潤日杲杲，渠澀泉泠泠。", "羣山曉過雨，一沐千髻青。", "岸巾納微凉，庭戶留餘清。", "喬木俯佳色，野卉含幽馨。", "昔來挽枯條，今來見欣榮。", "榮枯亦何有，對此難爲情。", "長年心事多，撫髀只自驚。", "冰炭交中腸，吾生安得寧。", "好風吹我裳，頗覺耳目醒。", "暇日可少憇，安用心營營。", "高卧綠陰底，玄蟬相對鳴。"]'),
('30e4b8c9-d857-407f-9d4c-d12817128022','村行','王炎','宋','宋诗','song-poetry','','[]','青山護村落，暗水通溝渠。',108,'全唐诗/poet.song.160000.json','["青山護村落，暗水通溝渠。", "人行禾黍間，漫漫迷所之。", "里社壓新醪，擊鮮賽叢祠。", "田父相勞苦，雨暘無失時。", "龍骨挂屋敖，秋熟可預期。", "行行度岡澗，泉石多幽奇。", "微風發清籟，好鳥吟高枝。", "此中有佳趣，豈無幽人知。", "去住兩不可，空吟招隠詩。"]'),
('d84505bd-7862-41fd-abf6-d70e6ca22268','雪晴即事','王炎','宋','宋诗','song-poetry','','[]','宵爨懸釜星，曉光落窗牖。',108,'全唐诗/poet.song.160000.json','["宵爨懸釜星，曉光落窗牖。", "烏鵲如諂人，賀語亦交口。", "收書白氍毹，青山併還舊。", "門巷未掃除，家童具箕帚。", "物色不招挽，顧盼左右有。", "梅兄可納交，竹弟亦耐久。", "毛錐得奇助，引我琢句手。", "酒國百無憂，問津其敢後。", "逐逐春意來，孤村又花柳。"]'),
('f6376291-e312-465c-aa3b-73408984dfa4','呂待制所居八詠 半隠','王炎','宋','宋诗','song-poetry','','[]','舉世競寵利，嗜進無肯休。',120,'全唐诗/poet.song.160000.json','["舉世競寵利，嗜進無肯休。", "山林槁項輩，又乏經濟謀。", "朅來半隠寮，再拜瞻呂侯。", "袖手辭富貴，結廬清且幽。", "我從爲兒時，久矣聞風流。", "父老數時賢，若人真少儔。", "已覆金甌名，姑作綠野遊。", "四海望霖雨，爭欲挽之留。", "向來釣璜老，一出扶宗周。", "廊廟方側席，公肯幡然不。"]'),
('ebacedab-0a65-4eb4-8cc7-b6f1df19fef1','呂待制所居八詠 舒嘯','王炎','宋','宋诗','song-poetry','','[]','黄山峙立高崔嵬，上有飛仙時往來。',96,'全唐诗/poet.song.160000.json','["黄山峙立高崔嵬，上有飛仙時往來。", "問之誰作東道主，舒嘯亭中人姓回。", "坐對危峰倒樽酒，偃仰胡床篆烟吐。", "劃然清響透雲端，此意悠悠眇千古。", "好是夜深孤月明，風松泉石清更清。", "我來擬作叔夜輩，一聽空山鸞鳳聲。"]'),
('ea5b5f6e-0480-4a4f-8ffc-b166355fcf7f','呂待制所居八詠 緩步','王炎','宋','宋诗','song-poetry','','[]','躍馬乘軒四十年，誰知公是地行仙。',64,'全唐诗/poet.song.160000.json','["躍馬乘軒四十年，誰知公是地行仙。", "向來曳履星辰上，今作遊山杖屨緣。", "總爲鼻端清栩栩，能令脚底步翩翩。", "青鞋若許陪行樂，早晚誅茅半隠邊。"]'),
('c956b152-2c6d-430f-99d6-f4a6530808e0','呂待制所居八詠 月臺','王炎','宋','宋诗','song-poetry','','[]','我欲登仙換凡骨，飛上雲頭窺月窟。',64,'全唐诗/poet.song.160000.json','["我欲登仙換凡骨，飛上雲頭窺月窟。", "羿妻問我何自來，笑指廣寒令徑入。", "歸來却見半隠翁，月臺如在神仙中。", "霓裳歌舞不用覷，把酒長嘯生清風。"]'),
('cb1aa9ab-34a4-4583-8e17-6dbcd0f6d511','呂待制所居八詠 藤洞','王炎','宋','宋诗','song-poetry','','[]','空中一洞足清風，上有長藤翠蔓穠。',32,'全唐诗/poet.song.160000.json','["空中一洞足清風，上有長藤翠蔓穠。", "說與山靈護持取，蒼皮瘦骨恐爲龍。"]'),
('c1a012fb-a474-4453-8b78-504cc37d3f2e','呂待制所居八詠 歲寒','王炎','宋','宋诗','song-poetry','','[]','春陽競嫵媚，百卉顔色好。',72,'全唐诗/poet.song.160000.json','["春陽競嫵媚，百卉顔色好。", "凉秋風露來，往往競枯槁。", "一朝受霜雪，脫落遽如掃。", "特立金石姿，青青未嘗老。", "下視軟美輩，摧折不自保。", "古人幾失言，疾風知勁草。"]'),
('e954f1bf-36c6-4afc-9881-404afaaaac49','呂待制所居八詠 朝陽','王炎','宋','宋诗','song-poetry','','[]','腷膊雞聲夜向晨，東方飛景到雲林。',64,'全唐诗/poet.song.160000.json','["腷膊雞聲夜向晨，東方飛景到雲林。", "簾幃已是曈曈曉，庭戶全無曀曀陰。", "可是梧桐長得地，也知葵藿久傾心。", "日邊早晚來環賜，見說清光注意深。"]'),
('531be98a-c598-4225-b47f-567c3e8c3dfd','呂待制所居八詠 醉松','王炎','宋','宋诗','song-poetry','','[]','虬髯鐵榦老嶙峋，氣格儼然冠劍臣。',64,'全唐诗/poet.song.160000.json','["虬髯鐵榦老嶙峋，氣格儼然冠劍臣。", "應爲孤高多絕物，未妨偃蹇且全身。", "雪中屈折如頹玉，雨後淋漓又吐茵。", "撫手摩挲三嘆息，世間那有獨醒人。"]'),
('b7951d51-fc92-43d2-b4cd-df785020fa6c','太平道中遇流民','王炎','宋','宋诗','song-poetry','','[]','丁男負荷力已疲，弱妻稚子顔色悲。',128,'全唐诗/poet.song.160000.json','["丁男負荷力已疲，弱妻稚子顔色悲。", "親戚墳墓誰忍棄，嗟爾豈願爲流移。", "春蠶成繭穀成穗，輸入豪家無孑遺。", "豐年凜凜不自保，凶年菜色將何如。", "但憂銜恨委溝壑，豈暇懷土安室廬。", "故鄉既已不可居，他鄉爲客將誰依。", "黄雞啄黍白酒熟，去家未久吾懷歸。", "農桑不事得溫飽，見爾令人顔忸怩。"]'),
('b4a4eb86-ce8e-411e-9428-88909010d022','遊硯山','王炎','宋','宋诗','song-poetry','','[]','他山石徒多，器寶匿幽僻。',240,'全唐诗/poet.song.160000.json','["他山石徒多，器寶匿幽僻。", "産璞芙蓉坑，金聲而玉德。", "岡巒外鈎聯，地勢中斷隔。", "曲塢八九家，路入羊豕迹。", "澗水抱石根，石骨多紺碧。", "北山上攙天，南山勢蟠伏。", "硯工二百指，日鑿崔嵬腹。", "篝燈礪斧斤，深入逾百尺。", "我行冒風雨，周覽不知夕。", "夜宿茅茨下，青燈照岑寂。", "酒闌呼匠氏，訪之語纖悉。", "冰蠶吐銀絲，鮫人織霧縠。", "巧手琢磨之，價直黄金鎰。", "斷巖半傾欹，舊穴久湮塞。", "旁求得他材，飲水不受墨。", "堅滑已支庶，粗燥乃臧獲。", "信知天壤間，尤物神所惜。", "罕見固爲貴，有亦未易識。", "珉玉混一區，語盡三嘆息。", "摩挲蒼蘚崖，此言可鎸刻。"]'),
('86996e23-a446-4a5a-ae56-c0ca2683fcef','山間偶成二絕  其一','王炎','宋','宋诗','song-poetry','','[]','人家雞犬近相聞，村落紆回古木深。',32,'全唐诗/poet.song.160000.json','["人家雞犬近相聞，村落紆回古木深。", "山客一來塵想盡，水聲終日奏鳴琴。"]'),
('b481f516-6b82-4148-86b5-1c7beaa59cb3','山間偶成二絕  其二','王炎','宋','宋诗','song-poetry','','[]','隔枝啼鳥喚幽夢，排闥青山無世情。',32,'全唐诗/poet.song.160000.json','["隔枝啼鳥喚幽夢，排闥青山無世情。", "綠樹陰陰遮日影，虛窗卧看白雲行。"]'),
('cdc02209-b229-4080-b3ab-f32a2c932a56','雪中懷韓毅伯','王炎','宋','宋诗','song-poetry','','[]','雞罷三號來曉色，披衣起見瓦溝白。',64,'全唐诗/poet.song.160000.json','["雞罷三號來曉色，披衣起見瓦溝白。", "雪花初墮雲遽回，天意應憐未歸客。", "男兒鐵石爲剛腸，忍窮不見可憐色。", "當知曳履郭先生，可作餐氈蘇屬國。"]'),
('eef7fc65-69ab-4031-b1f3-b85097bfc65e','和韓毅伯詠鴈','王炎','宋','宋诗','song-poetry','','[]','孤飛欲作上林遊，塞北來時天始秋。',64,'全唐诗/poet.song.160000.json','["孤飛欲作上林遊，塞北來時天始秋。", "世路豈無矰繳慮，水鄉聊作稻粱謀。", "摩雲不憚關山遠，刷羽定非雞鶩儔。", "待看草青烟浪暖，带將春色離南州。"]'),
('96f6a1cf-6d72-4c1f-8665-ae567c136470','梅花','王炎','宋','宋诗','song-poetry','','[]','歲暮殺氣慘，草木華葉萎。',72,'全唐诗/poet.song.160000.json','["歲暮殺氣慘，草木華葉萎。", "寒梅吐新萼，娟娟擁疏枝。", "清意塵俗遠，幽香風露知。", "孤絕慣守獨，晚出甘後時。", "細推萬物理，榮謝相乘除。", "桃李向來繁，試問今何如。"]'),
('654a490c-e13b-4f12-9a22-0827625a1cf2','犬捕鼠','王炎','宋','宋诗','song-poetry','','[]','黠鼠穴居工匿形，宵竊吾餘頻有聲。',96,'全唐诗/poet.song.160000.json','["黠鼠穴居工匿形，宵竊吾餘頻有聲。", "狸奴已老無足忌，對面侮人渠得志。", "韓盧千載雲來孫，平時禦盜嚴司存。", "小施逐兔騰山力，不露爪牙潜有獲。", "主人高枕終夜安，論功法吏能掃姦。", "繩以漢家三尺律，鼠罪貫盈貓不職。"]'),
('d3e45bea-62ca-4937-94e3-f9d8c4ea7bbd','春日','王炎','宋','宋诗','song-poetry','','[]','小凭笋輿行野田，麥芒桑蕾春無邊。',80,'全唐诗/poet.song.160000.json','["小凭笋輿行野田，麥芒桑蕾春無邊。", "勒回風物未全好，小雨班班天護寒。", "入門烏鵲枝頭語，鴻鴈好音慈母喜。", "車馬不來門巷窮，桃花自作深深紅。", "世間萬事易冰冷，春來無處無東風。"]'),
('191f544d-2eb7-4295-90b6-025ddf5d7497','春日書懷二首  其一','王炎','宋','宋诗','song-poetry','','[]','杜門值春初，出門已春莫。',72,'全唐诗/poet.song.160000.json','["杜門值春初，出門已春莫。", "子規日夜啼，爲我訴春去。", "萋然草彌望，綠暗谿臯路。", "百尺游絲高，摇摇引心緒。", "歸來坐窗底，有句不能吐。", "喚取黄嬭來，且嘗黑甜味。"]'),
('4f15034f-9567-4fb4-8965-c8565cbad21c','春日書懷二首  其二','王炎','宋','宋诗','song-poetry','','[]','餘月雨新歇，風日亦已和。',72,'全唐诗/poet.song.160000.json','["餘月雨新歇，風日亦已和。", "佳木頗秀整，好鳥仍嘯歌。", "今我苦不樂，如此春意何。", "喧寂有異境，窮達元同科。", "此道貴堅壁，外物將倒戈。", "有慨懷古人，執柯能伐柯。"]'),
('a2a5e707-cf89-4427-b20c-511c273ddbc8','答韓毅伯五首  其一','王炎','宋','宋诗','song-poetry','','[]','爲別未一日，思君如三秋。',96,'全唐诗/poet.song.160000.json','["爲別未一日，思君如三秋。", "解后孤城中，握手復少留。", "士方未遇時，鮮不困宦游。", "君獨芻豢色，胸次回萬牛。", "自愧得之淺，誤欲代君憂。", "白璧識者稀，駑馬市者稠。", "莫作分外慮，輕重終不侔。", "諸公競推轂，失士固所羞。"]'),
('6bbe3c71-a982-40a0-8bf4-56f12bffb535','答韓毅伯五首  其二','王炎','宋','宋诗','song-poetry','','[]','情義如投膠，去意如激矢。',60,'全唐诗/poet.song.160000.json','["情義如投膠，去意如激矢。", "險阻要備嘗，山川餞行李。", "霜雪衣裘單，燈前話兒女。", "下堂辭親去，上堂拜親喜。", "燕頷能飛揚，何必毛錐子。"]'),
('f25fa499-de6e-4ee2-8d87-3724eca92d8c','答韓毅伯五首  其三','王炎','宋','宋诗','song-poetry','','[]','憶君初至時，投宿村店莫。',72,'全唐诗/poet.song.160000.json','["憶君初至時，投宿村店莫。", "門巷冷如冰，漫刺來一顧。", "升堂方下榻，出戶復就屨。", "綈袍寒不溫，北風攪庭戶。", "念君何以堪，此意推不去。", "强飯登前塗，爲親善調護。"]'),
('a5947f2c-0a02-4ca4-87da-210a962b6077','答韓毅伯五首  其四','王炎','宋','宋诗','song-poetry','','[]','老松寒不凋，古井風無波。',48,'全唐诗/poet.song.160000.json','["老松寒不凋，古井風無波。", "斯人閲千古，所得亦已多。", "句法餘事爾，高處凌陰何。", "寧爲擁膝吟，無作扣角歌。"]'),
('353b5f70-7edf-4e6a-82f0-e4a96924293b','答韓毅伯五首  其五','王炎','宋','宋诗','song-poetry','','[]','三書上時宰，我常疑退之。',84,'全唐诗/poet.song.160000.json','["三書上時宰，我常疑退之。", "士窮見素守，躁求亦何爲。", "蜀客聞此語，爲我一解頤。", "歲晚歸未得，且過江之西。", "未到意先喜，主人賢足依。", "江西魚稻鄉，米熟蟹螯肥。", "不妨且醉飽，利達自有時。"]'),
('632d5847-59cc-4f35-bc5a-7dd9a82abc9e','漁人','王炎','宋','宋诗','song-poetry','','[]','西南月未墮，白霧吞青山。',48,'全唐诗/poet.song.160000.json','["西南月未墮，白霧吞青山。", "渡口無人行，老漁一舟還。", "呵手繫短纜，襏襫犯夜寒。", "捕魚養妻子，誰謂斯人閒。"]'),
('b84e4a60-b341-4ff8-b235-aca576cbbdcd','促織','王炎','宋','宋诗','song-poetry','','[]','春山布穀勸耕事，秋園絡緯催機杼。',64,'全唐诗/poet.song.160000.json','["春山布穀勸耕事，秋園絡緯催機杼。", "大家未織吏索租，小家欲織無絲縷。", "無絲可織寒無衣，輸租後期罪當笞。", "悲鳴終夜不能已，嗟爾候蟲何自苦。"]'),
('363e2d72-9028-499b-b78d-4b1e38b1682d','大水行','王炎','宋','宋诗','song-poetry','','[]','屯雲墨色日將暮，晦明揮霍雨如注。',395,'全唐诗/poet.song.160000.json','["屯雲墨色日將暮，晦明揮霍雨如注。", "水聲夜半摇匡床，平旦出門吁可畏。", "盤渦溔瀁吞邊旁，悍流洶湧行中央。", "日中雨復綆縻下，溝塍水躍皆渾黄。", "黑風拗怒雷擊地，浪頭起立三丈强。", "杈枒老木根株拔，崚嶒古屋椽桷裂。", "快馬萬蹄迸突而憑凌，靈鼉百面澒洞而砯砰。", "銳兵鏖戰城柵倒，猛虎嘷吼崖谷崩。", "旁觀氣奪目力眩，瀕流上下俱不寧。", "升高辟害叫舟楫，篙工倚柂不敢行。", "寂寥向晚頗衰落，斷霞返照回新晴。", "鳥飛不盡天界闊，蒼烟淡淡山青青。", "銜杯引滿幸無恙，收召魂魄猶屏營。", "往年秋水沈半壁，闔門九死得一生。", "今日思之痛方定，一見洪波心震驚。", "吾聞山挾河回衝底柱，峽束江盤投灧澦。", "魚龍百怪家其中，風濤暴橫無終窮。", "小溪常時清且淺，漪漣不動平於板。", "淺津可涉深可梁，一旦沸騰能漭茫。", "傳聞潰渱山裂破，黑蛟夜出作奇禍。", "抉崖走石勢力粗，十家六七無室廬。", "百年枯塚尚漂泊，變生倉卒人爲魚。", "君不見去年四月不雨至七月，澗谿一綫皆斷絕。", "川居人曾死於暍，山居人今死於溺。"]'),
('0d0b469e-dc21-4502-baf0-7d0b8992963f','冬日即事','王炎','宋','宋诗','song-poetry','','[]','曝背茅簷下，驅寒得曉晴。',48,'全唐诗/poet.song.160000.json','["曝背茅簷下，驅寒得曉晴。", "杜門來客少，開卷此心清。", "晦迹存吾道，端居閲世情。", "南山無改色，相對免將迎。"]'),
('9b1e9c77-9721-4fd1-9db7-44bb8b8534e1','春興二首  其一','王炎','宋','宋诗','song-poetry','','[]','蔓長宜誅草，花飛可弔梅。',48,'全唐诗/poet.song.160000.json','["蔓長宜誅草，花飛可弔梅。", "斷雲將雨去，啼鳥喚春回。", "書亂時開帙，樽空久覆杯。", "長年觀景物，不復起衰懷。"]'),
('5694364c-734b-4ab4-a205-2f788888a068','春興二首  其二','王炎','宋','宋诗','song-poetry','','[]','山遠煙蒙樹，汀回水嚙沙。',48,'全唐诗/poet.song.160000.json','["山遠煙蒙樹，汀回水嚙沙。", "雲陰初解駁，春色已光華。", "土潤麥爭秀，日蒸桃欲花。", "杜門無可喜，鵲語誤楂楂。"]'),
('b51a19fb-d6e9-4f23-b467-63cc7e54af85','旅興','王炎','宋','宋诗','song-poetry','','[]','白眼看時事，剛腸厭俗流。',48,'全唐诗/poet.song.160000.json','["白眼看時事，剛腸厭俗流。", "也知蜂有毒，未信鼠堪投。", "熟睡消磨日，清吟撥置愁。", "倚門應望切，早晚賦刀頭。"]'),
('22b54fb4-82e3-4ebc-96e5-263c8e5158eb','蔬食','王炎','宋','宋诗','song-poetry','','[]','瓠白吾何有，人言太瘦生。',48,'全唐诗/poet.song.160000.json','["瓠白吾何有，人言太瘦生。", "富兒皆肉食，我輩但藜羹。", "安得萬錢費，應無五鼎烹。", "饑腸雷欲吼，一飽亦何營。"]'),
('a74cda6a-4330-4c67-9e06-3cd1a094c5cc','春雨','王炎','宋','宋诗','song-poetry','','[]','喚雨蒼鳩罷，山高雲更隮。',48,'全唐诗/poet.song.160000.json','["喚雨蒼鳩罷，山高雲更隮。", "泥深妨著屣，水足有扶犁。", "索酒無同飲，哦詩只自題。", "小窗回午夢，鄰舍一聲雞。"]'),
('d22a04dd-bdc7-438d-a8ee-f834cc1b3891','石盆荷葉','王炎','宋','宋诗','song-poetry','','[]','月明露冷浄娟娟，收入窗間一掬泉。',64,'全唐诗/poet.song.160000.json','["月明露冷浄娟娟，收入窗間一掬泉。", "不用亭亭張翠蓋，也能細細疊青錢。", "時因新汲分瓶杓，暗有微香散簡編。", "留待移根栽玉井，開花十丈藕如船。"]'),
('01ab8c60-66c9-46de-9cc2-fae4f6e15476','窗外紫竹','王炎','宋','宋诗','song-poetry','','[]','疎籬短柵外鈎聯，聚立龍孫已嶷然。',64,'全唐诗/poet.song.160000.json','["疎籬短柵外鈎聯，聚立龍孫已嶷然。", "向日斧斤幾不赦，而今苗裔尚能全。", "少時秀色青珉潤，歲晚英標紫玉堅。", "借與風煙扶直氣，稍加歲月定參天。"]'),
('d8e6408e-cce8-4b2b-9e08-01791a04ba5d','秋日晚晴','王炎','宋','宋诗','song-poetry','','[]','斷霞縷脈淺深紅，雨挾凉來助好風。',64,'全唐诗/poet.song.160000.json','["斷霞縷脈淺深紅，雨挾凉來助好風。", "心厭亂蟬專美蔭，目隨高鳥度晴空。", "此身尚落功名外，生理方侵念慮中。", "坐到夜深明月上，秋聲故故遶梧桐。"]'),
('388e791e-0d9e-49b0-90f2-9e116bf26613','和毅伯見寄','王炎','宋','宋诗','song-poetry','','[]','欲問故人歸未歸，江湖不見雁南飛。',64,'全唐诗/poet.song.160000.json','["欲問故人歸未歸，江湖不見雁南飛。", "青雲未上辭鄉國，白璧無因困褐衣。", "客裏書來行李滯，江南春盡落花稀。", "倚門望斷山川遠，我却疑君此策非。"]'),
('788e2205-0849-41ff-bcd4-eedf938f340b','喜祝季通相訪','王炎','宋','宋诗','song-poetry','','[]','一笑掀髯語不休，隻雞斗酒少淹留。',64,'全唐诗/poet.song.160000.json','["一笑掀髯語不休，隻雞斗酒少淹留。", "讀書未療一身困，彈劍同懷千歲憂。", "喬木擁煙村落冷，西風吹雨稻粱秋。", "此中可覓離騷句，躍馬重來谿上頭。"]'),
('7007a3f1-2d43-4ce3-af0e-7c7d8b33dd06','和祝季通韻','王炎','宋','宋诗','song-poetry','','[]','踏破蒼苔馬有聲，百金一諾不寒盟。',64,'全唐诗/poet.song.160000.json','["踏破蒼苔馬有聲，百金一諾不寒盟。", "揮犀議論高流輩，落筆典刑追老成。", "犯雪方知松節直，截河不變濟流清。", "論交獨許吾同調，翻覆從渠自世情。"]'),
('f07ab5bd-7b25-4053-b16f-58b93b5db737','南齋中秋小酌','王炎','宋','宋诗','song-poetry','','[]','銀河絡角晚風凉，月入庭除滿地霜。',64,'全唐诗/poet.song.160000.json','["銀河絡角晚風凉，月入庭除滿地霜。", "夜靜老翁閒玉斧，天寒仙子舞霓裳。", "田家旋斸蹲鴟美，野店新篘綠蟻香。", "草草杯盤供一笑，暫時耳熱發清狂。"]'),
('b4b1aac3-555c-41af-b7bf-595dc60debfa','南齋書懷','王炎','宋','宋诗','song-poetry','','[]','幽居用拙懶追尋，小徑無人苔半侵。',64,'全唐诗/poet.song.160000.json','["幽居用拙懶追尋，小徑無人苔半侵。", "燕子已歸知社近，桃花半破覺春深。", "長編短簡資身策，故歲新年念母心。", "拂拭橫床眠未穩，匆匆屋角有鳴禽。"]'),
('8f8c0521-9b47-47fb-a4bf-40a9e4d6f5cf','和韓毅伯韻三首  其一','王炎','宋','宋诗','song-poetry','','[]','鵲寄先聲到敝廬，故人回首意何如。',64,'全唐诗/poet.song.160000.json','["鵲寄先聲到敝廬，故人回首意何如。", "我方無事能高枕，子亦徐行可當車。", "小甕牀頭新注酒，青燈窗下靜觀書。", "虀鹽冷淡商今古，恐勝朱門食有魚。"]'),
('1e0754a8-e0bd-4268-82cc-226196da4d16','和韓毅伯韻三首  其二','王炎','宋','宋诗','song-poetry','','[]','有客回車肯再過，天寒冰雪滿關河。',64,'全唐诗/poet.song.160000.json','["有客回車肯再過，天寒冰雪滿關河。", "家貧草具惟雞黍，地僻柴門但雀羅。", "人固剛腸窮已甚，天無老眼命如何。", "男兒自許功名事，相對肯悲彈劍歌。"]'),
('4aef026d-3323-44ca-af09-b6c652195af5','和韓毅伯韻三首  其三','王炎','宋','宋诗','song-poetry','','[]','萬里乾坤尚側身，諸公青眼拂埃塵。',64,'全唐诗/poet.song.160000.json','["萬里乾坤尚側身，諸公青眼拂埃塵。", "平生毛穎義相許，今日方兄情稍親。", "信有朱絃能使鬼，肯將拱璧暗投人。", "不妨歲晚留行色，梅柳梢頭已報春。"]'),
('74a67890-edfc-4487-b6b7-1a6094295729','再和前韻三首  其一','王炎','宋','宋诗','song-poetry','','[]','扣關剝啄到吾廬，覺我論才有不如。',64,'全唐诗/poet.song.160000.json','["扣關剝啄到吾廬，覺我論才有不如。", "道在褐衣懷美玉，文成熟路駕輕車。", "而今談笑不携手，他日寒溫徒寄書。", "勢利之交兒輩事，何須有客佩金魚。"]'),
('3d39950f-16bb-4a0e-a9a2-9601afa1b09b','再和前韻三首  其二','王炎','宋','宋诗','song-poetry','','[]','窮巷曾勤特地過，瀾翻舌本落懸河。',64,'全唐诗/poet.song.160000.json','["窮巷曾勤特地過，瀾翻舌本落懸河。", "君方迹未離塵土，我亦身嘗墮網羅。", "幸有吾曹相爾汝，肯教俗子更誰何。", "詩成騷雅遺風在，壓倒南山白石歌。"]'),
('b6c6bf2d-13ce-404c-9741-78b1c4d54c01','再和前韻三首  其三','王炎','宋','宋诗','song-poetry','','[]','小屈青雲富貴身，翻翻倦脚踏街塵。',64,'全唐诗/poet.song.160000.json','["小屈青雲富貴身，翻翻倦脚踏街塵。", "黑貂久敝歲云晚，鴻鴈不來家有親。", "客路山川聊緩带，天關虎豹莫憎人。", "一寒元是功名兆，落筆能回桃李春。"]'),
('ffafcdff-0265-4687-8668-011ee1d24291','追念鱅谿老人  其一','王炎','宋','宋诗','song-poetry','','[]','交游大半上青雲，可使斯人竟陸沈。',64,'全唐诗/poet.song.160000.json','["交游大半上青雲，可使斯人竟陸沈。", "寒日亂山皆慘色，北風古木亦悲吟。", "傷情空拜丹青像，提耳不聞金玉音。", "舐墨欲書耆舊傳，無言三嘆我何心。"]'),
('82f04a25-083b-4157-b6e7-0e1f796237ee','追念鱅谿老人  其二','王炎','宋','宋诗','song-poetry','','[]','遶屋青山鎖白雲，其人如玉已埋沈。',64,'全唐诗/poet.song.160000.json','["遶屋青山鎖白雲，其人如玉已埋沈。", "瘦筇未掃往來迹，遺墨半存長短吟。", "有客不堪頻墮捷，此生無復見知音。", "天寒日短凄凉甚，老眼皇天照此心。"]'),
('4bb99f34-09e9-4c06-9ed4-ca5c241d7359','如大坂二絕  其一','王炎','宋','宋诗','song-poetry','','[]','輕風掠面作微凉，盡日筍輿行澗岡。',32,'全唐诗/poet.song.160000.json','["輕風掠面作微凉，盡日筍輿行澗岡。", "畦稻欲花新得雨，老農屈指計秋嘗。"]'),
('d8b0e2ca-f5b1-4858-9637-2a3d3429827d','如大坂二絕  其二','王炎','宋','宋诗','song-poetry','','[]','盤薄解衣方少休，青山白水挽吾留。',32,'全唐诗/poet.song.160000.json','["盤薄解衣方少休，青山白水挽吾留。", "一聲杜宇喚歸意，百囀黄鸝生客愁。"]'),
('9dcaba8d-3ece-4477-88ec-2894a8dfbd3c','田間閒步','王炎','宋','宋诗','song-poetry','','[]','春光挽我出柴扃，道上陳根換短青。',32,'全唐诗/poet.song.160000.json','["春光挽我出柴扃，道上陳根換短青。", "尚怯東風寒料峭，已聞好鳥語丁寧。"]'),
('e1890c6e-bc91-4346-b841-abf8ed812117','晚浴溪上','王炎','宋','宋诗','song-poetry','','[]','山脚草深樵徑沒，溪頭水落石梁高。',32,'全唐诗/poet.song.160000.json','["山脚草深樵徑沒，溪頭水落石梁高。", "一川風露無人占，古柳玄蟬處處號。"]'),
('ea0ff23c-a4c2-4c9a-b885-fd84798be27e','自南齋晚歸二絕  其一','王炎','宋','宋诗','song-poetry','','[]','返照南山脚，西風古渡頭。',24,'全唐诗/poet.song.160000.json','["返照南山脚，西風古渡頭。", "破烟雙鷺晚，抱葉一蟬秋。"]'),
('560e2886-c84f-4f10-9761-0e0a94afde16','自南齋晚歸二絕  其二','王炎','宋','宋诗','song-poetry','','[]','溪凉魚發發，山靜鳥飛飛。',24,'全唐诗/poet.song.160000.json','["溪凉魚發發，山靜鳥飛飛。", "草笠兒驅犢，荆釵女浣衣。"]'),
('4384a961-8594-468d-8a55-8d7282b030bf','到白石先妣新塋','王炎','宋','宋诗','song-poetry','','[]','淚滴松楸意轉哀，欲歸小立更徘徊。',32,'全唐诗/poet.song.160000.json','["淚滴松楸意轉哀，欲歸小立更徘徊。", "春風不管人間恨，溪上櫻桃花自開。"]'),
('e8e3c716-a3f5-4c07-a0d2-1702b0cb12fa','新晴二絕  其一','王炎','宋','宋诗','song-poetry','','[]','初春欲暖未全暖，小雨妨晴還得晴。',32,'全唐诗/poet.song.160000.json','["初春欲暖未全暖，小雨妨晴還得晴。", "多謝東風舊相識，少年樂事已寒盟。"]'),
('fd79fe30-9e0a-46bb-9269-489d2402e027','新晴二絕  其二','王炎','宋','宋诗','song-poetry','','[]','鴝鵒喜晴鳴竹枝，一篙新浪拍漁磯。',32,'全唐诗/poet.song.160000.json','["鴝鵒喜晴鳴竹枝，一篙新浪拍漁磯。", "春寒稍向日邊破，花信欲從風際歸。"]'),
('a6307f05-291f-4c56-98d1-8972afd02bc2','溪上晚望二絕  其一','王炎','宋','宋诗','song-poetry','','[]','溪深一股淥浮浮，橋斷人歸拏小舟。',32,'全唐诗/poet.song.160000.json','["溪深一股淥浮浮，橋斷人歸拏小舟。", "煙淡雲黄來暝色，青山數疊不遮愁。"]'),
('b54ef15d-053a-4baa-8a10-bdd895aef206','溪上晚望二絕  其二','王炎','宋','宋诗','song-poetry','','[]','日墮西山煙水昏，寂寥雞犬數家村。',32,'全唐诗/poet.song.160000.json','["日墮西山煙水昏，寂寥雞犬數家村。", "滄洲歸鷺客停棹，古寺疎鐘人掩門。"]'),
('db7b5772-a0c7-4759-bb27-572506be64c2','春日書懷','王炎','宋','宋诗','song-poetry','','[]','自憐童穉色凄凉，偃伏田廬歲月長。',64,'全唐诗/poet.song.160000.json','["自憐童穉色凄凉，偃伏田廬歲月長。", "用拙漫令文有冢，避愁不慣醉爲鄉。", "春來雨禁鳥烏樂，天末風回鴻鴈行。", "軒冕山林兩無得，諱窮徒覺意蒼茫。"]'),
('5d61b0f0-2af6-4c77-82b6-fd470b1fed27','送詹少游之平江','王炎','宋','宋诗','song-poetry','','[]','溪上相逢把盞時，回頭今是一年餘。',64,'全唐诗/poet.song.160000.json','["溪上相逢把盞時，回頭今是一年餘。", "聞君有喜驅都騎，顧我無聊守敝廬。", "信道此行騎鳳背，未知何日寄魚書。", "月明千里關山隔，莫爲新情忘故居。"]'),
('ded4ae52-2ddb-474d-99be-86e90565cabf','春日遣懷','王炎','宋','宋诗','song-poetry','','[]','感懷細數十年事，養拙略無終日閒。',64,'全唐诗/poet.song.160000.json','["感懷細數十年事，養拙略無終日閒。", "景物自新春稍稍，吾親漸老髮斑斑。", "豈曾有夢到天上，且任此生浮世間。", "願約漁樵同小隠，謂予不信有南山。"]'),
('4d6b8f8d-8d38-4d74-ba73-177204ac5000','題古塔主語錄','王炎','宋','宋诗','song-poetry','','[]','震雷動地音元寂，白月當空指即迷。',32,'全唐诗/poet.song.160000.json','["震雷動地音元寂，白月當空指即迷。", "天下老師應鎖口，此公不肯止兒啼。"]'),
('7bdacf4c-ac8b-4829-877f-611807684771','田間麥秀因成絕句','王炎','宋','宋诗','song-poetry','','[]','老穉緣崖鋤草根，炊烟不起自酸辛。',32,'全唐诗/poet.song.160000.json','["老穉緣崖鋤草根，炊烟不起自酸辛。", "東臯春到青青麥，屈指何時可食新。"]'),
('107630ea-6100-4b82-bb0f-80882ef9fccb','麥苗已有生意掘烏稬者未止','王炎','宋','宋诗','song-poetry','','[]','兒童飯犢女採桑，水滿東臯耕事忙。',68,'全唐诗/poet.song.160000.json','["兒童飯犢女採桑，水滿東臯耕事忙。", "稻秧半綠麥半黄，天許食新饘粥香。", "田父咨嗟仍笑語，赤地一年今得雨。", "紫{蔽/魚}有根妻子喜，免填溝壑棄閭里。"]'),
('7d0284dc-a469-4ed9-9293-172198513827','雨晴出田間','王炎','宋','宋诗','song-poetry','','[]','去年龜兆生田臯，今年龍骨挂屋敖。',80,'全唐诗/poet.song.160000.json','["去年龜兆生田臯，今年龍骨挂屋敖。", "烏牛告休卧籬落，夫耕婦饁亦既勞。", "稊稗不生白水滿，荷鋤出見禾苗高。", "屈指何時築場圃，割雞炊黍觴新醪。", "人言饑饉有豐稔，一笑破除心鬰陶。"]'),
('5297ef1f-f861-4941-9161-d03d6b2e39d3','得昭叔弟書','王炎','宋','宋诗','song-poetry','','[]','十年客館出無車，倦迹歸來守敝廬。',64,'全唐诗/poet.song.160000.json','["十年客館出無車，倦迹歸來守敝廬。", "林下巢傾烏哺斷，天邊風急鴈行疎。", "欲傳消息苦無便，喜報平安今有書。", "行李何時能緩带，對床風雨且幽居。"]'),
('f86911fe-b3ab-4a7f-8d09-05b40ebe160f','梟羹','王炎','宋','宋诗','song-poetry','','[]','日轉槐陰宮漏遲，蘭湯新浴生凉颸。',179,'全唐诗/poet.song.160000.json','["日轉槐陰宮漏遲，蘭湯新浴生凉颸。", "四方清晏上燕衎，千官鳴玉趨丹墀。", "鸞刀象箸薦多品，豈無炙鵠兼蒸鳬。", "射聲彈弋不虛發，獨取鳴梟供膳夫。", "卵翼深恩作奇禍，有此大罪宜翦夷。", "臣工拜手謝君賜，惟忠與孝終無虞。", "高皇盛德號寬大，惡不可赦彭黥菹。", "惜哉雲夢信先縛，功蓋一世人所疑。", "賜之屬鏤前事失，淫刑以逞誰無辜。", "留侯辟穀以智免，酇侯縲紲幾身危。", "君不見避人不出畏矰繳，商雒深山鸞鳳飛。"]'),
('eda5803a-82f6-4719-9971-ed4eed978763','聞虎傷人','王炎','宋','宋诗','song-poetry','','[]','胸臆包藏不可窺，誰能攘臂編其鬚。',64,'全唐诗/poet.song.160000.json','["胸臆包藏不可窺，誰能攘臂編其鬚。", "未論犬牛俱受禍，飽人之肉人何辜。", "騶虞不肯食生物，自古及今常罕出。", "吁嗟虎豹山林多，陷穽弓刀如彼何。"]'),
('78919577-1ab3-4c69-a4f3-c513b7b1a0d4','賀景高新居','王炎','宋','宋诗','song-poetry','','[]','百楹夏屋勢渠渠，氣象巋然壓里閭。',64,'全唐诗/poet.song.160000.json','["百楹夏屋勢渠渠，氣象巋然壓里閭。", "庭下紫荆方秀茂，階前玉樹亦扶疎。", "門容駟馬于公宅，客佩金魚吏部廬。", "莫使烏衣文彩減，諸郎勤讀五車書。"]'),
('74e2521c-7094-46bf-808e-f4396fad5c88','元日書懷','王炎','宋','宋诗','song-poetry','','[]','年光除日又元日，心事今吾非故吾。',64,'全唐诗/poet.song.160000.json','["年光除日又元日，心事今吾非故吾。", "兩板不須書鬰壘，一杯亦强飲屠蘇。", "添丁解事尋王母，內子傷時念老姑。", "欲報情深恩罔極，不終反哺愧林烏。"]'),
('9aa58b47-f86b-436d-8a79-b0b7613a7c46','到大坂','王炎','宋','宋诗','song-poetry','','[]','經年不踏鱅溪路，此日重來訪舊游。',32,'全唐诗/poet.song.160000.json','["經年不踏鱅溪路，此日重來訪舊游。", "溪上老人今不見，凉風細雨四山秋。"]'),
('724306b3-2f90-4a7f-82fa-74c6887e3dcc','江夏道中值雪','王炎','宋','宋诗','song-poetry','','[]','歎息謀身拙，棲遲簿領間。',48,'全唐诗/poet.song.160000.json','["歎息謀身拙，棲遲簿領間。", "朔風吹密霰，瘦馬踏窮山。", "游宦亦何好，浮生元自閒。", "去年溪上雪，高卧掩柴關。"]'),
('d09567bb-c7fa-4b35-ad82-a1a3269d3fcd','蒲圻道中遇雪二首  其一','王炎','宋','宋诗','song-poetry','','[]','馬上寒生手欲龜，田廬人靜爨烟稀。',64,'全唐诗/poet.song.160000.json','["馬上寒生手欲龜，田廬人靜爨烟稀。", "疑逢海上雙銀闕，想見雲中萬玉妃。", "野店避風聊解轡，地爐圍火自熏衣。", "勞生今被微官縛，何日衡茅獨掩扉。"]'),
('6895dd5b-3eb8-4221-990f-9e389e67ce13','蒲圻道中遇雪二首  其二','王炎','宋','宋诗','song-poetry','','[]','天慘雲垂地，風寒雪塞塗。',48,'全唐诗/poet.song.160000.json','["天慘雲垂地，風寒雪塞塗。", "驟看花滿眼，己覺粟生膚。", "冷屋無鳴漏，冰枝有立烏。", "馬寒如蝟縮，行役厭馳驅。"]'),
('b7f24fd6-6bb4-48a9-bd7a-c3ae55c093a9','再如蒲圻二首  其一','王炎','宋','宋诗','song-poetry','','[]','雲暝雨將雪，天低風正寒。',48,'全唐诗/poet.song.160000.json','["雲暝雨將雪，天低風正寒。", "簡書端可畏，行李不遑安。", "要路飛騰好，窮途進取難。", "折腰徒自苦，吾亦悔儒冠。"]'),
('32101ed0-1383-48c2-a3d4-d63a22caa3e7','再如蒲圻二首  其二','王炎','宋','宋诗','song-poetry','','[]','北走蓴塘路，從公敢憚行。',48,'全唐诗/poet.song.160000.json','["北走蓴塘路，從公敢憚行。", "凄凉當短日，寂寞過荒城。", "薄祿非吾願，塵緣窘此生。", "丘園如可樂，何必問功名。"]'),
('991f08c0-a6e2-474e-977e-fbda2302e896','行湖路','王炎','宋','宋诗','song-poetry','','[]','落日行湖尾，重袍不禦寒。',48,'全唐诗/poet.song.160000.json','["落日行湖尾，重袍不禦寒。", "亂流橫短棹，入暝解征鞍。", "梅瘦覺春未，鴈來知歲殘。", "何時休跋履，猶幸得平安。"]'),
('d9ea71a9-3e1b-4b4b-b736-4cd95041d16e','送游堯臣歸閩六首  其一','王炎','宋','宋诗','song-poetry','','[]','荆璞天下珍，價重金百鎰。',60,'全唐诗/poet.song.160000.json','["荆璞天下珍，價重金百鎰。", "誰能玉其德，有亦未易識。", "陸沈黄綬間，心不計喧寂。", "挽之置通津，誰借一臂力。", "窮山抱白虹，緹襲貴燕石。"]'),
('b582d888-bd90-4da0-b68b-63012c30d9b9','送游堯臣歸閩六首  其二','王炎','宋','宋诗','song-poetry','','[]','良農種嘉穀，未必皆歲豐。',60,'全唐诗/poet.song.160000.json','["良農種嘉穀，未必皆歲豐。", "世間固無巧，得喪係其逢。", "汾上百斛鼎，嶧陽七絲桐。", "清廟不登薦，造物頗未工。", "不移金石心，前哲能固窮。"]'),
('fc133aab-2a1b-4f51-b7ef-3ac60a2eb340','送游堯臣歸閩六首  其三','王炎','宋','宋诗','song-poetry','','[]','攫金不見人，士以貪自欺。',60,'全唐诗/poet.song.160000.json','["攫金不見人，士以貪自欺。", "玉壺有清冰，皎皎不受緇。", "畏義如畏刑，律己吾所師。", "一尉百僚底，三歲袖手歸。", "鄙夫顙有泚，行李惟囊衣。"]'),
('482b235e-5b9f-418f-add1-b6192f22c2bb','送游堯臣歸閩六首  其四','王炎','宋','宋诗','song-poetry','','[]','宦游適四方，僚友兄及弟。',60,'全唐诗/poet.song.160000.json','["宦游適四方，僚友兄及弟。", "所惡薰有蕕，氣味不相似。", "黄鵠來自南，俛首啄禾黍。", "意欲摩雲霄，石交予與汝。", "雞鶩安用喧，短翼無遠舉。"]'),
('a4fa03db-f9eb-49b0-a912-f3841772a8dd','送游堯臣歸閩六首  其五','王炎','宋','宋诗','song-poetry','','[]','火流暑將退，車馬戒行役。',60,'全唐诗/poet.song.160000.json','["火流暑將退，車馬戒行役。", "可不舉一杯，明日川陸隔。", "北堂太夫人，綠鬢今未白。", "雝雝鳳將雛，此樂豈易得。", "軒冕儻來爾，爲親謹眠食。"]'),
('196a93d2-a21b-46be-85c6-d213fca8a62a','送游堯臣歸閩六首  其六','王炎','宋','宋诗','song-poetry','','[]','松楸不掃灑，吾甚思江東。',60,'全唐诗/poet.song.160000.json','["松楸不掃灑，吾甚思江東。", "七閩在其南，雲間無去鴻。", "關山共明月，何時一尊同。", "小游忘年友，努力翰墨中。", "鑄金作龍淵，世豈無國工。"]'),
('fa13b6e6-8100-4e63-8ed1-375bcfa12857','和游堯臣出郊二首  其一','王炎','宋','宋诗','song-poetry','','[]','崎嶇深谷與崇岡，王事有期行李忙。',64,'全唐诗/poet.song.160000.json','["崎嶇深谷與崇岡，王事有期行李忙。", "玉佩泉鳴清醉耳，劍鋩山峭割愁腸。", "鳥鳴花發年華改，雨暗雲昏客路長。", "且喜歸來同笑語，蒲團棐几似僧房。"]'),
('adddc1c4-11a0-47a9-bfe7-a12829c38d4b','和游堯臣出郊二首  其二','王炎','宋','宋诗','song-poetry','','[]','小窗獨坐怯輕寒，一穗香雲遶博山。',64,'全唐诗/poet.song.160000.json','["小窗獨坐怯輕寒，一穗香雲遶博山。", "鵲語怱怱來屋角，梅花點點下欄干。", "馬蹄破雨休行役，麈尾生風共燕閒。", "只恐日邊需振鷺，鋒車早晚趣君還。"]'),
('452837c6-7803-4cad-baf6-6d14c82ef0ad','送游大冶歸建陽','王炎','宋','宋诗','song-poetry','','[]','西風來鴈歲欲晚，衰柳鳴蟬人語離。',64,'全唐诗/poet.song.160000.json','["西風來鴈歲欲晚，衰柳鳴蟬人語離。", "市道交游何足數，君家父子總相知。", "讀書要見古人意，立事正須年少時。", "話舊班荆尚無日，莫忘苦語有箴規。"]'),
('a7183726-632e-482a-8d38-a9e6827a1803','送張飾之','王炎','宋','宋诗','song-poetry','','[]','俗子問寒溫，吾儕相爾汝。',192,'全唐诗/poet.song.160000.json','["俗子問寒溫，吾儕相爾汝。", "二年坐窮山，蛛網懸一麈。", "剝啄誰扣關，欲語不敢吐。", "有客騎鯨魚，迎之倒雙屣。", "家聲本光融，人物亦英偉。", "胸次蟠江湖，筆端走風雨。", "贈我瓊瑶章，白虹貫囊褚。", "我如穿鼻犢，涉世多齟齬。", "君如側翅鷹，雲路未軒翥。", "杯酒接慇懃，縱談傾肺腑。", "百圍飽雪霜，士要嘗艱阻。", "傅說起胥靡，夷吾出囚虜。", "淮陰有寄食，新豐有逆旅。", "饑饉必豐年，乘除乃天理。", "豪傑就功名，但問歲寒爾。", "相對一掀髯，窮通忘慍喜。"]'),
('5c8eaaea-de94-41b9-bc70-461c0bc5b8d0','題周功甫總領石溪三亭 溪亭','王炎','宋','宋诗','song-poetry','','[]','表章泉石幽，領略鷗鷺閒。',96,'全唐诗/poet.song.160000.json','["表章泉石幽，領略鷗鷺閒。", "陰陰楊柳邊，小築置曲欄。", "平鋪簟紋綠，俯仰眼界寬。", "俗塵不可污，漁艇時往還。", "是心淡如水，聲名落人寰。", "身行霄漢上，夢遶滄波間。", "我欲從公游，斫鱠覆酒船。", "三弄噴霜竹，月高風露寒。"]'),
('edcd8e54-4fcd-473f-9767-c86471715cff','題周功甫總領石溪三亭 雪亭','王炎','宋','宋诗','song-poetry','','[]','竹窗環佩聲瓏玲，開窗不見山眉青。',128,'全唐诗/poet.song.160000.json','["竹窗環佩聲瓏玲，開窗不見山眉青。", "玉妃翦水墮花片，龜手入袖膚粟生。", "紫茵錦幕燎爐熾，不知酒面寒欲冰。", "春葱百指酌暖玉，似勝煮茗松風鳴。", "亭中主人笑無語，雪景佳處未易評。", "詩成呵筆筆隨凍，冥搜有味銀海明。", "天風浩浩吹鶴氅，欲跨白霓凌太清。", "負暄曝背者誰子，此亭可望不可登。"]'),
('f76c5ef7-482e-4393-8f4c-673a12f99643','題周功甫總領石溪三亭 嫣然亭','王炎','宋','宋诗','song-poetry','','[]','桃花結子杏花落，蛺蝶飛來遶新綠。',96,'全唐诗/poet.song.160000.json','["桃花結子杏花落，蛺蝶飛來遶新綠。", "臙脂如醉春意濃，嫣然一笑桃杏俗。", "薔薇之露不涴衣，玉頰彷彿生頩姿。", "無雙國色自愛惜，描貌安用詩人詩。", "雨濕東風三月尾，夜寒燒燭照花睡。", "索花勸飲乾百壺，美人羞死顰眉翠。"]'),
('57458942-4d30-450d-9f15-bc3e3bd8bc53','題陳巽叔適軒','王炎','宋','宋诗','song-poetry','','[]','消摇鵬鷃游，小大各有適。',108,'全唐诗/poet.song.160000.json','["消摇鵬鷃游，小大各有適。", "士墮躁欲中，束身就徽墨。", "桃溪有市隠，被褐懷拱璧。", "袖手閲世故，不變芻豢色。", "小窗一蒲團，燕坐琴書側。", "豈不對客語，青眼送鴻翼。", "自言肥遯好，外物斷欣戚。", "千金戒垂堂，一跌在所惜。", "笑我踏風波，轅駒窘覊靮。"]'),
('1787a76f-2c25-4bd8-ae15-3a688dbb3938','黄一翁自郡城回','王炎','宋','宋诗','song-poetry','','[]','千金一璧傾秦都，此璞未剖衆所疑。',240,'全唐诗/poet.song.160000.json','["千金一璧傾秦都，此璞未剖衆所疑。", "朱絲度曲有山水，袖手不鼓無人知。", "黄香裋褐走江漢，失脚未上青雲衢。", "此客胸中有佳處，笑人論士相目皮。", "敂關謁我即辭去，赤霄孔翠不可呼。", "江城邂逅共杯酒，麈尾清風生綌絺。", "步行觸熱兩足繭，別後略無雙鯉魚。", "楚山摇落歲又晚，花信首回南北枝。", "青燈抽穗出金粟，喜見間關行李歸。", "粲然爲我啟貝齒，知我不見如調饑。", "揮毫妙入斲輪手，倒囊盡出驪龍珠。", "朱朱白白顔色好，春風爛漫催花時。", "肯留花底共醉倒，爲君春酒滿眼酤。", "褦襶推之不肯去，忍使故人天一涯。", "摩挲老眼望寥廓，願見秋鶚凌風飛。"]'),
('7fcaefa0-a69e-4a3d-b893-109e9c3a3a4b','秋懷五首簡陳巽叔徐伯老  其一','王炎','宋','宋诗','song-poetry','','[]','西風脫數葉，木末秋有聲。',72,'全唐诗/poet.song.160000.json','["西風脫數葉，木末秋有聲。", "團扇內篋中，肅肅庭戶清。", "公退頗無事，解衣坐東榮。", "本乏霄漢心，未斷丘壑情。", "日月不肯留，奪我雙鬢青。", "陳編堪解頤，凉夜親短檠。"]'),
('4a22e40e-a50c-44fd-a72e-5dae8add4cac','秋懷五首簡陳巽叔徐伯老  其二','王炎','宋','宋诗','song-poetry','','[]','凉風挾秋回，蒲柳青欲黄。',48,'全唐诗/poet.song.160000.json','["凉風挾秋回，蒲柳青欲黄。", "桂樹枝相樛，采采含幽芳。", "清香美無度，坐憂露爲霜。", "志士有所懷，後時多慨慷。"]'),
('c95bdb24-7e67-466c-9dca-500f47741aa7','秋懷五首簡陳巽叔徐伯老  其三','王炎','宋','宋诗','song-poetry','','[]','西南天漢流，蟋蟀鳴露草。',48,'全唐诗/poet.song.160000.json','["西南天漢流，蟋蟀鳴露草。", "黄鵠垂其翼，坐看歲年老。", "寸陰輕尺璧，進德恨不早。", "百圍飽風霜，蹭蹬何足道。"]'),
('061dd9f5-da62-4883-9060-244c09435354','秋懷五首簡陳巽叔徐伯老  其四','王炎','宋','宋诗','song-poetry','','[]','我來今幾時，寒暑已一變。',60,'全唐诗/poet.song.160000.json','["我來今幾時，寒暑已一變。", "回首望江東，天末鴈行遠。", "弧矢四方志，別離詎能免。", "有懷先君子，生理只鉛槧。", "相憶可相忘，問學當自勉。"]'),
('0671a40a-ec3c-4bdf-95c8-bc9a559fefac','秋懷五首簡陳巽叔徐伯老  其五','王炎','宋','宋诗','song-poetry','','[]','我家南溪上，老屋四立壁。',60,'全唐诗/poet.song.160000.json','["我家南溪上，老屋四立壁。", "俗子呼不來，巷無車馬跡。", "公庭有將迎，未免眼青白。", "陳徐臭味同，吾獲雙拱璧。", "拂我榻上塵，與君商六籍。"]'),
('31d85b23-3d48-4ff2-acc5-ae00950fce08','又五首  其一','王炎','宋','宋诗','song-poetry','','[]','一身將百指，就食家浮游。',60,'全唐诗/poet.song.160000.json','["一身將百指，就食家浮游。", "清霜木葉黄，弊笥無完裘。", "平生三釜心，山阿種松楸。", "圓枘運方穿，命不與己謀。", "盥濯朱墨手，清江操鈞舟。"]'),
('eb9f1397-99c5-4a8b-b4af-66fc96f58cfa','又五首  其二','王炎','宋','宋诗','song-poetry','','[]','擇友得石交，心腹管城子。',60,'全唐诗/poet.song.160000.json','["擇友得石交，心腹管城子。", "可憐老而禿，我窮正坐此。", "玲瓏玉其音，六學有妙理。", "抱此爲身媒，前賢恐不爾。", "翩翩肉食飛，書生懦於武。"]'),
('855d56b7-14f8-48e7-baa6-4b251c15e492','又五首  其三','王炎','宋','宋诗','song-poetry','','[]','東風黄鳥鳴，白露寒蟬悲。',60,'全唐诗/poet.song.160000.json','["東風黄鳥鳴，白露寒蟬悲。", "去日何太短，種種髮欲疎。", "人言了婚嫁，此事今何如。", "欲耕無一廛，兒女牽人衣。", "蠶以繭自纏，深念難爲娛。"]'),
('4aaee2c9-02d7-461e-a38a-e19f138948ab','又五首  其四','王炎','宋','宋诗','song-poetry','','[]','跣行我足傷，涉世無夷路。',48,'全唐诗/poet.song.160000.json','["跣行我足傷，涉世無夷路。", "三復貝錦詩，讒口古亦惡。", "兒女附耳言，譽喜訴其怒。", "勿用驅青蠅，玉質自如故。"]'),
('b34bb844-94d3-47c0-befc-80dc4ec21954','又五首  其五','王炎','宋','宋诗','song-poetry','','[]','竹間有數椽，讀書樂未央。',72,'全唐诗/poet.song.160000.json','["竹間有數椽，讀書樂未央。", "稻粱自爲謀，風散鴻鴈行。", "叔氏從我來，季子天一方。", "人生手足愛，念之攪中腸。", "誰不思息肩，我豈樂異鄉。", "何時一青燈，夜雨同對床。"]'),
('127fcac1-5915-4d3f-bec9-944b63a6f807','用前韻答黄一翁五首  其一','王炎','宋','宋诗','song-poetry','','[]','天寒鴻鴈低，客子亦倦游。',60,'全唐诗/poet.song.160000.json','["天寒鴻鴈低，客子亦倦游。", "憶昔少年時，風埃蔽貂裘。", "欲辦一束茅，不種千章楸。", "黄鵠入雞鶩，亦爲飲啄謀。", "豈有斗升水，能行千斛舟。"]'),
('fc1294ff-29f1-495b-a0b4-ed9a80b7c40a','用前韻答黄一翁五首  其二','王炎','宋','宋诗','song-poetry','','[]','吾友西家黄，筆力壓餘子。',60,'全唐诗/poet.song.160000.json','["吾友西家黄，筆力壓餘子。", "金馬可曳裾，胡爲亦留此。", "整整插架書，拂蠹自料理。", "三年飛不翔，袖手今且爾。", "儀鳳五色文，霄漢終接武。"]'),
('dbdd162b-9135-4c8c-9d4d-1c2dba953675','用前韻答黄一翁五首  其三','王炎','宋','宋诗','song-poetry','','[]','楚客抱玉虹，刖足只自悲。',60,'全唐诗/poet.song.160000.json','["楚客抱玉虹，刖足只自悲。", "有寶不韞櫝，此計亦未疎。", "子虛一賦成，日邊問相如。", "老眼閲人多，君豈一布衣。", "篋中有瓊瑶，把玩聊自娛。"]'),
('a84d72fa-278d-4664-b771-833f724e6527','用前韻答黄一翁五首  其四','王炎','宋','宋诗','song-poetry','','[]','秣馬踐古轍，經術導先路。',48,'全唐诗/poet.song.160000.json','["秣馬踐古轍，經術導先路。", "士要人品高，與俗殊好惡。", "忮心蠆尾毒，褊心螳臂怒。", "唾面令自乾，吾今乃非故。"]'),
('c814e1c0-e21e-4aa6-903b-77e81c1e23cd','用前韻答黄一翁五首  其五','王炎','宋','宋诗','song-poetry','','[]','青雲諸貴人，鳴玉朝未央。',72,'全唐诗/poet.song.160000.json','["青雲諸貴人，鳴玉朝未央。", "我無封侯骨，難入鵷鷺行。", "生女不出門，生男志四方。", "十年九不就，食薺苦我腸。", "未能返故園，且可歸醉鄉。", "細君諭此懷，春溜鳴糟床。"]'),
('5d590561-4799-439b-91c3-369ec37b59f5','廨舍梅花欲開三絕  其一','王炎','宋','宋诗','song-poetry','','[]','花開不肯待春融，恐混繁枝深淺紅。',32,'全唐诗/poet.song.160000.json','["花開不肯待春融，恐混繁枝深淺紅。", "潔白天然貞女操，清癯獨立古人風。"]'),
('88b45580-ae32-4375-b7a7-759194095dfa','廨舍梅花欲開三絕  其二','王炎','宋','宋诗','song-poetry','','[]','懷人不寄隴頭信，寓興亦無東閣詩。',32,'全唐诗/poet.song.160000.json','["懷人不寄隴頭信，寓興亦無東閣詩。", "坐裛暗香供鼻觀，小窗寒月浸疎枝。"]'),
('7f129c5a-3a6b-465c-8a07-12c69a9a89c4','廨舍梅花欲開三絕  其三','王炎','宋','宋诗','song-poetry','','[]','頗怪涪翁錯下言，水仙許入弟兄間。',32,'全唐诗/poet.song.160000.json','["頗怪涪翁錯下言，水仙許入弟兄間。", "恨無好語供題品，花定嗔人頹玉山。"]'),
('d8620dc9-0593-4a47-9e4f-62d4a5366e83','郊外見梅再用前韻三首  其一','王炎','宋','宋诗','song-poetry','','[]','四山有雪未全融，蓓蕾梢頭茁小紅。',32,'全唐诗/poet.song.160000.json','["四山有雪未全融，蓓蕾梢頭茁小紅。", "也欲索花同一笑，蒼顔羞澀見春風。"]'),
('36ae0bc4-cf4e-4990-9a3c-acc14c83f8d4','郊外見梅再用前韻三首  其二','王炎','宋','宋诗','song-poetry','','["\u897f\u6e56"]','皎如玉雪不容緇，乞我寒香苦索詩。',32,'全唐诗/poet.song.160000.json','["皎如玉雪不容緇，乞我寒香苦索詩。", "輸與西湖閒處士，解吟籬落忽橫枝。"]'),
('c633f5e3-9a53-4ffb-af16-caf3da5f92bd','郊外見梅再用前韻三首  其三','王炎','宋','宋诗','song-poetry','','[]','故園疎竹蔽柴關，手植孤根在竹間。',32,'全唐诗/poet.song.160000.json','["故園疎竹蔽柴關，手植孤根在竹間。", "別後疎枝無恙否，寂寥風月冷溪山。"]'),
('59831f00-424a-466d-b929-d628251a9ea4','題咸寧江宰德先清遠堂','王炎','宋','宋诗','song-poetry','','[]','築屋俯平湖，百頃風漪漣。',156,'全唐诗/poet.song.160000.json','["築屋俯平湖，百頃風漪漣。", "湖底行白雲，湖外橫青山。", "仙官踏兩鳬，游戲來人間。", "清都在天上，欲去懶著鞭。", "百里可盤薄，苦無敲朴喧。", "試出持蟹手，爲民奏鳴絃。", "潘郎兒輩爾，栽花作春妍。", "淵明未甚高，料理種秫田。", "捲箔坐繩床，香吐一縷烟。", "白鳥入空濛，飛鴻度雲邊。", "箇裏不著愁，心與物共閒。", "漁榔勸客飲，玉色亦粲然。", "目極意不盡，老蟾生莫天。"]'),
('48e9b447-a490-4446-b8ec-9ff30eaaff83','生朝無以自慰作留貧薦一杯','王炎','宋','宋诗','song-poetry','','[]','私居飯半菽，官舍食無肉。',228,'全唐诗/poet.song.160000.json','["私居飯半菽，官舍食無肉。", "何乃太清生，囊無一錢蓄。", "人言骨相寒，有智不如福。", "貧者輕於葉，富者重如玉。", "輕重信然否，世情手翻覆。", "相彼守錢虜，無厭溪壑欲。", "口不談古今，枵然瓠壺腹。", "渠固笑我癯，我亦笑渠俗。", "珊瑚數十株，胡椒八百斛。", "冥冥鬼瞰室，一跌赤其族。", "未若貧而安，高枕睡常熟。", "我我雲溪陽，欹側數椽屋。", "屋後蒔菘韭，屋前種梅竹。", "室中四立壁，但有書可讀。", "世故驅我來，營此升斗粟。", "仕不上青雲，何如返耕牧。", "頗怪草玄翁，乃謂貧可逐。", "卒歲一布裘，終朝一饘粥。", "此外何所求，吾生無不足。"]'),
('5caa4f07-1b4f-4d08-8af0-f86375d0e3f0','用前韻答黄一翁二首  其一','王炎','宋','宋诗','song-poetry','','[]','縕袍敵狐裘，晚飯可當肉。',228,'全唐诗/poet.song.160000.json','["縕袍敵狐裘，晚飯可當肉。", "諱窮竟未免，豈不愛儲蓄。", "嗜利顙有泚，恐愧王承福。", "財固禍之媒，越鄉忌懷玉。", "君看座右器，已滿即傾覆。", "聖賢用功處，清心而寡欲。", "於世淡無求，乃能實其腹。", "誰令入青衫，失策混流俗。", "黄子振鷺姿，筆力扛百斛。", "笑人龜手藥，欲售先聚族。", "知予頗清苦，應物未圓熟。", "游宦不能巧，俯首立矮屋。", "鍛鍊知精金，祁寒見松竹。", "自立不堅定，庸行徒聖讀。", "誰謂漆園高，俯首欲丐粟。", "窮作扣角歌，老厭淄川牧。", "古道寖斲喪，時人方逐逐。", "有田南山南，可辦一盂粥。", "請賡歸去來，世路早收足。"]'),
('fdb410ad-13f4-4832-92a5-aaecd717dfd4','用前韻答黄一翁二首  其二','王炎','宋','宋诗','song-poetry','','[]','豆羹采藜藿，鼎食厭粱肉。',228,'全唐诗/poet.song.160000.json','["豆羹采藜藿，鼎食厭粱肉。", "士欲齊得喪，胸次要涵蓄。", "我晚頗聞道，寧有慧無福。", "外物皆浮雲，此道等珠玉。", "閲事如閲棋，已過安用覆。", "回光照諸妄，稍稍淡無欲。", "與君共玄談，一笑時捧腹。", "更以詩留貧，此語頗驚俗。", "細看苜蓿盤，豈減檳榔斛。", "見金不見人，渠輩非吾族。", "君獨臭味同，吾固知之熟。", "平生求益友，今日並牆屋。", "不肯兄事錢，寧以君呼竹。", "力學追古人，經史費抄讀。", "我方病少瘳，擁衲膚有粟。", "百念漸灰冷，有牛不須牧。", "君如汗血駒，墮地必馳逐。", "甘爲走踆踆，耻作雌粥粥。", "有玉未嘗獻，豈憂終刖足。"]'),
('b749cc77-6a70-4728-8ac5-d3395ee5239e','過幕阜山','王炎','宋','宋诗','song-poetry','','[]','昔聞幕阜古洞天，偶馳瘦馬行山前。',160,'全唐诗/poet.song.160000.json','["昔聞幕阜古洞天，偶馳瘦馬行山前。", "諸峰却立一峰出，蒼龍墮地走復蟠。", "誰燒丹竈汲丹井，絕頂萬丈巢飛仙。", "捫蘿攀磴敢憚險，欲往未有一日閒。", "仙翁見我定拍手，笑我詰曲來人間。", "雨淋日炙行路難，何如鸞鶴游雲端。", "人生不比金石堅，向來青鬢今蒼顔。", "百年富貴草頭露，何乃自苦縻一官。", "雖無道骨可不死，亦欲早挂頭上冠。", "南山之南北山北，築屋翠微高枕眠。"]'),
('c47c435c-ef10-4c48-977b-344242f7d54f','平江道中','王炎','宋','宋诗','song-poetry','','[]','筍輿踏瘦石，揮汗日亭午。',96,'全唐诗/poet.song.160000.json','["筍輿踏瘦石，揮汗日亭午。", "山斷忽眼明，人家住溪滸。", "解衣近綠陰，隔枝鳥相語。", "好風送凉來，坐久失畏暑。", "潭潭一水綠，可以浣塵土。", "樵歌響空谷，漁艇散前浦。", "丘壑太寂寥，從俗祇自苦。", "征夫問前途，欲往空顧佇。"]'),
('e84b047a-8dc6-4eba-9095-af05ed5ffb44','喜雨歌','王炎','宋','宋诗','song-poetry','','[]','去年夏旱田原枯，龍骨取水禾不蘇。',160,'全唐诗/poet.song.160000.json','["去年夏旱田原枯，龍骨取水禾不蘇。", "張頤待哺神所憫，吏既禱之甘雨隨。", "東阡西陌喜相賀，化我磽确成膏腴。", "炊粳釀黍作秋社，翁媼醉飽兒孫嬉。", "今年種藝方入土，梅天宜雨還不雨。", "高仰之田龜兆開，污邪亦半無流水。", "帝從人欲不待祈，豐隆擊鼓羣龍趨。", "山南山北起雲霧，雨脚急來如綆縻。", "富家安坐有紅粟，田家作苦惟饘粥。", "丁壯力耕兒飯牛，旱時得雨勝珠玉。"]'),
('0b42eb59-0b45-4d46-be2d-debc3a8feb9f','沿檄如蒲圻訊民之食菜事魔者作詩憫之','王炎','宋','宋诗','song-poetry','','[]','三代日方中，爲民破重昏。',156,'全唐诗/poet.song.160000.json','["三代日方中，爲民破重昏。", "既蝕復光融，孔孟道益尊。", "古禮今則亡，陳編意猶存。", "飲燕用觥籌，薦享羞羔豚。", "瞿曇何爲者，髠首徒實繁。", "不飲非畏義，不殺非知仁。", "舉世昏不悟，跣足行荆榛。", "胎禍産妖幻，與佛岐又分。", "俗愚有罣誤，吏議多深文。", "怒言必溢惡，疑似恐不根。", "黔首亦何罪，可憫不可嗔。", "大道若返古，怪說難眩民。", "帝居虎豹守，此語誰扣閽。"]'),
('78d34e86-6ac9-4b22-8fbc-cebf440be41e','和沈粹卿登南樓韻','王炎','宋','宋诗','song-poetry','','[]','鼓角聲悲城上頭，沈郎懷古一登樓。',64,'全唐诗/poet.song.160000.json','["鼓角聲悲城上頭，沈郎懷古一登樓。", "下臨平楚容回顧，北望神州定欲愁。", "叫日征鴻雲路冷，嘶風戰馬塞垣秋。", "人間俯仰更興廢，江漢滔滔萬古流。"]'),
('e2d599cc-80ef-4df4-9037-e14fe5f0545e','晚春書懷簡陳巽叔二首  其一','王炎','宋','宋诗','song-poetry','','[]','畏病不多酌，遣情時自吟。',48,'全唐诗/poet.song.160000.json','["畏病不多酌，遣情時自吟。", "絮飛春漠漠，樹密午陰陰。", "壯縣今岑寂，微官有陸沉。", "青山啼杜宇，未斷故園心。"]'),
('3f6636f7-2f73-4153-9db7-4aee8ef54ed8','晚春書懷簡陳巽叔二首  其二','王炎','宋','宋诗','song-poetry','','[]','花片已零落，綠陰遮短牆。',48,'全唐诗/poet.song.160000.json','["花片已零落，綠陰遮短牆。", "園蔬春笋長，官酒臘醅香。", "揮麈故人少，杜門閒日長。", "不妨時過我，談笑倚繩床。"]'),
('c6ab28cf-551d-4d95-a986-e3627e7aa944','和廖守岳陽樓韻三首  其一','王炎','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','湖水無波亦蹴天，君山蟠結獨巋然。',64,'全唐诗/poet.song.160000.json','["湖水無波亦蹴天，君山蟠結獨巋然。", "未須弔古懷騷客，聊復憑虛揖呂仙。", "霽月光風供笑傲，長篇短句總流傳。", "尊中况有蒲萄綠，試作長鯨飲百川。"]'),
('3469e957-e295-4b9e-acbf-d8ba6bea3872','和廖守岳陽樓韻三首  其二','王炎','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','蛟螭旗尾擁樓頭，偃仰胡床護一州。',64,'全唐诗/poet.song.160000.json','["蛟螭旗尾擁樓頭，偃仰胡床護一州。", "水闊三江成匯澤，風高六月有清秋。", "長吟不減白蘋句，坐嘯能分黄屋憂。", "凭檻可窮千里目，角聲嗚軋楚帆收。"]'),
('a469cb9b-ca41-4b12-990f-0931b5cb3f2e','和廖守岳陽樓韻三首  其三','王炎','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','清香燕寢憩儒先，出對湖山一莞然。',64,'全唐诗/poet.song.160000.json','["清香燕寢憩儒先，出對湖山一莞然。", "紅旆小驅聊緩带，青雲直上且揚鞭。", "肯容坐客同揮麈，莫憚行厨費擊鮮。", "種就巴丘桃李逕，不應畫諾更留連。"]'),
('5ce64f15-d8f7-491c-b81f-3d46232c339a','和留獻之出郊勸農','王炎','宋','宋诗','song-poetry','','[]','瀾翻布穀喚春晴，浩蕩花風擁旆旌。',64,'全唐诗/poet.song.160000.json','["瀾翻布穀喚春晴，浩蕩花風擁旆旌。", "野老無知須戶曉，長官著意自山行。", "四郊烟火皆新集，百里污萊未盡耕。", "前日惰農今力穡，閭閻閒暇政寬平。"]'),
('89ec4905-096d-4844-af1d-afe3a5cc02c6','和游堯臣勸農韻','王炎','宋','宋诗','song-poetry','','[]','傳呼穩凭筍輿行，喜見漫山麥浪平。',64,'全唐诗/poet.song.160000.json','["傳呼穩凭筍輿行，喜見漫山麥浪平。", "道上老農皆好語，年來瘦地有新耕。", "草深黄犢陽坡暖，雨過青蒲野水生。", "桃李陰中春事好，田家雞犬亦歡聲。"]'),
('af7230a3-a1dd-4701-91e9-10df94fe86a1','到胡道士草庵二首  其一','王炎','宋','宋诗','song-poetry','','[]','清風颼颼竹萬箇，白日寂寂茅三間。',64,'全唐诗/poet.song.160000.json','["清風颼颼竹萬箇，白日寂寂茅三間。", "春深只有鳥呼夢，地僻略無人叩關。", "豈但壺中堪避世，也勝圖上可遊山。", "出門回首不能住，輸與道人閒復閒。"]'),
('35e495e7-b144-4d32-a555-f4158678ef35','到胡道士草庵二首  其二','王炎','宋','宋诗','song-poetry','','[]','綠陰啼鳥戶庭幽，解带聊爲一夕留。',64,'全唐诗/poet.song.160000.json','["綠陰啼鳥戶庭幽，解带聊爲一夕留。", "行李未知何日了，轉蓬方覺此生浮。", "市朝役役兔三窟，今古悠悠貉一丘。", "得似黄冠林下住，何須控鶴上瀛洲。"]'),
('38620385-6e67-421d-b806-c46aaf91a857','旅中書懷','王炎','宋','宋诗','song-poetry','','[]','燕子未歸寒已退，海棠半落雨初晴。',64,'全唐诗/poet.song.160000.json','["燕子未歸寒已退，海棠半落雨初晴。", "他鄉異縣見春色，遠水平蕪關客情。", "道路不來黄犬信，烟波深負白鷗盟。", "數奇落在千官底，敢嘆儒冠誤此生。"]'),
('67065a12-7090-440b-865d-5373d0dd72c6','到壽安精舍','王炎','宋','宋诗','song-poetry','','[]','佛宇崇崇倚翠微，萬株松蓋碧相圍。',64,'全唐诗/poet.song.160000.json','["佛宇崇崇倚翠微，萬株松蓋碧相圍。", "崎嶇短策頻行路，盤薄胡床暫解衣。", "自笑將身爲馬走，不妨著眼趁鴻飛。", "枕流漱石平生事，却爲蝸蠻定是非。"]'),
('965457de-f6a7-4466-8445-ce4f23932e17','歲莫官舍書懷二首  其一','王炎','宋','宋诗','song-poetry','','[]','九霄側目不飛揚，落在荆湖又一霜。',64,'全唐诗/poet.song.160000.json','["九霄側目不飛揚，落在荆湖又一霜。", "寒日無輝溪水凍，春風有信野梅香。", "少年豪氣今揫斂，小隠生涯尚渺茫。", "歎息衣襟漬朱墨，鏡中容易鬢毛蒼。"]'),
('0bab5e36-aedd-495b-abe1-75247225c896','歲莫官舍書懷二首  其二','王炎','宋','宋诗','song-poetry','','[]','三徑無資出宦游，歸心日夜遶松楸。',64,'全唐诗/poet.song.160000.json','["三徑無資出宦游，歸心日夜遶松楸。", "絡頭不盡奔騰志，側翅聊爲飲啄謀。", "捉麈縱談無好客，捲書獨坐有清愁。", "陶泓毛穎成何事，彈指人間歲月流。"]'),
('0b999c2c-4426-4928-9abe-c8eaf7a7f8d2','聞杜鵑','王炎','宋','宋诗','song-poetry','','[]','稻秧出水綠初齊，憶在田間把一犁。',32,'全唐诗/poet.song.160000.json','["稻秧出水綠初齊，憶在田間把一犁。", "留滯天涯歸未得，杜鵑何苦向人啼。"]'),
('1a6de899-1c34-4d86-aded-31a98a07f855','野鳬','王炎','宋','宋诗','song-poetry','','[]','白水滿塘蒲荇青，野鳬相對浴春晴。',32,'全唐诗/poet.song.160000.json','["白水滿塘蒲荇青，野鳬相對浴春晴。", "背人飛去猶回顧，我已忘機莫浪驚。"]'),
('f0acb7e9-ae98-45c6-81cc-64335d2dc980','林監生日','王炎','宋','宋诗','song-poetry','','[]','玉融秀參天，人物時炳靈。',96,'全唐诗/poet.song.160000.json','["玉融秀參天，人物時炳靈。", "小春氣候佳，産此千人英。", "酌酒爲君壽，不惟祝年齡。", "君家屋渠渠，鶴髮居中庭。", "前有棣華秀，後有蘭芽馨。", "安用執象簡，始足爲君榮。", "置身瓶盎間，恐損雙鬢青。", "試占眉間黄，身閒即蓬瀛。"]'),
('7a4e407a-8911-4096-b8b8-a13dcd2a6eed','留獻之初得孫','王炎','宋','宋诗','song-poetry','','[]','藍田美玉驪龍珠，天馬之駒丹鳳雛。',240,'全唐诗/poet.song.160000.json','["藍田美玉驪龍珠，天馬之駒丹鳳雛。", "平生眼底未曾見，物以希有爲珍奇。", "世間尺子乏英骨，㹠犬雖多安用爲。", "留侯豐下宜有後，更積陰德栽培之。", "大兒嶄然露頭角，胸中篋笥羅詩書。", "文章機杼有家法，睥睨雲漢思高飛。", "小兒學語解揖客，眼如點漆膚凝脂。", "家庭有此萬金産，何憂門戶無光輝。", "乃翁昨日坐堂上，津津黄氣溢兩眉。", "女奴走報子舍喜，紫蘭玉樹生孫枝。", "不須老釋親抱送，此真天上麒麟兒。", "我來欲與湯餠客，對翁壽以金屈巵。", "看渠一歲能識字，八歲落筆驅文辭。", "三衢之留世冠冕，公侯衮衮當無疑。", "他年我未鬚髮白，已見此子摩天衢。"]'),
('54d91bb6-ef47-454b-9efc-a6fa860c16e5','野次欲訪于從周不果因寄二首  其一','王炎','宋','宋诗','song-poetry','','[]','見說南山下，雲霞好隠居。',48,'全唐诗/poet.song.160000.json','["見說南山下，雲霞好隠居。", "草深幽徑斷，心遠俗人疎。", "倚杖時觀穫，焚香只讀書。", "宦游無此樂，令我憶吾廬。"]'),
('90fe6b95-9af1-4009-aaa2-4ba7e5c3188a','野次欲訪于從周不果因寄二首  其二','王炎','宋','宋诗','song-poetry','','[]','佳士不可見，清游難豫期。',48,'全唐诗/poet.song.160000.json','["佳士不可見，清游難豫期。", "此心雖眷眷，欲去却遲遲。", "白酒應新熟，黄粱亦可炊。", "稍閒當躍馬，說與主人知。"]'),
('86a0036c-c9e8-4521-81a9-2d3b588e519c','過鳳隠山','王炎','宋','宋诗','song-poetry','','[]','落日孤村靜，青松一徑斜。',48,'全唐诗/poet.song.160000.json','["落日孤村靜，青松一徑斜。", "問程愁客路，託宿到僧家。", "香鼎生雲穗，茶甌湧雪花。", "胸襟添道氣，隠几息喧譁。"]'),
('67672d9b-3596-44fc-bca1-94503c96930e','出游郊外七絕  其一','王炎','宋','宋诗','song-poetry','','[]','漠漠野田新水生，花枝一笑欲傾城。',32,'全唐诗/poet.song.160000.json','["漠漠野田新水生，花枝一笑欲傾城。", "孤村曲塢皆春色，信有東風不世情。"]'),
('4eb6acb0-da8c-48b8-98d7-4d18b158dc9e','出游郊外七絕  其二','王炎','宋','宋诗','song-poetry','','[]','幽鳥共歌春意好，閒花巧笑客愁多。',32,'全唐诗/poet.song.160000.json','["幽鳥共歌春意好，閒花巧笑客愁多。", "酒徒詩社俱疎隔，如此東郊景物何。"]'),
('410dc0ce-fcca-4c2f-8853-5b5837563223','出游郊外七絕  其三','王炎','宋','宋诗','song-poetry','','[]','閉戶不知春色佳，柳梢欲暗可藏鴉。',32,'全唐诗/poet.song.160000.json','["閉戶不知春色佳，柳梢欲暗可藏鴉。", "鴨頭新綠齊腰水，女頰輕紅刺眼花。"]'),
('72d1c54a-0c34-43cc-ba28-bd778d8aa8ad','出游郊外七絕  其四','王炎','宋','宋诗','song-poetry','','[]','道上東風掠面輕，一犁雨足得新晴。',32,'全唐诗/poet.song.160000.json','["道上東風掠面輕，一犁雨足得新晴。", "草頭蛺蝶自由舞，林下鶌鵃相對鳴。"]'),
('afb1fd3e-af16-42bc-8e5e-eefd87c9cafd','出游郊外七絕  其五','王炎','宋','宋诗','song-poetry','','[]','孤烟近見數椽屋，急水時行獨木橋。',32,'全唐诗/poet.song.160000.json','["孤烟近見數椽屋，急水時行獨木橋。", "入眼異鄉風景別，脩眉一抹暮山遥。"]'),
('39ab5ff3-dbcb-4c35-ac4a-cd72ade83c49','出游郊外七絕  其六','王炎','宋','宋诗','song-poetry','','[]','快馬駸駸穿野徑，春風處處見山花。',32,'全唐诗/poet.song.160000.json','["快馬駸駸穿野徑，春風處處見山花。", "不須舉首看回鴈，家在南頭天一涯。"]'),
('f358f03f-16fd-40f6-a0b8-6be7c5c4a7a4','出游郊外七絕  其七','王炎','宋','宋诗','song-poetry','','[]','雲昏山色收圖畫，雨過泉聲雜管絃。',32,'全唐诗/poet.song.160000.json','["雲昏山色收圖畫，雨過泉聲雜管絃。", "馬上得晴春滿眼，好花迎客亦嫣然。"]'),
('f9228e33-80a5-41d0-a3be-60eefecd9f8f','旅中思家','王炎','宋','宋诗','song-poetry','','[]','野田既雨水皆滿，山路無風花自香。',64,'全唐诗/poet.song.160000.json','["野田既雨水皆滿，山路無風花自香。", "且復將身供世事，也能隨處對春光。", "絕嫌俗物眼多白，未辦生涯髯已蒼。", "待看楂梨粗可教，老夫耕釣即韜藏。"]'),
('d7bb8f1e-1cdf-4f51-a616-4828285ac5bd','至灌溪予瓌老二首  其一','王炎','宋','宋诗','song-poetry','','[]','春風一路百花開，踏遍空山特地來。',32,'全唐诗/poet.song.160000.json','["春風一路百花開，踏遍空山特地來。", "莫道漚麻池水淺，千尋飛瀑吼春雷。"]'),
('0d52e497-aeb6-4e7d-87b6-a1a3cd14d64d','至灌溪予瓌老二首  其二','王炎','宋','宋诗','song-poetry','','[]','食肉定知非虎頸，騰身自笑不鳶肩。',32,'全唐诗/poet.song.160000.json','["食肉定知非虎頸，騰身自笑不鳶肩。", "相逢莫話青雲事，借我清風一枕眠。"]'),
('25c36c1d-cc1c-4426-ad5c-bcdd30b2e86a','宿野人家','王炎','宋','宋诗','song-poetry','','[]','破籬犬吠月將落，曲沼蛙號天欲晴。',32,'全唐诗/poet.song.160000.json','["破籬犬吠月將落，曲沼蛙號天欲晴。", "日出東方塵滿眼，不如欹枕夢魂清。"]'),
('881a902b-8973-4454-91d7-1d156d859814','聞蟬','王炎','宋','宋诗','song-poetry','','[]','綠陰遮日忽鳴蟬，墮地殘紅色未蔫。',32,'全唐诗/poet.song.160000.json','["綠陰遮日忽鳴蟬，墮地殘紅色未蔫。", "兩岸垂楊低蘸水，夢魂時到故溪邊。"]'),
('73a53cda-9517-44ce-ba15-becaa66d10f8','山行二絕  其一','王炎','宋','宋诗','song-poetry','','[]','路回穠綠屢低蓋，風定落紅時點衣。',32,'全唐诗/poet.song.160000.json','["路回穠綠屢低蓋，風定落紅時點衣。", "行李馳驅無暇日，客情鄉思兩依依。"]'),
('33d34a4e-7df1-4aef-9bde-1d44fda6c5d2','山行二絕  其二','王炎','宋','宋诗','song-poetry','','[]','盡日扶輿度亂山，石根古澗水潺潺。',32,'全唐诗/poet.song.160000.json','["盡日扶輿度亂山，石根古澗水潺潺。", "孤烟時傍翠微起，疑在新安道路間。"]'),
('32b16d50-debd-4a1c-a6fc-794d1185be42','春日二絕  其一','王炎','宋','宋诗','song-poetry','','[]','柳影人家燕子飛，東風落絮罥游絲。',32,'全唐诗/poet.song.160000.json','["柳影人家燕子飛，東風落絮罥游絲。", "欲題崔護桃花句，惆悵春深子滿枝。"]'),
('c0879e73-aa32-47d2-8e9f-b8756765609c','春日二絕  其二','王炎','宋','宋诗','song-poetry','','[]','野花無頼作紅白，香力也能來著人。',32,'全唐诗/poet.song.160000.json','["野花無頼作紅白，香力也能來著人。", "古澗寒泉山下路，道人別作一家春。"]'),
('1c363b99-c9d4-435e-a890-18f063e100ce','到常清寺予哲師三絕  其一','王炎','宋','宋诗','song-poetry','','[]','扣關解后老支郎，見我丁寧問故鄉。',32,'全唐诗/poet.song.160000.json','["扣關解后老支郎，見我丁寧問故鄉。", "自說病身歸不得，花開葉落幾凄凉。"]'),
('b894fa15-1a2d-461a-bda2-6c457da55bc1','到常清寺予哲師三絕  其二','王炎','宋','宋诗','song-poetry','','[]','寂寂松門古道場，暫容倦客拂橫床。',32,'全唐诗/poet.song.160000.json','["寂寂松門古道場，暫容倦客拂橫床。", "老僧欲盡殷勤意，林下春風茗椀香。"]'),
('d5690fa6-10d6-4529-9acb-d0e4d0d0c62c','到常清寺予哲師三絕  其三','王炎','宋','宋诗','song-poetry','','[]','古井寒泉久不波，豈貪好夢到南柯。',32,'全唐诗/poet.song.160000.json','["古井寒泉久不波，豈貪好夢到南柯。", "夜來雨過巖花落，好鳥留春自嘯歌。"]'),
('48c6bd03-06af-4a56-a921-0df76f747999','晚憩田家二絕  其一','王炎','宋','宋诗','song-poetry','','[]','家書未到鵲先喜，春事無多鶑又啼。',32,'全唐诗/poet.song.160000.json','["家書未到鵲先喜，春事無多鶑又啼。", "偶對好山留客坐，綠陰遮屋日將西。"]'),
('d99dab98-c0b1-4c57-920d-d818b69b1d6b','晚憩田家二絕  其二','王炎','宋','宋诗','song-poetry','','[]','山間一徑牛羊迹，林下數家雞犬聲。',32,'全唐诗/poet.song.160000.json','["山間一徑牛羊迹，林下數家雞犬聲。", "底事居人苦爭畔，閒田官正募民耕。"]'),
('90499501-562e-4514-bfae-2794338e65e6','留山間即事','王炎','宋','宋诗','song-poetry','','[]','暫留野次倦征行，差覺山林氣味清。',64,'全唐诗/poet.song.160000.json','["暫留野次倦征行，差覺山林氣味清。", "日釀梅酸新雨過，山連空翠淡烟橫。", "東臯水滿起農事，南國草青回鴈程。", "撥置文書聊隠几，笙歌一部聽蛙鳴。"]'),
('b8f5ede4-fc81-4735-a7be-032dc10c1d16','出郊書懷','王炎','宋','宋诗','song-poetry','','[]','扁舟蓑笠寄平生，元是江湖一白丁。',64,'全唐诗/poet.song.160000.json','["扁舟蓑笠寄平生，元是江湖一白丁。", "偶著青衫持手版，懶占黄色上天庭。", "正須每事問三尺，未暇對人談六經。", "啼鳥數聲春事了，故鄉回首幾長亭。"]'),
('67530a81-4b81-43e4-9457-01ac8c8dd7c9','野次遇雨','王炎','宋','宋诗','song-poetry','','[]','木末雲屯飛雨暗，柳梢水到小溪深。',64,'全唐诗/poet.song.160000.json','["木末雲屯飛雨暗，柳梢水到小溪深。", "身隨王事有行役，家在江南無信音。", "但得林泉堪著眼，莫將軒冕更關心。", "拂衣何日徑歸去，青鬢不禁愁緒侵。"]'),
('33cc68c6-980a-457d-86f9-0bbeca0d4e0b','酬陳叔裕四首  其一','王炎','宋','宋诗','song-poetry','','[]','扣關倒屣略從容，驚見文章豹管中。',64,'全唐诗/poet.song.160000.json','["扣關倒屣略從容，驚見文章豹管中。", "水闊山遥俱倦客，花明柳暗又東風。", "錦囊收拾語皆好，黄卷沉潜經可窮。", "會看卧龍騰踏去，知賢吾或似龐翁。"]'),
('87f6ca0a-8d3a-4928-973f-bfe125a7e920','酬陳叔裕四首  其二','王炎','宋','宋诗','song-poetry','','[]','花枝破蕾作輕紅，漸有春愁入眼中。',64,'全唐诗/poet.song.160000.json','["花枝破蕾作輕紅，漸有春愁入眼中。", "儻可登樓銷暇日，幸無舉扇障西風。", "朱絃自奏難諧俗，白璧深藏莫醜窮。", "樽酒論文期款曲，驪駒催客陋江翁。"]'),
('daf65ff2-a712-4968-85e1-8e19d7e6be4e','酬陳叔裕四首  其三','王炎','宋','宋诗','song-poetry','','[]','未能築室隠牆東，偶爾書名宦牒中。',64,'全唐诗/poet.song.160000.json','["未能築室隠牆東，偶爾書名宦牒中。", "羅雀門空無俗物，騎鯨客至有仙風。", "刀頭雖折故鄉遠，錐末不營生理窮。", "意欲挽君來酒國，接䍦倒著任山翁。"]'),
('f8a3e006-d2b5-4568-8027-0a4c3fa9b0c8','酬陳叔裕四首  其四','王炎','宋','宋诗','song-poetry','','[]','天台遠在浙江東，景物應曾到夢中。',64,'全唐诗/poet.song.160000.json','["天台遠在浙江東，景物應曾到夢中。", "但有錦囊盛白雪，苦無羅襪舞回風。", "閉門花鳥春心薄，隠几詩書日力窮。", "益友琢磨吾豈敢，西隣仙吏有詩翁。"]'),
('ca390224-0b13-424c-9e3d-309b50980ca9','上巳','王炎','宋','宋诗','song-poetry','','[]','莫春祓禊好天氣，不到水邊流一杯。',64,'全唐诗/poet.song.160000.json','["莫春祓禊好天氣，不到水邊流一杯。", "旋擘紅泥嘗煮酒，自循綠樹摘青梅。", "淹留異縣客多病，迢遞故鄉書不來。", "歷歷舊時行樂處，憑欄小立首空迴。"]'),
('4ce7f933-430e-4c96-a6b8-9bb67a544b81','過靈塔寺','王炎','宋','宋诗','song-poetry','','[]','蕭寺經新雨，山間六月清。',48,'全唐诗/poet.song.160000.json','["蕭寺經新雨，山間六月清。", "松梢凝翠滴，蕉葉自風生。", "古塔巋然在，僧魚冷不鳴。", "旅懷多感激，高樹又蟬聲。"]'),
('11b8baf7-318d-4d56-b015-dd8e202980c5','過西崙莊一宿','王炎','宋','宋诗','song-poetry','','[]','南首巴陵道，籃輿小作程。',48,'全唐诗/poet.song.160000.json','["南首巴陵道，籃輿小作程。", "欲隨王事去，頗戀佛廬清。", "一雨暑欲退，四山秋有聲。", "流年欺鬢髮，摇落又關情。"]'),
('300e5aea-d213-4de9-97b8-d35435491cba','酬李秀才','王炎','宋','宋诗','song-poetry','','[]','繫馬松根倦欲休，入門解逅得詩流。',64,'全唐诗/poet.song.160000.json','["繫馬松根倦欲休，入門解逅得詩流。", "暑天客裏難行路，莫雨山間便覺秋。", "共對青燈譚世事，惜無斗酒破牢愁。", "黄花可摘吾當返，肯過桃溪一醉不。"]'),
('e584450a-993a-432b-9fdb-feaf0a7de810','湘陰道中','王炎','宋','宋诗','song-poetry','','[]','道出昌江險，翩翩馬足輕。',48,'全唐诗/poet.song.160000.json','["道出昌江險，翩翩馬足輕。", "流萍嗟遠宦，行李偶南征。", "地带長沙濕，川通湘水清。", "凄凉懷屈賈，天闊莫雲平。"]'),
('7c55f921-5d73-4a3c-90ea-b2d3c8d46893','喜晴','王炎','宋','宋诗','song-poetry','','[]','雲上山椒鳴竹雞，愁行客路踏青泥。',32,'全唐诗/poet.song.160000.json','["雲上山椒鳴竹雞，愁行客路踏青泥。", "窮人也得天調護，乞與新晴可杖藜。"]'),
('de783eb6-6005-4004-9d04-0c5e4a5a9cfe','雨中山行','王炎','宋','宋诗','song-poetry','','[]','暝烟有客投茅舍，春水無人渡板橋。',32,'全唐诗/poet.song.160000.json','["暝烟有客投茅舍，春水無人渡板橋。", "滿地落花愁寂寂，連天芳草思迢迢。"]'),
('1470b05b-dde9-41be-b751-4b28da17c75b','春日即事四絕  其一','王炎','宋','宋诗','song-poetry','','[]','晚晴鸜鵒自相語，春冷海棠猶未花。',32,'全唐诗/poet.song.160000.json','["晚晴鸜鵒自相語，春冷海棠猶未花。", "把酒排愁先畏病，擁衾作夢欲還家。"]'),
('036eda25-c322-47d7-9079-7f99f11bee85','春日即事四絕  其二','王炎','宋','宋诗','song-poetry','','[]','年少逢春喜欲狂，長年心事易凄凉。',32,'全唐诗/poet.song.160000.json','["年少逢春喜欲狂，長年心事易凄凉。", "胸中不可無今古，坐閲陳編自炷香。"]'),
('6f3e5758-bcc4-4ce6-ae06-259719b444df','春日即事四絕  其三','王炎','宋','宋诗','song-poetry','','[]','著人春氣濃於酒，老眼倦看深淺紅。',32,'全唐诗/poet.song.160000.json','["著人春氣濃於酒，老眼倦看深淺紅。", "只有睡魔降未得，銅瓶魚眼沸松風。"]'),
('095dbfcf-9259-419c-b371-12095a7242e4','春日即事四絕  其四','王炎','宋','宋诗','song-poetry','','[]','小園桃李怯風雨，春事一年渾得晴。',32,'全唐诗/poet.song.160000.json','["小園桃李怯風雨，春事一年渾得晴。", "燕子欲相牽率去，踏青吾不敢徒行。"]'),
('bcdf6051-e813-455a-b04b-06e217284107','雨後繼成二絕  其一','王炎','宋','宋诗','song-poetry','','[]','草泥融處墮蔫紅，社近寒生雨又風。',32,'全唐诗/poet.song.160000.json','["草泥融處墮蔫紅，社近寒生雨又風。", "未辦把杯供一醉，花開花落太怱怱。"]'),
('fca7e938-79f5-411d-84aa-56e84b3976b4','雨後繼成二絕  其二','王炎','宋','宋诗','song-poetry','','[]','水摇山影綠沉沉，雨打花光故惱人。',32,'全唐诗/poet.song.160000.json','["水摇山影綠沉沉，雨打花光故惱人。", "頼有海棠傾國色，嫣然一笑解留春。"]'),
('e64f7a1f-cfe8-45d3-a20b-feada9ffa665','陪留宰游灌溪回飲縣圃六絕  其一','王炎','宋','宋诗','song-poetry','','[]','泥融紫燕欲營壘，日暖黄蜂爭取花。',32,'全唐诗/poet.song.160000.json','["泥融紫燕欲營壘，日暖黄蜂爭取花。", "試向靜中觀物化，蒲團相對坐僧家。"]'),
('8a177be1-4a97-44cb-9cce-2e6a24c70269','陪留宰游灌溪回飲縣圃六絕  其二','王炎','宋','宋诗','song-poetry','','[]','花暖不勝胡蝶狂，松間支徑午陰凉。',32,'全唐诗/poet.song.160000.json','["花暖不勝胡蝶狂，松間支徑午陰凉。", "漚麻別自有春色，鼻觀同參佛土香。"]'),
('c77a1f77-4c33-495b-aced-c32818f7475e','陪留宰游灌溪回飲縣圃六絕  其三','王炎','宋','宋诗','song-poetry','','[]','樽中歡伯解人意，乞我桃皮杏眼紅。',32,'全唐诗/poet.song.160000.json','["樽中歡伯解人意，乞我桃皮杏眼紅。", "一笑勞生那易得，回鞭落日馬嘶風。"]'),
('4a5ebe70-34b8-40f1-b416-5f1e77179440','陪留宰游灌溪回飲縣圃六絕  其四','王炎','宋','宋诗','song-poetry','','[]','入眼山花盡笑迎，雙鳬飛處雨初晴。',32,'全唐诗/poet.song.160000.json','["入眼山花盡笑迎，雙鳬飛處雨初晴。", "二年踏遍桃溪路，携酒尋春只此行。"]'),
('21a62fce-dbd8-40da-b867-a8d5f72d710a','陪留宰游灌溪回飲縣圃六絕  其五','王炎','宋','宋诗','song-poetry','','[]','高燒蠟炬照深紅，恐負一年花信風。',32,'全唐诗/poet.song.160000.json','["高燒蠟炬照深紅，恐負一年花信風。", "惡客敢辭今日醉，明年別去定匆匆。"]'),
('a3681ec1-2214-412d-96c9-f8218b003bbf','陪留宰游灌溪回飲縣圃六絕  其六','王炎','宋','宋诗','song-poetry','','[]','東風桃李可招客，吏事塵埃能困人。',32,'全唐诗/poet.song.160000.json','["東風桃李可招客，吏事塵埃能困人。", "蘸甲一杯留我醉，知公胸次有陽春。"]'),
('2d1bcdd1-09da-4fdc-822b-b1dea2c30e8c','和留宰賞荼䕷二絕  其一','王炎','宋','宋诗','song-poetry','','[]','郎官喚客坐花旁，盡日杯行笑語香。',32,'全唐诗/poet.song.160000.json','["郎官喚客坐花旁，盡日杯行笑語香。", "醉看綠雲籠暖雪，不知憔悴落他鄉。"]'),
('69bb57e5-e90e-4b15-94fa-0e3e9d720666','和留宰賞荼䕷二絕  其二','王炎','宋','宋诗','song-poetry','','[]','得酒衰懷亦滿觴，不禁花氣逼人香。',32,'全唐诗/poet.song.160000.json','["得酒衰懷亦滿觴，不禁花氣逼人香。", "醒時忍見風吹盡，玉質溫柔是故鄉。"]'),
('70528ab9-7cc6-4193-bf8a-024e2e49f1a4','陳推官幽居十詠 彭蠡歸舟','王炎','宋','宋诗','song-poetry','','[]','三老檣邊爾汝，頗疑居士知津。',28,'全唐诗/poet.song.160000.json','["三老檣邊爾汝，頗疑居士知津。", "頼有白鷗無恙，肯來迎棹相親。"]'),
('dac5dd2d-18f8-41e3-b110-ecc4a1ed9ba3','陳推官幽居十詠 山堂曠望','王炎','宋','宋诗','song-poetry','','[]','俗物令人眼白，鈎簾領略湖山。',28,'全唐诗/poet.song.160000.json','["俗物令人眼白，鈎簾領略湖山。", "袖手倚楹獨立，孤鴻滅沒人間。"]'),
('98a20fe7-3749-4e43-9a97-b9085635871b','陳推官幽居十詠 重湖泛月','王炎','宋','宋诗','song-poetry','','[]','四顧水光無際，自操一葉輕舟。',28,'全唐诗/poet.song.160000.json','["四顧水光無際，自操一葉輕舟。", "天闊冰輪欲墮，短橈猶在中流。"]'),
('3bfdbcd7-7573-4677-bda3-d08f01b5bbda','陳推官幽居十詠 星灣晚釣','王炎','宋','宋诗','song-poetry','','[]','割據一灣風月，棹行衝破青蘋。',28,'全唐诗/poet.song.160000.json','["割據一灣風月，棹行衝破青蘋。", "未有霜鱗貫柳，注心不在垂綸。"]'),
('05bcfa9c-8fcc-4e4b-8606-1a4e74c835c5','陳推官幽居十詠 雨後觀瀑','王炎','宋','宋诗','song-poetry','','[]','銀漢倒傾波浪，玉龍怒挾雷霆。',28,'全唐诗/poet.song.160000.json','["銀漢倒傾波浪，玉龍怒挾雷霆。", "雨後遥看更好，斬新泉白山青。"]'),
('6eff9498-3ae3-4936-9eb2-739b0950d78d','陳推官幽居十詠 松徑閒步','王炎','宋','宋诗','song-poetry','','[]','兩行松蓋遮護，下有蒼苔地衣。',28,'全唐诗/poet.song.160000.json','["兩行松蓋遮護，下有蒼苔地衣。", "試我青鞋布襪，支筇却立忘歸。"]'),
('d16bfcd2-0c83-46f0-82a0-094229d1993e','陳推官幽居十詠 溪上賦詩','王炎','宋','宋诗','song-poetry','','[]','閲遍岸花汀草，撚髭危坐漁磯。',28,'全唐诗/poet.song.160000.json','["閲遍岸花汀草，撚髭危坐漁磯。", "一笑冥搜得句，溪山爭吐光輝。"]'),
('7c180351-6ef3-415d-be27-273513eb426a','陳推官幽居十詠 林下避暑','王炎','宋','宋诗','song-poetry','','[]','灌木樛枝密葉，南風細細無聲。',28,'全唐诗/poet.song.160000.json','["灌木樛枝密葉，南風細細無聲。", "不用蒲葵到手，箇中六月秋清。"]'),
('a584db77-357c-4122-b996-d41c648259e9','陳推官幽居十詠 載酒尋梅','王炎','宋','宋诗','song-poetry','','[]','幽花信美如玉，不願游人見知。',28,'全唐诗/poet.song.160000.json','["幽花信美如玉，不願游人見知。", "喚取麴生同載，爲春物色南枝。"]'),
('7cd81957-04df-47e8-a6d8-5333ff798f35','陳推官幽居十詠 雪中訪隠','王炎','宋','宋诗','song-poetry','','[]','寒氣侵凌鶴氅，蒼頭急打柴門。',28,'全唐诗/poet.song.160000.json','["寒氣侵凌鶴氅，蒼頭急打柴門。", "鵲抱冰枝欲語，山人喜色春溫。"]'),
('6ba02608-4eca-44d4-90ad-31a391cb154b','宿公安二聖寺','王炎','宋','宋诗','song-poetry','','[]','蒙城一市萬人聚，一堤如虹作遮護。',96,'全唐诗/poet.song.160000.json','["蒙城一市萬人聚，一堤如虹作遮護。", "風濤悍怒魚龍宮，瀕流壓以青蓮宇。", "潭潭廣殿不動尊，夾立二丈力士身。", "楚帆蜀柂日銜尾，過者蹴然生畏心。", "粥魚齋鼓二千指，我貧未辦作檀施。", "明朝踏霜出江頭，借佛定力扶扁舟。"]'),
('2875d30f-7eb9-494d-a7bb-f686ecc0d8ad','寓江陵能仁僧舍二首  其一','王炎','宋','宋诗','song-poetry','','[]','客裏歲月晚，春生梅柳枝。',48,'全唐诗/poet.song.160000.json','["客裏歲月晚，春生梅柳枝。", "弟兄嗟別久，兒女話歸遲。", "拙直將安用，飛騰敢自期。", "老支剛笑我，底事作癡兒。"]'),
('0d5937aa-b304-48a0-8a76-94110cbd2f02','寓江陵能仁僧舍二首  其二','王炎','宋','宋诗','song-poetry','','[]','容膝非無地，安心即是家。',48,'全唐诗/poet.song.160000.json','["容膝非無地，安心即是家。", "焚香翻貝葉，汲水養梅花。", "無客同持酒，呼僧共煮茶。", "夜寒燒木佛，誰是老丹霞。"]'),
('586956d6-4678-4fde-906f-96226d2f74e2','夜坐','王炎','宋','宋诗','song-poetry','','[]','月白侵衣冷，窗間對一燈。',48,'全唐诗/poet.song.160000.json','["月白侵衣冷，窗間對一燈。", "淹留歸未得，進取我何能。", "空室無天女，清談只衲僧。", "不嫌身寂寞，絕喜睡瞢騰。"]'),
('4111a4a1-719f-485f-9bec-bcefcaa3a0eb','復州道中二首  其一','王炎','宋','宋诗','song-poetry','','[]','歲事已告畢，客行殊未歸。',48,'全唐诗/poet.song.160000.json','["歲事已告畢，客行殊未歸。", "蔞蒿穿雪長，水鳥背人飛。", "沮洳蒹葭遠，村墟烟火稀。", "邊風吹莫色，短策度斜暉。"]'),
('ac79939b-e000-4fa9-a6bc-2ac815c4d270','復州道中二首  其二','王炎','宋','宋诗','song-poetry','','[]','私喜歸期近，天邊更遠遊。',48,'全唐诗/poet.song.160000.json','["私喜歸期近，天邊更遠遊。", "士須嘗險阻，吾敢恨淹留。", "塵事蟻旋磨，浮名魚中鈎。", "春風桃李月，倚柂看東流。"]'),
('1465d2c6-88b4-44de-aab8-bf894451f4ca','夜宿江上','王炎','宋','宋诗','song-poetry','','[]','夜宿江邊蘆葦叢，江流浩浩吼天風。',32,'全唐诗/poet.song.160000.json','["夜宿江邊蘆葦叢，江流浩浩吼天風。", "西南闕月淡無色，擁衲不眠聽塞鴻。"]'),
('2b1fb149-3304-44b8-b3e6-b5238d3757e2','贈李居士棄官爲僧二絕  其一','王炎','宋','宋诗','song-poetry','','[]','踏破青鞋走四方，年來收脚坐禪床。',32,'全唐诗/poet.song.160000.json','["踏破青鞋走四方，年來收脚坐禪床。", "更無言下商量處，靜對窗間一炷香。"]'),
('ca840a1c-aa9b-4769-89a3-fa2c82949363','贈李居士棄官爲僧二絕  其二','王炎','宋','宋诗','song-poetry','','[]','遮寒破衲雪蒙頭，笑我浪懷千歲憂。',32,'全唐诗/poet.song.160000.json','["遮寒破衲雪蒙頭，笑我浪懷千歲憂。", "解下腰包只如此，亦無莫莫與休休。"]'),
('5e1e21d9-0d36-4111-bf12-b0b7091c6bfb','春日叢桂書舍偶成二首  其一','王炎','宋','宋诗','song-poetry','','[]','芳草青青晝掩關，倦游心緒歎重山。',64,'全唐诗/poet.song.160000.json','["芳草青青晝掩關，倦游心緒歎重山。", "寒生怪雨盲風後，春在斜陽暮靄間。", "杜宇勸人歸小隠，桃花笑我欲蒼顔。", "腐儒未解謀生理，魚蠹陳編不自閒。"]'),
('61ec2b41-4963-45f6-bf1f-ebdf1b2c1fc2','春日叢桂書舍偶成二首  其二','王炎','宋','宋诗','song-poetry','','[]','簷頭燕子話新晴，客裏春來何似生。',64,'全唐诗/poet.song.160000.json','["簷頭燕子話新晴，客裏春來何似生。", "短榻曲肱眠未穩，好花刺眼笑相迎。", "生憎重碧盃中物，懶趁踏青江上行。", "燕坐翛然有佳處，耳根更聽讀書聲。"]'),
('c386aedb-6679-4ebc-b113-3e782ebde901','用前韻答彌明聖言二首  其一','王炎','宋','宋诗','song-poetry','','[]','清晝渾無客敂關，不知春色滿溪山。',64,'全唐诗/poet.song.160000.json','["清晝渾無客敂關，不知春色滿溪山。", "少年側目雲霄上，今日藏身翰墨間。", "揮麈逢君談世事，舉杯爲我變衰顔。", "歸來更倚繩床坐，賸得勞生一日閒。"]'),
('531858f5-c0ac-484e-b259-012264a93fe1','用前韻答彌明聖言二首  其二','王炎','宋','宋诗','song-poetry','','[]','游絲落絮弄春晴，挽我花邊喚麴生。',64,'全唐诗/poet.song.160000.json','["游絲落絮弄春晴，挽我花邊喚麴生。", "挈榼在門驚剝啄，褰裳出戶喜逢迎。", "小園曲折藏三徑，暇日從容共一行。", "且復解頤談衮衮，聖賢深處不容聲。"]'),
('6b334481-102f-44c0-94c8-9ed7bdf178a7','再用前韻答繼周丈二首  其一','王炎','宋','宋诗','song-poetry','','[]','雲路鵷鴻度九關，誰知霧豹隠南山。',64,'全唐诗/poet.song.160000.json','["雲路鵷鴻度九關，誰知霧豹隠南山。", "追懷先世交朋舊，幸拜英姿丈席間。", "歎我壯年猶白髮，知公有道養朱顔。", "運斤肯試成風巧，當許摳衣侍燕閒。"]'),
('8e7dd88c-d95e-4305-b458-e788b1ab2da9','再用前韻答繼周丈二首  其二','王炎','宋','宋诗','song-poetry','','[]','士女春遊喜得晴，焚香燕坐太清生。',64,'全唐诗/poet.song.160000.json','["士女春遊喜得晴，焚香燕坐太清生。", "遶枝烏鵲如相語，排闥青山不待迎。", "倦客琴書來寓處，前人杖屨昔經行。", "平生父黨惟公在，發藥宜聞謦欬聲。"]'),
('0841e435-b187-46b6-9e4f-37718dd62f2a','家僕來叢桂告米粟不繼','王炎','宋','宋诗','song-poetry','','[]','來時花柳未全春，燕子將雛已夏深。',64,'全唐诗/poet.song.160000.json','["來時花柳未全春，燕子將雛已夏深。", "破鏡望中占遠信，扊扅歌裏有悲音。", "青衫得祿猶彈鋏，白髮欺人欲上簪。", "築室買田謀小隠，探囊何日有黄金。"]'),
('88eef363-2804-4c92-9faa-c48e840eb019','書舍遣興二首  其一','王炎','宋','宋诗','song-poetry','','[]','意裏謀功業，閒中度歲年。',48,'全唐诗/poet.song.160000.json','["意裏謀功業，閒中度歲年。", "詩囊渾漫興，酒榼更無緣。", "久客荒三徑，歸耕欠一廛。", "懶扶藜杖出，回眼入陳編。"]'),
('d21387ca-5bcd-4cc0-817d-7a9729dd6839','書舍遣興二首  其二','王炎','宋','宋诗','song-poetry','','[]','山好晴邊出，風微雨後凉。',48,'全唐诗/poet.song.160000.json','["山好晴邊出，風微雨後凉。", "憑欄幽鳥語，步屧草花香。", "塵事何時了，浮生有底忙。", "此身垂老大，不自决行藏。"]'),
('d25a21b1-559d-41e3-a21c-3d9c6387b031','即事','王炎','宋','宋诗','song-poetry','','[]','桑盡蠶皆繭，秧成麥已秋。',48,'全唐诗/poet.song.160000.json','["桑盡蠶皆繭，秧成麥已秋。", "山雲翻黑雨，溪樹沒黄流。", "紅粟方翔貴，蒼生未病瘳。", "茅茨烟不起，飽飯得無憂。"]'),
('46606fc7-145b-4bb5-a272-d62624df2b4f','賀吳繼仲母氏生日','王炎','宋','宋诗','song-poetry','','[]','青都仙子玉鍊顔，五雲深處乘青鸞。',144,'全唐诗/poet.song.160000.json','["青都仙子玉鍊顔，五雲深處乘青鸞。", "桃花欲實王母老，桂花半落嫦娥寒。", "芝英瓊蘂薄滋味，絳霄倒景窺人間。", "風微水麝香可掬，雨定海榴紅欲燃。", "中州風物亦自好，翩然萬里來雲軿。", "潭潭院落春不老，別有日月藏壺天。", "狻猊不動烟縷直，吹笙伐鼓開賓筵。", "九重紫誥照環佩，兩兒綠綬扶金船。", "南山可平海可竭，高堂歡樂無窮年。"]'),
('e88b37f4-304e-4722-94bf-3cdde66b9ce1','清化寓居','王炎','宋','宋诗','song-poetry','','[]','委巷何深僻，僑居太寂寥。',48,'全唐诗/poet.song.160000.json','["委巷何深僻，僑居太寂寥。", "古牆行絡石，喬木上凌霄。", "賦就貧難逐，詩成隠莫招。", "固窮吾輩事，心地要逍遥。"]'),
('684aa0f4-5fb4-4f95-9ad2-7d768e7c7ec0','秋旱得雨','王炎','宋','宋诗','song-poetry','','[]','下田出龜兆，高田半黄埃。',132,'全唐诗/poet.song.160000.json','["下田出龜兆，高田半黄埃。", "禾穗槁欲死，益以蟊賊災。", "鉦鼓競禱祈，民病神所哀。", "劃空走笑電，隠地鳴怒雷。", "雲將爲前驅，頗送甘雨來。", "老穉喜欲狂，稍覺生意回。", "雞豚賽秋社，屈指篘新醅。", "米價免翔貴，我亦懷抱開。", "凉聲遶松梢，披襟可徘徊。", "執熱汗如雨，得此亦快哉。", "短歌當甿謠，因以侑一杯。"]'),
('f4d63597-7367-47ab-ab70-c336a094cd1f','夜坐偶追悼豬哥不覺流涕因以絕句寫其悲','王炎','宋','宋诗','song-poetry','','[]','三年娠孕疑希有，千里鄉關不共歸。',32,'全唐诗/poet.song.160000.json','["三年娠孕疑希有，千里鄉關不共歸。", "旅殯新墳今宿草，西風老淚更沾衣。"]'),
('67679558-ae93-42a4-95f5-1981919bdf18','除夜官舍獨坐','王炎','宋','宋诗','song-poetry','','[]','半世更憂患，微霜入鬢邊。',48,'全唐诗/poet.song.160000.json','["半世更憂患，微霜入鬢邊。", "旅懷尊有酒，官况客無氈。", "故國踰千里，浮生又一年。", "遥憐小兒女，今夜話燈前。"]'),
('c4f343da-6ad8-4446-8681-93460f48cd4d','到城南園瞻南軒先生遺像','王炎','宋','宋诗','song-poetry','','[]','入門荷香凈，步屧柳陰濕。',120,'全唐诗/poet.song.160000.json','["入門荷香凈，步屧柳陰濕。", "欲寫情鬰陶，翻引興蕭瑟。", "瞻望堂中人，玉色而山立。", "六學妙經綸，未試百之一。", "身存天下望，身沒海內惜。", "此道付誰傳，丹青但陳迹。", "樓邊好山近，竹底凉風入。", "兩鶴韻亦高，導我轉湖側。", "獨游何太清，滯念亦可釋。", "門關莫返鎖，願言日散策。"]'),
('bb39a4cf-082c-4c16-b46a-5f0c8f9c8a7c','用前韻答彪講書','王炎','宋','宋诗','song-poetry','','[]','薄游城南園，墮睫衣袂濕。',120,'全唐诗/poet.song.160000.json','["薄游城南園，墮睫衣袂濕。", "斯人既騎箕，有客猶鼓瑟。", "凜然氣如生，可使懦夫立。", "當時道義交，彪子居其一。", "嘗試問所疑，傾倒無吝惜。", "逝者不可作，往訪杖屨迹。", "欲返更徘徊，遠岫邀日入。", "緬懷經世心，伐輻置河側。", "立朝道不容，憂國意難釋。", "敢負門下知，晨夕自警策。"]'),
('da8e33c2-8c1c-4d68-b847-e7733dba4b3f','送李侍郎歸衡州二首  其一','王炎','宋','宋诗','song-poetry','','[]','繫纜南風直，轉柂北風微。',156,'全唐诗/poet.song.160000.json','["繫纜南風直，轉柂北風微。", "輕雲載雨來，凉意生綌絺。", "江神真解事，穩送六幅蒲。", "篷窗卧胡床，鷗鷺相追隨。", "落帆衡陽岸，新舊迎公歸。", "兒童競挽袂，父老前捋鬚。", "明時有勇退，晚歲善自頤。", "稍添數髭白，不改兩頰朱。", "松菊對主人，亦自清而腴。", "門外無車馬，室中但琴書。", "青鞋時出遊，不用藜杖扶。", "翛然萬物表，意得樂有餘。", "乃知上要津，不若還幽居。"]'),
('cd779981-03de-43e6-b2a0-ed47a69cd3f9','送李侍郎歸衡州二首  其二','王炎','宋','宋诗','song-poetry','','[]','道重物自輕，心清內無慾。',156,'全唐诗/poet.song.160000.json','["道重物自輕，心清內無慾。", "未定胸中見，難行天下獨。", "冠蓋上青雲，著鞭競馳逐。", "南山有德人，一笑遺寵辱。", "巋然殿諸老，足以鎮浮俗。", "一出上禁林，再出擁牙纛。", "本無圭組累，歸去便野服。", "譬如山中雲，潤澤滋草木。", "未雨出巖岫，已雨反幽谷。", "明月共樽罍，清風滿松竹。", "問誰從之游，韋編能熟讀。", "人生了婚嫁，意願何時足。", "儻肯割半山，誅茅從卜築。"]'),
('32701bac-cb6c-40cf-bfc4-75a55a286da7','和謝安國求硯','王炎','宋','宋诗','song-poetry','','[]','靈均葬魚腹，賈傅問服臆。',168,'全唐诗/poet.song.160000.json','["靈均葬魚腹，賈傅問服臆。", "挽我來訪古，窮鬼信有力。", "敢恨客氈寒，私喜無吏責。", "稍稍集韋布，時時論文墨。", "濯纓湘水清，拄笏湘山碧。", "陶泓耐久朋，笑我玄尚白。", "今代謝叔源，人物居第一。", "詩來招石友，願費黄金鎰。", "冰絲固希有，霧縠亦罕得。", "何以報明珠，更覺意羞澀。", "回首歙溪上，寂寞子雲宅。", "當求玉堂樣，特來獻詞伯。", "胸中五色絲，一用可華國。", "視草須若人，携之上文石。"]'),
('ca7ebb94-1793-42ed-a57d-b2d31a6f7e43','和謝安國韻','王炎','宋','宋诗','song-poetry','','[]','虎豹嗔人上九關，不妨拄笏看雲山。',64,'全唐诗/poet.song.160000.json','["虎豹嗔人上九關，不妨拄笏看雲山。", "家聲元是封胡後，人物還如晉宋間。", "解組聞公真有意，折腰顧我亦何顔。", "故園無地開三徑，敢說歸耕是等閒。"]'),
('d844614e-cd33-418f-9b9f-9c8d51dc1a00','送謝安國歸清江','王炎','宋','宋诗','song-poetry','','[]','軒冕喜而憂，山林靜而閒。',240,'全唐诗/poet.song.160000.json','["軒冕喜而憂，山林靜而閒。", "寵辱皆妄事，請看槐夢安。", "世人悟此少，低頭縛微官。", "足跌尚欲趨，翼倦不肯還。", "謝公湖海士，著眼高塵寰。", "心如玉壺冰，當暑氣自寒。", "懷璧不願市，懶上青雲端。", "親朋勸之仕，晚出彈其冠。", "未令據槐廳，亦合登蓬山。", "造物拙用大，束带來侯藩。", "掉頭厭多事，袖手思故園。", "眉間已黄色，鏡裏猶朱顔。", "家住玉笥西，別有壺中天。", "千畝稻秫肥，三徑松菊繁。", "妙得詩酒趣，小作杖屨緣。", "鴻飛霄漢外，蟬蛻塵埃間。", "我方自窘束，仰屋坐長歎。", "欲仕苦無津，欲歸苦無田。", "野鹿念豐草，老驥困短轅。", "終當抱琴書，從公掩雲關。"]'),
('a6998635-4b61-4cd6-8b4a-c864c15c0031','題王倅來泉','王炎','宋','宋诗','song-poetry','','[]','寒泉一竇行脩渠，日夜輸來爲納湖。',64,'全唐诗/poet.song.160000.json','["寒泉一竇行脩渠，日夜輸來爲納湖。", "荷花菱葉並籬落，平分十頃青玻璃。", "錫山老湫暗流注，此泉疑自玉龍吐。", "問公泉中何所有，明月可弄不可取。"]'),
('b09645f4-0439-4936-a24a-ec3fe1253d63','又題巢林','王炎','宋','宋诗','song-poetry','','[]','闤闠深居似林谷，緣坡手種青青玉。',64,'全唐诗/poet.song.160000.json','["闤闠深居似林谷，緣坡手種青青玉。", "市聲不向耳根來，蒙密中間深結屋。", "鷦鷯但願巢一枝，鸞停鵠峙意何如。", "青雲千級風在下，飛翰穩去摩天衢。"]'),
('9fc8aa7a-8754-48ff-b53b-b23899fcb013','過浯溪讀中興碑','王炎','宋','宋诗','song-poetry','','[]','日光玉潔元子辭，銀鈎鐵畫顔公書。',240,'全唐诗/poet.song.160000.json','["日光玉潔元子辭，銀鈎鐵畫顔公書。", "百金不憚買墨本，摩挲石刻今見之。", "猗那清廟久不作，其末變爲王黍離。", "春秋一經事多貶，魯頌四篇文無譏。", "漁陽鼙鼓入潼華，公卿徒步從六飛。", "朔方天子扶九廟，京師父老迎千麾。", "紫袍再拜謁道左，上皇萬里旋鑾輿。", "牝雞鳴晨有悍婦，孽狐嘷夜有老奴。", "扶桑杲杲未翳蝕，但歌大業吾何疵。", "首章義正語未婉，前輩不辨來者疑。", "正須細讀史克頌，未用苦說涪翁詩。", "許張勁節震金石，李郭壯武如虎貔。", "斷崖蒼石有時泐，諸公萬古聲烈垂。", "天憐倦客有所恨，雨濕江寒催解維。", "神州北望三嘆息，翰墨是非何議爲。"]'),
('63c1c66f-185d-44b5-8aff-d94909f3f391','和趙行之三首  其一','王炎','宋','宋诗','song-poetry','','[]','未暖柳梢綠，已暖花梢紅。',48,'全唐诗/poet.song.160000.json','["未暖柳梢綠，已暖花梢紅。", "胸次有天和，本與春意同。", "士戒溺於慾，物忌居其雄。", "西山有理窟，一室惟清風。"]'),
('75f3125f-7b0f-4d02-bb1e-6861efaa916e','和趙行之三首  其二','王炎','宋','宋诗','song-poetry','','[]','義利毫髮間，其末分舜跖。',48,'全唐诗/poet.song.160000.json','["義利毫髮間，其末分舜跖。", "葛藟多攀援，喬松但孤立。", "陽鱎貪芳餌，鵷雛食竹實。", "知道貴含光，露牙多召敵。"]'),
('31970a66-a8d8-43e9-afa4-c85b42bd0a39','和趙行之三首  其三','王炎','宋','宋诗','song-poetry','','[]','轉喉有觸諱，拭面或逢嗔。',48,'全唐诗/poet.song.160000.json','["轉喉有觸諱，拭面或逢嗔。", "刳心踏風波，未免悔吝生。", "葵猶衛其足，况此千金身。", "山林本逍遥，無虞莫從禽。"]'),
('1d93be72-fc79-4a91-ac6c-c5ccdb6c2f00','湘中雜咏十絕  其一','王炎','宋','宋诗','song-poetry','','[]','朝陽巖下莫雲冷，冉水磯邊秋樹深。',32,'全唐诗/poet.song.160000.json','["朝陽巖下莫雲冷，冉水磯邊秋樹深。", "欲弔元和柳司馬，溪山無力挽歸心。"]'),
('50e4807d-ffa8-4eb4-8865-220802ca15e6','湘中雜咏十絕  其二','王炎','宋','宋诗','song-poetry','','[]','江樹疎疎兼密密，雲根怪怪復奇奇。',32,'全唐诗/poet.song.160000.json','["江樹疎疎兼密密，雲根怪怪復奇奇。", "風光冷落無人問，付與漁翁理釣絲。"]'),
('342eaef5-7a2f-4265-9734-a5a4e2270389','湘中雜咏十絕  其三','王炎','宋','宋诗','song-poetry','','[]','昨日北風頻打頭，今朝風定却安流。',32,'全唐诗/poet.song.160000.json','["昨日北風頻打頭，今朝風定却安流。", "江山如畫供詩眼，陰雨無端釀客愁。"]'),
('00d1d7e8-11a3-4992-8704-43a4984cc8b3','湘中雜咏十絕  其四','王炎','宋','宋诗','song-poetry','','[]','有懷冉水柳司馬，更憶浯溪元道州。',32,'全唐诗/poet.song.160000.json','["有懷冉水柳司馬，更憶浯溪元道州。", "仕宦兩公俱落莫，斯文千古共傳流。"]'),
('02c501d8-3ed6-47d2-a39a-440f7c196053','湘中雜咏十絕  其五','王炎','宋','宋诗','song-poetry','','[]','順流鳴櫓不論程，上水開帆取次行。',32,'全唐诗/poet.song.160000.json','["順流鳴櫓不論程，上水開帆取次行。", "逆順自從人意轉，風生波湧本無情。"]'),
('2f5375e3-0a3c-4658-bb45-8cfa9c799acd','湘中雜咏十絕  其六','王炎','宋','宋诗','song-poetry','','[]','江天雲暝雨垂垂，日暮移舟口岸時。',32,'全唐诗/poet.song.160000.json','["江天雲暝雨垂垂，日暮移舟口岸時。", "拈筆欲題還袖手，細搜摩詰畫中詩。"]'),
('5780cde5-a2be-4f61-ab92-4e37fad059a5','湘中雜咏十絕  其七','王炎','宋','宋诗','song-poetry','','[]','中流四顧浪花平，雙櫓夾船鵝鸛鳴。',32,'全唐诗/poet.song.160000.json','["中流四顧浪花平，雙櫓夾船鵝鸛鳴。", "欵乃聲中山水綠，不妨緩緩計歸程。"]'),
('a8fad75b-4b7e-47c7-bcee-bad9ee84c214','湘中雜咏十絕  其八','王炎','宋','宋诗','song-poetry','','[]','蕩槳妨人擁衲眠，篷窗細雨濕炊烟。',32,'全唐诗/poet.song.160000.json','["蕩槳妨人擁衲眠，篷窗細雨濕炊烟。", "江神念我怯行險，收却風波穩放船。"]'),
('391c04b4-dfdd-4598-9cd8-d6f71f24c209','湘中雜咏十絕  其九','王炎','宋','宋诗','song-poetry','','[]','江頭昨夜雨何似，新漲平添一丈强。',32,'全唐诗/poet.song.160000.json','["江頭昨夜雨何似，新漲平添一丈强。", "倚柂穩如天上坐，順流明日到衡陽。"]'),
('7731c528-3c22-4e4d-8c4c-2ea30fd29fa5','湘中雜咏十絕  其一○','王炎','宋','宋诗','song-poetry','','[]','舴艋輕輕載短簑，蘋花風急起滄波。',32,'全唐诗/poet.song.160000.json','["舴艋輕輕載短簑，蘋花風急起滄波。", "憑誰喚取玄真子，更作湘中漁父歌。"]'),
('38cfa800-13c9-417c-afb4-6b9feb0a6014','秋懷二首  其一','王炎','宋','宋诗','song-poetry','','[]','鏡中忽忽老侵尋，政坐文窮自陸沉。',64,'全唐诗/poet.song.160000.json','["鏡中忽忽老侵尋，政坐文窮自陸沉。", "獨對西風搔短髮，欲謀小隠背初心。", "江湖鴻鴈天將冷，籬落黄花秋又深。", "拄笏看山聊爾耳，懶彈綠綺索知音。"]'),
('62f53ad9-3915-41b0-a3ed-d0f2a19d3596','秋懷二首  其二','王炎','宋','宋诗','song-poetry','','[]','朅來雲夢澤南州，風物蕭蕭兩見秋。',64,'全唐诗/poet.song.160000.json','["朅來雲夢澤南州，風物蕭蕭兩見秋。", "三徑草荒真左計，一官冰冷更何求。", "莫招毛穎論時事，且喚麴生澆客愁。", "短艇輕蓑良不惡，此心何敢負江鷗。"]'),
('0c43953a-d5e5-4e1a-bf2e-398562cad0aa','游岳麓三絕  其一','王炎','宋','宋诗','song-poetry','','[]','湘山湘水極清遠，特地來登百尺臺。',32,'全唐诗/poet.song.160000.json','["湘山湘水極清遠，特地來登百尺臺。", "不盡胸中丘壑意，又從沙尾喚舟回。"]'),
('a13ed434-4bfe-4378-96d9-33798cbaa6b0','游岳麓三絕  其二','王炎','宋','宋诗','song-poetry','','[]','百級蒼珉到佛宮，汲泉煮茗聽松風。',32,'全唐诗/poet.song.160000.json','["百級蒼珉到佛宮，汲泉煮茗聽松風。", "不須騎鶴摩雲去，只要心游碧落中。"]'),
('7de46c46-cb62-4134-9633-adc75549ca77','游岳麓三絕  其三','王炎','宋','宋诗','song-poetry','','[]','山椒却立小遲留，欲傍江山洗客愁。',32,'全唐诗/poet.song.160000.json','["山椒却立小遲留，欲傍江山洗客愁。", "不覺憑高來遠念，此心潜與水東流。"]'),
('d3af872f-d2c4-48b8-8e44-4a4496ab21d0','冬日書懷四首  其一','王炎','宋','宋诗','song-poetry','','[]','治身如治玉，所貴無瑕疵。',60,'全唐诗/poet.song.160000.json','["治身如治玉，所貴無瑕疵。", "玉美不願市，身修豈求知。", "人生爲糊口，乃爾斂板趨。", "漸失兩鬢青，莫浣雙袖緇。", "勿用懷不平，弦急聲易悲。"]'),
('d23e609a-b474-4a5e-85e9-d71c07773b97','冬日書懷四首  其二','王炎','宋','宋诗','song-poetry','','[]','齏鹽雖淡泊，義理極雋永。',60,'全唐诗/poet.song.160000.json','["齏鹽雖淡泊，義理極雋永。", "士唯知此味，未語已相領。", "同流有淄澠，何用勤造請。", "不敢眼青白，口諾心未肯。", "平生環堵中，三徑自冰冷。"]'),
('2b7c676a-0f99-45d8-bf64-0a90cc5ce7ee','冬日書懷四首  其三','王炎','宋','宋诗','song-poetry','','[]','客來倦捉麈，客去徐挾書。',60,'全唐诗/poet.song.160000.json','["客來倦捉麈，客去徐挾書。", "兒曹厭官冷，數問何時歸。", "豈知庇風雨，未辦蝸牛廬。", "老我懷百憂，又自一解頤。", "雨流木偶行，久矣無定居。"]'),
('89a03d06-5b92-4bd2-bb31-281a08195e20','冬日書懷四首  其四','王炎','宋','宋诗','song-poetry','','[]','結茅綠陰下，四壁但圖史。',60,'全唐诗/poet.song.160000.json','["結茅綠陰下，四壁但圖史。", "時亦有好事，相過款名理。", "捨之學宦游，蓬轉不自已。", "豈無山水音，塵埃被綠綺。", "幽夢遶雲溪，拏舟弄清泚。"]'),
('e0e19832-1766-4841-b3c8-3fa894dcc8c6','雪中官舍獨坐聞薪炭翔貴因成長句','王炎','宋','宋诗','song-poetry','','[]','天寒吹墮一尺雪，官冷釀成千斛愁。',64,'全唐诗/poet.song.160000.json','["天寒吹墮一尺雪，官冷釀成千斛愁。", "酌酒到花非所欲，束薪如桂若爲謀。", "風前鶴氅誰携策，江上漁蓑自艤舟。", "憑仗六龍回日轂，稍分輕暖到南州。"]'),
('7b74dfb3-42ef-4b96-8a34-d63862b1ef30','蕭參議雪中宴客朱僉判有詩因次韻  其一','王炎','宋','宋诗','song-poetry','','[]','飛花落絮自何來，勾引詩翁酌梓罍。',64,'全唐诗/poet.song.160000.json','["飛花落絮自何來，勾引詩翁酌梓罍。", "濯鼎有冰宜煮茗，携筇無路可尋梅。", "江城瓊玉踰千頃，古錦珠璣溢百枚。", "聞道夜闌車馬散，難窺鶴氅御風回。"]'),
('3087d1a2-8e7c-4b0d-8457-e62b1259065a','蕭參議雪中宴客朱僉判有詩因次韻  其二','王炎','宋','宋诗','song-poetry','','[]','不慣長安曳履游，貪看冰柱滿簷頭。',64,'全唐诗/poet.song.160000.json','["不慣長安曳履游，貪看冰柱滿簷頭。", "素花一色如梅嶺，碎玉無聲欠竹樓。", "蠟炬欲殘方夜永，金釵半醉自春浮。", "無氈獨坐君知否，也捲陳編索酒舟。"]'),
('fb79e556-4b00-412d-ba50-a7273d494753','和林寶文鹿鳴宴韻','王炎','宋','宋诗','song-poetry','','[]','材如杞梓總堪論，氣壓龍媒定躡雲。',64,'全唐诗/poet.song.160000.json','["材如杞梓總堪論，氣壓龍媒定躡雲。", "畫戟凝香供張飲，彤墀射策待方聞。", "月中折桂雖堪喜，馬上看花未足云。", "憂國愛君伸素志，始酬勸駕意殷勤。"]'),
('80f7d91f-4661-4a03-9fee-a4c16901a496','和林寶文喜雨','王炎','宋','宋诗','song-poetry','','[]','山椒靄靄暮雲徂，一雨翻盆物盡蘇。',32,'全唐诗/poet.song.160000.json','["山椒靄靄暮雲徂，一雨翻盆物盡蘇。", "父老相逢笑相語，今年和氣舊時無。"]'),
('8c22dc45-46c2-4351-bd5f-47dc3c3f2405','豐年謠五首  其一','王炎','宋','宋诗','song-poetry','','[]','滿箔春蠶得繭絲，家家機杼換新衣。',32,'全唐诗/poet.song.160000.json','["滿箔春蠶得繭絲，家家機杼換新衣。", "五風十雨天時好，又見西郊稻秫肥。"]'),
('538583d6-4694-4c4c-b437-6bfce851f62d','豐年謠五首  其二','王炎','宋','宋诗','song-poetry','','[]','縱橫南陌接東阡，婦餉夫耕望有年。',32,'全唐诗/poet.song.160000.json','["縱橫南陌接東阡，婦餉夫耕望有年。", "前此丁黄饑欲死，今年米賤不論錢。"]'),
('5d636ded-4c93-4e02-8b10-727d3e157630','豐年謠五首  其三','王炎','宋','宋诗','song-poetry','','[]','洞丁徭戶盡歸耕，篁竹無人弄寸兵。',32,'全唐诗/poet.song.160000.json','["洞丁徭戶盡歸耕，篁竹無人弄寸兵。", "要識二天恩德廣，黄雲千里見秋成。"]'),
('ef6ac329-ab1d-4e84-9896-cf234bf7d6a0','豐年謠五首  其四','王炎','宋','宋诗','song-poetry','','[]','睡鴨陂塘水慢流，離離禾稼滿平疇。',32,'全唐诗/poet.song.160000.json','["睡鴨陂塘水慢流，離離禾稼滿平疇。", "共言官府催科緩，飽飯渾家百不憂。"]'),
('a48f1bb9-92a3-4c33-a02c-2b2dac56f4ed','豐年謠五首  其五','王炎','宋','宋诗','song-poetry','','[]','稻如馬尾覆溝塍，桑柘陰中雞犬鳴。',32,'全唐诗/poet.song.160000.json','["稻如馬尾覆溝塍，桑柘陰中雞犬鳴。", "收穫登場便無事，輸租人不入州城。"]'),
('5a7711ca-3833-46ed-9ab2-ac5de93751f7','和林寶文吹暑軒二絕  其一','王炎','宋','宋诗','song-poetry','','[]','木末長風送雨來，田家遠近稻花開。',32,'全唐诗/poet.song.160000.json','["木末長風送雨來，田家遠近稻花開。", "披襟燕坐黄堂靜，一笑江山爽氣回。"]'),
('6312abcd-4dee-4304-b7e7-85555ff96a69','和林寶文吹暑軒二絕  其二','王炎','宋','宋诗','song-poetry','','[]','藕花香裏畫船橫，人靜惟聞洗玉聲。',32,'全唐诗/poet.song.160000.json','["藕花香裏畫船橫，人靜惟聞洗玉聲。", "四野清平公燕喜，隠然方面有長城。"]'),
('61970349-5567-4de1-b71b-080b5d554c2d','再和林寶文三絕  其一','王炎','宋','宋诗','song-poetry','','[]','要知好雨自何來，和氣連雲撥不開。',32,'全唐诗/poet.song.160000.json','["要知好雨自何來，和氣連雲撥不開。", "廊廟爲霖須妙手，即看力斡大鈞回。"]'),
('35953c92-6553-41b7-8054-cdeaa62a1898','再和林寶文三絕  其二','王炎','宋','宋诗','song-poetry','','[]','千里山川含秀色，四郊雞犬散歡聲。',32,'全唐诗/poet.song.160000.json','["千里山川含秀色，四郊雞犬散歡聲。", "更呼屏翳從頤指，潤澤無邊浹屬城。"]'),
('27ea7553-8764-4ea2-9c1d-41291806598c','再和林寶文三絕  其三','王炎','宋','宋诗','song-poetry','','[]','陽開陰闔四時更，誰解均調玉燭明。',32,'全唐诗/poet.song.160000.json','["陽開陰闔四時更，誰解均調玉燭明。", "畫戟香中沛恩澤，祥風甘雨自流行。"]'),
('7a9c9e60-a7cb-41e3-8f5f-0b55d8e46734','李閣學挽詩三首  其一','王炎','宋','宋诗','song-poetry','','[]','物望推耆哲，巋然可鎮浮。',48,'全唐诗/poet.song.160000.json','["物望推耆哲，巋然可鎮浮。", "莫年登近侍，再起殿南州。", "不樂分銅虎，方期杖玉鳩。", "胡然歸未久，仙去杳難留。"]'),
('17d86752-ef64-4361-9f53-531ccca4d5f5','李閣學挽詩三首  其二','王炎','宋','宋诗','song-poetry','','[]','止水中心靜，浮雲外物輕。',48,'全唐诗/poet.song.160000.json','["止水中心靜，浮雲外物輕。", "行藏無悔吝，存歿備哀榮。", "士類思前輩，朝廷失老成。", "衡湘人物盡，念舊若爲情。"]'),
('0dbfb1f6-6cbd-4127-b198-fb8f036818a7','李閣學挽詩三首  其三','王炎','宋','宋诗','song-poetry','','[]','頻歲仍饑饉，三湘要撫綏。',48,'全唐诗/poet.song.160000.json','["頻歲仍饑饉，三湘要撫綏。", "分憂承帝命，遺愛結民思。", "自有欒公社，何須叔子碑。", "若書耆舊傳，清德不磷緇。"]'),
('ea3270ca-4445-44b7-b328-0d3a46e13af1','魏丞相挽詩三首  其一','王炎','宋','宋诗','song-poetry','','[]','士論崇高節，宸心眷樸忠。',48,'全唐诗/poet.song.160000.json','["士論崇高節，宸心眷樸忠。", "調元纔玉鉉，均佚即琳宮。", "補衮嘉謀密，平衡道揆公。", "惜哉當國淺，不及究成功。"]'),
('f1f22894-c0d8-4a21-9208-c84637e6efa6','魏丞相挽詩三首  其二','王炎','宋','宋诗','song-poetry','','[]','冠劍青雲士，艱危孰奮身。',48,'全唐诗/poet.song.160000.json','["冠劍青雲士，艱危孰奮身。", "向來持漢節，徑去犯邊塵。", "既用公爲相，方知國有人。", "凜然生氣在，端合畫麒麟。"]'),
('0047e602-6a7e-44fa-bfb4-cd8ab225c988','魏丞相挽詩三首  其三','王炎','宋','宋诗','song-poetry','','[]','衮繡遺三事，松梅共一川。',48,'全唐诗/poet.song.160000.json','["衮繡遺三事，松梅共一川。", "小溪空勝景，先隴忽新阡。", "上悟流言妄，人思舊弼賢。", "忠嘉雖削稿，合付殺青傳。"]'),
('52cfad30-e713-465c-9487-31fed67f6e9c','黄致政挽詩二首  其一','王炎','宋','宋诗','song-poetry','','[]','後學資模楷，先生久里居。',48,'全唐诗/poet.song.160000.json','["後學資模楷，先生久里居。", "兩兒聯玉筍，三命佩銀魚。", "米廩無重席，蓬山孰校書。", "如何遺此老，宰木遽蕭疎。"]'),
('bd61fdab-ef2f-43eb-a474-a4a930d0ab35','黄致政挽詩二首  其二','王炎','宋','宋诗','song-poetry','','[]','祿養更迎侍，消摇介壽康。',48,'全唐诗/poet.song.160000.json','["祿養更迎侍，消摇介壽康。", "壯圖雖偃屈，潜德竟輝光。", "可惜今埋玉，無由自奠觴。", "他年觀上冢，千騎擁龍岡。"]'),
('9b529f4c-5444-4283-830d-90f7e2001468','賀東宮誕辰','王炎','宋','宋诗','song-poetry','','[]','萬國乾符正，千齡鼎祚長。',192,'全唐诗/poet.song.160000.json','["萬國乾符正，千齡鼎祚長。", "春禖膺眷顧，甲觀肇休祥。", "紫極聯前曜，青宮位少陽。", "五雲凝喜色，重日爛榮光。", "繼體臨崇福，承顔侍未央。", "犀簪羣后表，象輅兩宮旁。", "氣接金行爽，天開火德昌。", "慈皇年有永，大帝壽無疆。", "欽愛誠彌篤，溫文德自彰。", "喬枝方疊蔭，瓜瓞寖垂芳。", "儲禁銅扉肅，官僚玉佩鏘。", "旌麾張十戟，筍簴列三廂。", "恭命來南紀，馳情望左坊。", "也叨持虎節，莫預獻鸞觴。", "海潤涵羣彙，霞騫映四方。", "願言申戩穀，夷夏仰元良。"]'),
('8b89a37a-712b-4922-825d-9d8babed704d','和王右司游南岳得晴','王炎','宋','宋诗','song-poetry','','[]','笑披鶴氅上坡陀，風籟無聲日氣和。',64,'全唐诗/poet.song.160000.json','["笑披鶴氅上坡陀，風籟無聲日氣和。", "絕頂瓊瑶蒙竹樹，上方宮殿隔藤蘿。", "雪花夜墮方如許，天宇晨開豈有他。", "一點春陽溫厚意，積陰消釋自無多。"]'),
('6df7cc21-2724-4519-8826-d6b6fc9c4143','和蕭參議游岳麓八絕  其一','王炎','宋','宋诗','song-poetry','','[]','登臨須返意須留，目力無邊不著愁。',32,'全唐诗/poet.song.160000.json','["登臨須返意須留，目力無邊不著愁。", "收拾風光歸古錦，千巖萬壑獻清秋。"]'),
('094f9528-ccf5-413f-b24c-35cbd5c2746e','和蕭參議游岳麓八絕  其二','王炎','宋','宋诗','song-poetry','','[]','逐客當年出帝鄉，不容蹤跡到黄堂。',32,'全唐诗/poet.song.160000.json','["逐客當年出帝鄉，不容蹤跡到黄堂。", "蒼崖屐齒今安在，公獨懷思未忍忘。"]'),
('fc8657fe-5091-4ddd-9401-f5a8708a2a7f','和蕭參議游岳麓八絕  其三','王炎','宋','宋诗','song-poetry','','[]','凭欄落照俯江天，睥睨詩翁翰墨傳。',32,'全唐诗/poet.song.160000.json','["凭欄落照俯江天，睥睨詩翁翰墨傳。", "試爲江山重著語，筆端桃李恰爭妍。"]'),
('75e25235-6e14-4128-bd07-65bcddaa659d','和蕭參議游岳麓八絕  其四','王炎','宋','宋诗','song-poetry','','[]','泉遶雲根玉雪清，蒼珉百級可階升。',32,'全唐诗/poet.song.160000.json','["泉遶雲根玉雪清，蒼珉百級可階升。", "汲泉煮茗松風起，誰識無塵有髮僧。"]'),
('e39647da-3c00-4fe6-8dea-a4b981fadd5c','和蕭參議游岳麓八絕  其五','王炎','宋','宋诗','song-poetry','','[]','清風峽裏水清泠，不但琮琤可靜聽。',32,'全唐诗/poet.song.160000.json','["清風峽裏水清泠，不但琮琤可靜聽。", "秋桂秋蘭在深谷，更堪鼻觀挹幽馨。"]'),
('7bc310d2-6b0f-4caa-9354-65ade8b4f1ed','和蕭參議游岳麓八絕  其六','王炎','宋','宋诗','song-poetry','','[]','每到精廬即少留，品題清境甲湘州。',32,'全唐诗/poet.song.160000.json','["每到精廬即少留，品題清境甲湘州。", "游山脚力猶强健，緩步曾登最上頭。"]'),
('5bb2a180-9833-4bf7-a1e2-12f2416f1676','和蕭參議游岳麓八絕  其七','王炎','宋','宋诗','song-poetry','','[]','蕭寺相望湘水西，談玄誰解析精微。',32,'全唐诗/poet.song.160000.json','["蕭寺相望湘水西，談玄誰解析精微。", "聖門自有超凡地，懶向林間問衲衣。"]'),
('76924ff4-49ae-4474-8a46-9ecb63146156','和蕭參議游岳麓八絕  其八','王炎','宋','宋诗','song-poetry','','[]','近來曾與二三子，準擬誅茅紫翠間。',32,'全唐诗/poet.song.160000.json','["近來曾與二三子，準擬誅茅紫翠間。", "老石摩挲堪篆刻，恨無筆力記西山。"]'),
('a2315f30-e7be-4061-a818-f6211d81d405','和王右司游南岳三絕  其一','王炎','宋','宋诗','song-poetry','','[]','懶跨狨鞍趁曉班，却穿蠟屐小游山。',32,'全唐诗/poet.song.160000.json','["懶跨狨鞍趁曉班，却穿蠟屐小游山。", "山頭草木生光彩，玉節曾行紫翠間。"]'),
('2aaaf2fa-58aa-4e69-92f4-963dd422c9c5','和王右司游南岳三絕  其二','王炎','宋','宋诗','song-poetry','','[]','喬岳雄於楚粵間，衆丘迤邐釀高寒。',32,'全唐诗/poet.song.160000.json','["喬岳雄於楚粵間，衆丘迤邐釀高寒。", "青藜拄到雲霄上，見得心如眼界寬。"]'),
('ba9b4d03-e1aa-4e8a-8565-5fa9042640ff','和王右司游南岳三絕  其三','王炎','宋','宋诗','song-poetry','','[]','祝融獨秀壓羣峰，登覽雖終興未窮。',32,'全唐诗/poet.song.160000.json','["祝融獨秀壓羣峰，登覽雖終興未窮。", "人物與山爭峻特，也宜班爵視三公。"]'),
('760b2cf3-8630-4f6b-9a60-b60ffade0bf6','林寶文生日','王炎','宋','宋诗','song-poetry','','[]','乾健運元氣，斗杓默回旋。',240,'全唐诗/poet.song.160000.json','["乾健運元氣，斗杓默回旋。", "千歲生一聖，半千生一賢。", "間世有異稟，天意非徒然。", "皇極在人心，俗學無自得。", "天意興斯文，公獨抱深識。", "微言發緒餘，河漢浩無極。", "士氣久不振，罷軟無剛風。", "天意眷吾君，公獨奮精忠。", "雷霆不能驚，正色攖神龍。", "膏澤不下流，閭閻有憔悴。", "天意佑斯民，公獨藴慈惠。", "春風小披拂，萬物回生意。", "既賦以全德，必益以壽祺。", "其顔如渥丹，天意可測知。", "再拜上黄堂，一洗玉屈巵。", "戩穀既鼎來，何以致祝辭。", "在外守麟符，十連蒙寵綏。", "在內調金鉉，四海無憂虞。", "邦人丐公留，天子遄公歸。", "臞儒願控鶴，雲路從先驅。"]'),
('be1cb60d-165c-4aba-b34c-28bca6b41304','和王右司回鴈峰韻','王炎','宋','宋诗','song-poetry','','[]','宦途多遠游，王事無寧居。',96,'全唐诗/poet.song.160000.json','["宦途多遠游，王事無寧居。", "人生亦何求，意足即有餘。", "候鴈到衡陽，不肯更南去。", "達人識其幾，青雲首回顧。", "不受寵辱驚，進退皆裕如。", "平生金石心，此詩豈欺予。", "田園歸去來，千載淵明語。", "妙句當並傳，來哲定深許。"]'),
('168c3f41-3277-40bf-aeb6-ff8a50f86e9f','送王右司移江西憲','王炎','宋','宋诗','song-poetry','','[]','日邊好音來，繡斧移軺車。',216,'全唐诗/poet.song.160000.json','["日邊好音來，繡斧移軺車。", "九重寄視聽，四牡煩詢咨。", "才德難兩全，有即時所須。", "平生經綸學，豐蓄乃嗇施。", "底柱閲頹波，去就難招麾。", "湘濱督飛輓，未曾費符移。", "舉鞭有流錢，民瘠亦自肥。", "攬轡不可留，父老結去思。", "星臺照芹水，寒士增光輝。", "心旌遶門闌，意往身縶維。", "叱馭豈憚行，願言謹馳驅。", "遥知章貢上，喜色生里閭。", "舊聞珥筆風，家有城旦書。", "公行將直指，淑問如臯蘇。", "桁楊無幽枉，雨露皆沾濡。", "東望尺五天，入覲聊假途。", "善類望主盟，至尊渴謀謨。", "正須畫麒麟，未用思蓴鱸。"]'),
('991452c9-977e-4eea-9870-826c990b787d','和馬宜州卜居七首 卜居','王炎','宋','宋诗','song-poetry','','[]','一丘一壑胸次，來在市廛結廬。',28,'全唐诗/poet.song.160000.json','["一丘一壑胸次，來在市廛結廬。", "只恐飛騰燕頷，未容袖手深居。"]'),
('2bf59f8a-f507-49ba-a1f9-6e1867db95ee','和馬宜州卜居七首 足堂','王炎','宋','宋诗','song-poetry','','[]','身外成虧萬事，人間寵辱百年。',28,'全唐诗/poet.song.160000.json','["身外成虧萬事，人間寵辱百年。", "絲毫不挂念慮，一榻清風晝眠。"]'),
('d4e091af-a444-4172-8d54-b4ab3f197593','和馬宜州卜居七首 復齋','王炎','宋','宋诗','song-poetry','','[]','哲人慾不喪道，昧者是難勝非。',28,'全唐诗/poet.song.160000.json','["哲人慾不喪道，昧者是難勝非。", "學貴復之不遠，在知心體危微。"]'),
('f4b96353-796d-4326-9f3f-7563edb60aeb','和馬宜州卜居七首 退圃','王炎','宋','宋诗','song-poetry','','[]','爭利慾心汲汲，爭名私智閒閒。',28,'全唐诗/poet.song.160000.json','["爭利慾心汲汲，爭名私智閒閒。", "公獨退身一步，靜中著眼回看。"]'),
('7cb8360d-1834-4a59-97e3-bd0dbbe7bd9e','和馬宜州卜居七首 欣欣亭','王炎','宋','宋诗','song-poetry','','[]','卉木俱含喜色，日迎杖屨床前。',28,'全唐诗/poet.song.160000.json','["卉木俱含喜色，日迎杖屨床前。", "晚秀早芳相續，四時留得春天。"]'),
('6ca53e49-17e5-410b-a549-2a72832de868','和馬宜州卜居七首 冰雪軒','王炎','宋','宋诗','song-poetry','','[]','史君甚愛竹弟，欲與渠爲二難。',28,'全唐诗/poet.song.160000.json','["史君甚愛竹弟，欲與渠爲二難。", "歲晚青青玉立，不須俗眼同看。"]'),
('3afe173d-00cd-45d0-9940-37e0beda1407','和馬宜州卜居七首 白蓮池','王炎','宋','宋诗','song-poetry','','["\u897f\u6e56"]','處士幽居安在，荷花十里西湖。',28,'全唐诗/poet.song.160000.json','["處士幽居安在，荷花十里西湖。", "無謂一池褊小，以人爲重何殊。"]'),
('8179bcd2-81f9-4aa1-8a76-393b520d033b','九月到白石先妣塋所','王炎','宋','宋诗','song-poetry','','[]','不瞻宰木過三年，霜露凄凉倍愴然。',64,'全唐诗/poet.song.160000.json','["不瞻宰木過三年，霜露凄凉倍愴然。", "馬鬣但驚荒宿草，龜趺未辦表新阡。", "平生鍾釜空遺恨，舊物桮棬半不傳。", "鴻鴈差池風雨急，吞聲清淚徹黄泉。"]'),
('8bc5256c-ac36-4ffa-8601-142cccfd695c','次韻胡元龍携詩相訪','王炎','宋','宋诗','song-poetry','','[]','杜門度永日，蒼苔生柳陰。',96,'全唐诗/poet.song.160000.json','["杜門度永日，蒼苔生柳陰。", "欹枕喚黄嬭，頹然厭披吟。", "剝啄來者誰，一笑逢知心。", "試歸與婦謀，無酒堪共斟。", "解頤只玄談，清風拂衣襟。", "奚囊出妙語，戛玉而鏘金。", "爲公歌數詩，絃以綠綺琴。", "歡伯舊有盟，可寒猶可尋。"]'),
('4b86665b-72f1-4735-9dd8-b5a880eb1eec','丙午中秋夜','王炎','宋','宋诗','song-poetry','','[]','玉斧經年不暫閒，脩成今夜月團圓。',64,'全唐诗/poet.song.160000.json','["玉斧經年不暫閒，脩成今夜月團圓。", "老蟾是處光皆滿，飛鵲如予意未安。", "免與朋儕爭翰墨，聊呼兒女具杯盤。", "飲酣尚起飄然興，欲訪羣仙到廣寒。"]'),
('85e1dac7-4d26-4210-84a8-529c593c96fe','次韻李仲永携詩相別','王炎','宋','宋诗','song-poetry','','[]','李侯人物極清真，氣似靈犀可辟塵。',64,'全唐诗/poet.song.160000.json','["李侯人物極清真，氣似靈犀可辟塵。", "平日論心思益友，而今刮眼見詩人。", "有官墮在蒹葭境，爲政恐無桃李春。", "撫字要須寬猛濟，誦公佳句合書紳。"]'),
('dbe73a76-5e91-45d5-9ac9-ef68eca2811d','和至卿敘述三首  其一','王炎','宋','宋诗','song-poetry','','[]','長年英氣易消磨，窮達其如有命何。',64,'全唐诗/poet.song.160000.json','["長年英氣易消磨，窮達其如有命何。", "進德要須涵養熟，讀書不在見聞多。", "揮犀款曲思君話，烹鯉殷勤約我過。", "鏡裏素絲侵綠鬢，著鞭聖域莫蹉跎。"]'),
('fab8d9b6-67d6-4504-91d3-185b08bdff09','和至卿敘述三首  其二','王炎','宋','宋诗','song-poetry','','[]','木偶漂漂無定蹤，歸來依舊嘆途窮。',64,'全唐诗/poet.song.160000.json','["木偶漂漂無定蹤，歸來依舊嘆途窮。", "與君趨向元相似，涉世行藏略不同。", "縱使寒松生澗底，也勝澤雉蓄樊中。", "一丘一壑平生願，他日俱爲桑苧翁。"]');
